// SUPABASE (via proxy Vercel api/db.js)
// ══════════════════════════════════════════════
async function dbCall(method, table, opts = {}) {
  if (!VERCEL_URL) throw new Error('VERCEL_URL não configurado');
  const resp = await fetch(VERCEL_URL + '/api/db', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ method, table, ...opts })
  });
  const json = await resp.json();
  if (!resp.ok) throw new Error(json?.error?.message || json?.error || JSON.stringify(json));
  return json.data;
}
