const S={
  // Leitura local (cache rápido)
  pedidos:  ()=>JSON.parse(localStorage.getItem('wg_pedidos')||'[]'),
  excluidos:()=>JSON.parse(localStorage.getItem('wg_excluidos')||'[]'),
  audit:    ()=>JSON.parse(localStorage.getItem('wg_audit')||'[]'),
  clientes: ()=>JSON.parse(localStorage.getItem('wg_clientes')||'[]'),
  // Gravação local (cache)
  saveP: d=>localStorage.setItem('wg_pedidos',JSON.stringify(d)),
  saveX: d=>localStorage.setItem('wg_excluidos',JSON.stringify(d)),
  saveA: d=>localStorage.setItem('wg_audit',JSON.stringify(d)),
  saveCli:d=>localStorage.setItem('wg_clientes',JSON.stringify(d)),
};

