// ── HELPERS DE MAPEAMENTO ──
// Converte pedido do formato local → Supabase
function pedidoToDb(p, userId){
  return {
    id: p.id,
    status: p.status||'espelho',
    tipo: (p.cType||'b2b').toUpperCase(),
    vendedor_login: p.vendedor,
    total: p.total||0,
    frete_mode: p.frete?.mode||'definir',
    frete_valor: p.frete?.valor||0,
    fat_data: p.faturamento?.data||null,
    fat_forma: p.faturamento?.forma||null,
    fat_parcelas: parseInt(p.faturamento?.parcelas)||1,
    fat_prazos: p.faturamento?.prazos||null,
    bling_id: p.blingId||null,
    bling_sent_at: p.blingSentAt||null,
    excluido: !!(p.deletedAt),
    excluido_at: p.deletedAt||null,
    cliente_snapshot: JSON.stringify(p.cliente||{}),
    comments_snapshot: JSON.stringify(p.comments||[]),
    history_snapshot: JSON.stringify(p.history||[]),
    updated_at: new Date().toISOString()
  };
}
// Converte pedido do Supabase → formato local
function dbToPedido(row){
  return {
    id: row.id,
    status: row.status||'espelho',
    cType: (row.tipo||'B2B').toLowerCase(),
    vendedor: row.vendedor_login,
    vendedorName: usersCache.find(u=>u.user===row.vendedor_login)?.name||row.vendedor_login,
    total: parseFloat(row.total)||0,
    frete: {mode:row.frete_mode||'definir', valor:parseFloat(row.frete_valor)||0},
    faturamento: {data:row.fat_data||'', forma:row.fat_forma||'', parcelas:row.fat_parcelas||1, prazos:row.fat_prazos||''},
    blingId: row.bling_id||null,
    blingSentAt: row.bling_sent_at||null,
    deletedAt: row.excluido_at||null,
    cliente: tryParse(row.cliente_snapshot, {}),
    items: row.itens_snapshot ? tryParse(row.itens_snapshot, []) : (row._itens||[]),
    comments: tryParse(row.comments_snapshot, []),
    history: tryParse(row.history_snapshot, []),
  };
}
function tryParse(str, def){ try{return JSON.parse(str||'null')||def;}catch(e){return def;} }
function clienteToDb(c){
  return {
    id_local: c.id,
    razao_social: c.razao||'',
    nome_fantasia: c.fantasia||'',
    cnpj: c.cnpj||null,
    cpf: c.cpf||null,
    ie: c.ie||null,
    tipo: c.tipo||(c.cnpj?'B2B':'B2C'),
    ativo: c.ativo!==false,
    endereco: c.end||null,
    cidade: c.cidade||null,
    cep: c.cep||null,
    telefone: c.tel||null,
    email: c.email||null,
    vendedor_login: c.vendedor||CU?.user||null,
    updated_at: new Date().toISOString()
  };
}
function dbToCliente(row){
  return {
    id: row.id_local||row.id,
    razao: row.razao_social,
    fantasia: row.nome_fantasia||'',
    cnpj: row.cnpj||'',
    cpf: row.cpf||'',
    ie: row.ie||'',
    tipo: row.tipo||'B2B',
    ativo: row.ativo!==false,
    end: row.endereco||'',
    cidade: row.cidade||'',
    cep: row.cep||'',
    tel: row.telefone||'',
    email: row.email||'',
    vendedor: row.vendedor_login||'',
  };
}

// ── SINCRONIZAÇÃO ──
async function syncFromSupabase(){
  if(!VERCEL_URL) return;
  try{
    syncStatus='syncing';
    atualizarSyncIndicator();
    const isAdmin=CU.role==='admin';
    const isGerente=CU.role==='gerente'||CU.role==='coordenador';
    // Admin vê todos; gerente/coord vê a si mesmo + subordinados; vendedor vê só os seus
    let filtros={};
    if(!isAdmin){
      if(isGerente){
        // Busca equipe (quem reporta a ele, recursivamente até 2 níveis)
        const equipe=[CU.user, ...usersCache.filter(u=>u.reportaPara===CU.user).map(u=>u.user)];
        // Não há filtro "in" simples no dbCall atual; buscamos tudo e filtramos localmente
        // por isso buscamos sem filtro e filtramos depois
      } else {
        filtros={vendedor_login:CU.user};
      }
    }
    const rows=await dbCall('select','pedidos',{select:'*',order:'updated_at.desc'});
    // Filtrar localmente por hierarquia
    // Filtrar pedidos excluídos do Supabase
    let rowsFiltradas=rows.filter(r=>!r.excluido);
    if(!isAdmin){
      if(isGerente){
        const equipe=new Set([CU.user,...usersCache.filter(u=>u.reportaPara===CU.user).map(u=>u.user)]);
        rowsFiltradas=rowsFiltradas.filter(r=>equipe.has(r.vendedor_login));
      } else {
        rowsFiltradas=rowsFiltradas.filter(r=>r.vendedor_login===CU.user);
      }
    }
    // Adicionar itens via snapshot (já está no pedido como itens_snapshot ou comments_snapshot)
    pedidosCache=rowsFiltradas.map(dbToPedido);
    // Separar ativos de excluídos
    const ativos=pedidosCache.filter(p=>!p.deletedAt);
    const excluidos=pedidosCache.filter(p=>p.deletedAt);

    // MESCLAR com localStorage: manter pedidos locais que ainda não estão no Supabase
    const pedidosLocais=S.pedidos();
    const idsSupabase=new Set(ativos.map(p=>p.id));
    const apenasLocais=pedidosLocais.filter(p=>!idsSupabase.has(p.id));

    // Fazer upload dos pedidos que estão só no local para o Supabase
    if(apenasLocais.length>0){
      console.log(`Sincronizando ${apenasLocais.length} pedido(s) local(is) para o Supabase...`);
      for(const p of apenasLocais){
        try{ await dbSavePedido(p); }catch(e){ console.warn('Falha ao subir pedido local:', p.id); }
      }
    }

    // Salvar lista mesclada no localStorage
    const listaMesclada=[...ativos, ...apenasLocais];
    S.saveP(listaMesclada);
    S.saveX(excluidos);
    // Carregar clientes
    const cliRows=await dbCall('select','clientes',{select:'*',order:'razao_social.asc'});
    clientesCache=cliRows.map(dbToCliente);
    S.saveCli(clientesCache);
    syncStatus='synced';
    atualizarSyncIndicator();
  }catch(e){
    syncStatus='local';
    atualizarSyncIndicator();
    console.warn('Sync falhou, usando cache local:', e.message);
  }
}
function atualizarSyncIndicator(){
  const dot=document.getElementById('sdot');
  const lbl=document.getElementById('slbl');
  if(!dot||!lbl)return;
  if(syncStatus==='synced'){dot.className='sdot ok';lbl.textContent='Conectado · Supabase';}
  else if(syncStatus==='syncing'){dot.className='sdot';lbl.textContent='Sincronizando...';}
  else{dot.className='sdot';lbl.textContent='Modo local';}
}

// ── SALVAR PEDIDO NO SUPABASE ──
async function dbSavePedido(pedido){
  if(!VERCEL_URL) return;
  try{
    const row=pedidoToDb(pedido);
    // Salvar itens no snapshot
    row.itens_snapshot=JSON.stringify(pedido.items||[]);
    await dbCall('upsert','pedidos',{data:row,onConflict:'id'});
  }catch(e){ console.warn('Falha ao salvar pedido no Supabase:', e.message); }
}

// ── SALVAR CLIENTE NO SUPABASE ──
async function dbSaveCliente(c){
  if(!VERCEL_URL) return;
  try{
    const row=clienteToDb(c);
    await dbCall('upsert','clientes',{data:row,onConflict:'id_local'});
  }catch(e){ console.warn('Falha ao salvar cliente no Supabase:', e.message); }
}

// ── SALVAR AUDITORIA NO SUPABASE ──
async function dbSaveAudit(entry){
  if(!VERCEL_URL) return;
  try{
    await dbCall('insert','auditoria',{data:{
      usuario_login:entry.user,usuario_nome:entry.userName,usuario_role:entry.role,
      acao:entry.action,descricao:entry.desc,pedido_id:entry.pedidoId||null
    }});
  }catch(e){ /* silencioso, audit local já salvou */ }
}
