// COMISSÕES — Metas, Regras Próprias, Cascata, Painel
// ══════════════════════════════════════════════
const MESES=['Janeiro','Fevereiro','Março','Abril','Maio','Junho','Julho','Agosto','Setembro','Outubro','Novembro','Dezembro'];
let comissoesTab='metas';

function setCTab(t){
  comissoesTab=t;
  ['metas','regras','cascata','painel'].forEach(x=>{
    document.getElementById('ctab-content-'+x).style.display=x===t?'block':'none';
    const btn=document.getElementById('ctab-'+x);
    btn.style.borderBottomColor=x===t?'var(--wine)':'transparent';
    btn.style.color=x===t?'var(--wine)':'var(--txt-mid)';
  });
  if(t==='metas') renderMetas();
  if(t==='regras') renderRegras();
  if(t==='cascata') renderCascata();
  if(t==='painel') renderPainelComissoes();
}

async function initComissoes(){
  // Popular selects de ano
  const ano=new Date().getFullYear();
  const anos=[ano-1,ano,ano+1];
  ['meta-ano','painel-ano'].forEach(id=>{
    const sel=document.getElementById(id);if(!sel)return;
    sel.innerHTML=anos.map(a=>`<option value="${a}" ${a===ano?'selected':''}>${a}</option>`).join('');
  });
  // Popular select de mês no painel
  const selMes=document.getElementById('painel-mes');
  if(selMes) selMes.innerHTML=MESES.map((m,i)=>`<option value="${i+1}" ${i+1===new Date().getMonth()+1?'selected':''}>${m}</option>`).join('');
  // Popular select de usuário (metas e painel)
  const us=usersCache.filter(u=>u.ativo&&u.role!=='admin');
  const selMU=document.getElementById('meta-user');
  if(selMU) selMU.innerHTML=us.map(u=>`<option value="${u.user}">${u.name}</option>`).join('');
  const selPU=document.getElementById('painel-user');
  if(selPU) selPU.innerHTML='<option value="">Todos</option>'+us.map(u=>`<option value="${u.user}">${u.name}</option>`).join('');
  setCTab('metas');
}

// ── METAS ──
async function renderMetas(){
  const ano=parseInt(document.getElementById('meta-ano')?.value||new Date().getFullYear());
  const user=document.getElementById('meta-user')?.value;
  if(!user) return;
  let rows=[];
  try{ rows=await dbCall('select','metas',{select:'*',filters:{vendedor:user}}); }catch(e){}
  const byMesCanal={};
  rows.filter(r=>r.ano===ano).forEach(r=>{byMesCanal[r.mes+'-'+r.canal]={id:r.id,valor:r.valor_meta};});
  const tbody=document.getElementById('metas-body');
  tbody.innerHTML=MESES.map((m,i)=>{
    const mes=i+1;
    const b2b=byMesCanal[mes+'-b2b']||{};
    const b2c=byMesCanal[mes+'-b2c']||{};
    return `<tr style="border-bottom:1px solid var(--stripe);">
      <td style="padding:7px 6px;font-weight:bold;">${m}</td>
      <td style="padding:4px 6px;"><input class="fi" id="meta-${mes}-b2b" type="number" min="0" step="0.01" value="${b2b.valor||''}" placeholder="0,00" style="width:120px;font-size:11px;padding:5px 7px;"></td>
      <td style="padding:4px 6px;"><input class="fi" id="meta-${mes}-b2c" type="number" min="0" step="0.01" value="${b2c.valor||''}" placeholder="0,00" style="width:120px;font-size:11px;padding:5px 7px;"></td>
      <td style="padding:4px 6px;"><button class="bsm bsm-w" onclick="saveMeta(${ano},'${user}',${mes})">💾</button></td>
    </tr>`;
  }).join('');
}

async function saveMeta(ano,user,mes){
  const b2b=parseFloat(document.getElementById(`meta-${mes}-b2b`).value)||0;
  const b2c=parseFloat(document.getElementById(`meta-${mes}-b2c`).value)||0;
  try{
    await dbCall('upsert','metas',{data:{vendedor:user,ano,mes,canal:'b2b',valor_meta:b2b},onConflict:'vendedor,ano,mes,canal'});
    await dbCall('upsert','metas',{data:{vendedor:user,ano,mes,canal:'b2c',valor_meta:b2c},onConflict:'vendedor,ano,mes,canal'});
    showToast('Meta salva!',true);
  }catch(e){showToast('Erro: '+e.message);}
}

// ── REGRAS PRÓPRIAS ──
async function renderRegras(){
  let rows=[];
  try{ rows=await dbCall('select','regras_comissao',{select:'*'}); }catch(e){}
  const byUser={};rows.forEach(r=>byUser[r.usuario]=r);
  const users=usersCache.filter(u=>u.ativo&&u.role!=='admin');
  const tbody=document.getElementById('regras-body');
  tbody.innerHTML=users.map(u=>{
    const r=byUser[u.user]||{};
    const id=u.user.replace(/[^a-z0-9]/g,'');
    return `<tr style="border-bottom:1px solid var(--stripe);">
      <td style="padding:7px 6px;font-weight:bold;">${u.name}<br><span style="font-size:10px;color:var(--txt-mid);">@${u.user}</span></td>
      <td style="padding:4px;"><input class="fi" id="rg-${id}-b2bab" type="number" min="0" max="100" step="0.01" value="${r.b2b_pct_abaixo_meta||''}" placeholder="0" style="width:70px;font-size:11px;padding:5px;"> %</td>
      <td style="padding:4px;"><input class="fi" id="rg-${id}-b2bac" type="number" min="0" max="100" step="0.01" value="${r.b2b_pct_acima_meta||''}" placeholder="0" style="width:70px;font-size:11px;padding:5px;"> %</td>
      <td style="padding:4px;"><input class="fi" id="rg-${id}-b2cab" type="number" min="0" max="100" step="0.01" value="${r.b2c_pct_abaixo_meta||''}" placeholder="0" style="width:70px;font-size:11px;padding:5px;"> %</td>
      <td style="padding:4px;"><input class="fi" id="rg-${id}-b2cac" type="number" min="0" max="100" step="0.01" value="${r.b2c_pct_acima_meta||''}" placeholder="0" style="width:70px;font-size:11px;padding:5px;"> %</td>
      <td style="padding:4px;"><button class="bsm bsm-w" onclick="saveRegra('${u.user}','${id}')">💾</button></td>
    </tr>`;
  }).join('');
}

async function saveRegra(usuario,id){
  const data={
    usuario,
    b2b_pct_abaixo_meta:parseFloat(document.getElementById(`rg-${id}-b2bab`).value)||0,
    b2b_pct_acima_meta: parseFloat(document.getElementById(`rg-${id}-b2bac`).value)||0,
    b2c_pct_abaixo_meta:parseFloat(document.getElementById(`rg-${id}-b2cab`).value)||0,
    b2c_pct_acima_meta: parseFloat(document.getElementById(`rg-${id}-b2cac`).value)||0,
    updated_at:new Date().toISOString()
  };
  try{
    await dbCall('upsert','regras_comissao',{data,onConflict:'usuario'});
    showToast('Regra salva!',true);
  }catch(e){showToast('Erro: '+e.message);}
}

