async function renderDashComissoes(){
  const sec=document.getElementById('dash-comissoes-section');
  if(!sec)return;
  const isVendedor=CU.role==='vendedor'||CU.role==='coordenador'||CU.role==='gerente';
  if(!isVendedor){sec.style.display='none';return;}
  sec.style.display='block';
  const agora=new Date();
  const ano=agora.getFullYear(); const mes=agora.getMonth()+1;
  document.getElementById('dash-com-mes').textContent=MESES[mes-1]+' '+ano;
  // Pedidos do mês enviados ao Bling
  const pedidos=S.pedidos().filter(p=>p.vendedor===CU.user&&p.blingId&&p.faturamento?.data?.startsWith(`${ano}-${String(mes).padStart(2,'0')}`));
  const totB2B=pedidos.filter(p=>p.cType==='b2b').reduce((s,p)=>s+(p.total||0),0);
  const totB2C=pedidos.filter(p=>p.cType==='b2c').reduce((s,p)=>s+(p.total||0),0);
  let regras=[]; let metas=[];
  try{ [regras,metas]=await Promise.all([
    dbCall('select','regras_comissao',{select:'*',filters:{usuario:CU.user}}),
    dbCall('select','metas',{select:'*',filters:{vendedor:CU.user,ano,mes}})
  ]); }catch(e){}
  const reg=regras[0]||{};
  const metaMap={};metas.forEach(m=>metaMap[m.canal]=m.valor_meta||0);
  function calcCard(canal, total){
    const meta=metaMap[canal]||0;
    const bateu=meta>0&&total>=meta;
    const pct=canal==='b2b'?(bateu?reg.b2b_pct_acima_meta:reg.b2b_pct_abaixo_meta):(bateu?reg.b2c_pct_acima_meta:reg.b2c_pct_abaixo_meta)||0;
    const vlr=total*(pct/100);
    const mesesExtra=canal==='b2c'?1:2;
    const dataVenc=new Date(ano,mes-1+mesesExtra,5);
    const cor=canal==='b2b'?'var(--wine)':'var(--green)';
    return `<div style="background:var(--cream);border-radius:10px;padding:16px;border-left:4px solid ${cor};">
      <div style="font-size:11px;font-weight:bold;color:${cor};margin-bottom:8px;">${canal.toUpperCase()}</div>
      <div style="font-size:18px;font-weight:bold;color:var(--wine);">${fmtBRL(vlr)}</div>
      <div style="font-size:10px;color:var(--txt-mid);margin-top:4px;">Vendas: ${fmtBRL(total)} · ${pct}% ${bateu?'✅ Acima da meta':'⚠️ Abaixo da meta'}</div>
      ${meta?`<div style="font-size:10px;color:var(--txt-mid);">Meta: ${fmtBRL(meta)}</div>`:''}
      <div style="font-size:10px;color:var(--txt-mid);margin-top:4px;">Pagamento: 05/${String(dataVenc.getMonth()+1).padStart(2,'0')}/${dataVenc.getFullYear()}</div>
    </div>`;
  }
  document.getElementById('dash-comissoes-grid').innerHTML=calcCard('b2b',totB2B)+calcCard('b2c',totB2C);
  // Cascata (se coordenador ou gerente)
  if(CU.role==='coordenador'||CU.role==='gerente'){
    const subs=usersCache.filter(u=>u.reportaPara===CU.user&&u.ativo);
    if(subs.length){
      let cascataRows=[]; try{ cascataRows=await dbCall('select','comissoes',{select:'*',filters:{beneficiario:CU.user}}); }catch(e){}
      const deste_mes=cascataRows.filter(r=>r.data_venda?.startsWith(`${ano}-${String(mes).padStart(2,'0')}`)&&r.tipo_comissao==='cascata');
      if(deste_mes.length){
        const totalCascata=deste_mes.reduce((s,r)=>s+(parseFloat(r.valor_comissao)||0),0);
        const totalDireto=deste_mes.reduce((s,r)=>s+(parseFloat(r.valor_venda)||0),0);
        document.getElementById('dash-comissoes-cascata').style.display='block';
        document.getElementById('dash-comissoes-cascata-grid').innerHTML=`
          <div style="background:var(--cream);border-radius:10px;padding:16px;border-left:4px solid var(--gold);">
            <div style="font-size:11px;font-weight:bold;color:var(--gold);margin-bottom:8px;">CASCATA — Equipe (${subs.length} pessoas)</div>
            <div style="font-size:18px;font-weight:bold;color:var(--wine);">${fmtBRL(totalCascata)}</div>
            <div style="font-size:10px;color:var(--txt-mid);margin-top:4px;">Sobre vendas da equipe: ${fmtBRL(totalDireto)}</div>
          </div>`;
      }
    }
  }
}

