async function renderEstabelecimentos(){
  const sec=document.getElementById('dash-estabelecimentos-section');
  if(!sec)return;
  const isAG=CU.role==='admin'||CU.role==='gerente';
  if(!isAG){sec.style.display='none';return;}
  sec.style.display='block';
  const ano=parseInt(document.getElementById('est-ano')?.value||new Date().getFullYear());
  const mes=parseInt(document.getElementById('est-mes')?.value||0);
  const lista=document.getElementById('dash-estabelecimentos-list');
  lista.innerHTML='<div style="padding:10px;color:var(--txt-mid);font-size:12px;">Calculando...</div>';
  try{
    const pedidos=S.pedidos().filter(p=>{
      if(p.deletedAt)return false;
      const d=new Date(p.faturamento?.data||p.data||'');
      if(isNaN(d))return false;
      if(d.getFullYear()!==ano)return false;
      if(mes>0&&d.getMonth()+1!==mes)return false;
      return true;
    });
    // Agrupar por CNPJ/CPF
    const map={};
    pedidos.forEach(p=>{
      const doc=p.cliente?.cnpj||p.cliente?.cpf||'SEM DOC';
      if(!map[doc]) map[doc]={razao:p.cliente?.razao||'?',cnpj:p.cliente?.cnpj||'',cpf:p.cliente?.cpf||'',garrafas:0,valor:0,pedidos:0,tipo:p.cType};
      const garrafas=p.items?.reduce((s,it)=>s+(it.qty||0),0)||0;
      map[doc].garrafas+=garrafas;
      map[doc].valor+=(p.total||0);
      map[doc].pedidos++;
    });
    // Buscar bonificações aprovadas
    let aprovados=[]; try{ aprovados=await dbCall('select','bonificacao_config',{select:'*'}); }catch(e){}
    const aprovMap={};aprovados.forEach(a=>aprovMap[a.cnpj]=a);
    const sorted=Object.entries(map).sort(([,a],[,b])=>b.garrafas-a.garrafas);
    if(!sorted.length){lista.innerHTML='<div style="padding:12px;color:var(--txt-mid);font-size:12px;">Nenhum pedido no período.</div>';return;}
    lista.innerHTML=`<table style="width:100%;border-collapse:collapse;font-size:11px;">
      <thead><tr style="border-bottom:2px solid var(--stripe);">
        <th style="padding:7px 6px;text-align:left;">Estabelecimento</th>
        <th style="padding:7px 6px;">Pedidos</th>
        <th style="padding:7px 6px;">Garrafas</th>
        <th style="padding:7px 6px;">Valor</th>
        <th style="padding:7px 6px;">Bonificação</th>
        <th style="padding:7px 6px;">Step</th>
      </tr></thead>
      <tbody>${sorted.map(([doc,d])=>{
        const {step,garrafasBonus,credito,rotulo}=calcBonificacao(d.garrafas,d.valor,d.pedidos);
        const aprovado=aprovMap[d.cnpj];
        const bonStr=step>=0?`<span style="color:var(--green);font-weight:bold;">${garrafasBonus} gar. + ${fmtBRL(credito)}</span>`:'<span style="color:var(--txt-mid);">—</span>';
        const stepStr=step>=0?`<span style="background:var(--wine);color:var(--gold);padding:2px 7px;border-radius:4px;font-size:10px;">Step ${step}</span>`:'<span style="color:var(--txt-mid);font-size:10px;">&lt;60 gar.</span>';
        return `<tr style="border-bottom:1px solid var(--stripe);">
          <td style="padding:7px 6px;"><strong>${d.razao}</strong><br><span style="font-size:10px;color:var(--txt-mid);">${d.cnpj||d.cpf}</span>${aprovado?'<span style="margin-left:6px;background:var(--green);color:white;font-size:9px;padding:1px 5px;border-radius:3px;">✓ Bonif.</span>':''}</td>
          <td style="padding:7px 6px;text-align:center;">${d.pedidos}</td>
          <td style="padding:7px 6px;text-align:center;">${d.garrafas}</td>
          <td style="padding:7px 6px;">${fmtBRL(d.valor)}</td>
          <td style="padding:7px 6px;">${aprovado?bonStr:'<span style="color:var(--txt-mid);font-size:10px;">Não aprovado</span>'}</td>
          <td style="padding:7px 6px;">${aprovado?stepStr:'—'}</td>
        </tr>`;
      }).join('')}</tbody>
    </table>`;
  }catch(e){lista.innerHTML=`<div style="color:var(--red);padding:10px;font-size:12px;">Erro: ${e.message}</div>`;}
}

// ══════════════════════════════════════════════
// BONIFICAÇÃO B2B — Steps padrão do programa
// ══════════════════════════════════════════════
const BON_STEPS_PADRAO=[
  {min:60,  bonus:3,  credito:0},
  {min:80,  bonus:4,  credito:0},
  {min:100, bonus:5,  credito:100},
  {min:120, bonus:6,  credito:100},
  {min:140, bonus:7,  credito:100},
  {min:160, bonus:8,  credito:100},
  {min:180, bonus:9,  credito:100},
  {min:200, bonus:10, credito:100},
  {min:220, bonus:11, credito:100},
  {min:240, bonus:12, credito:200},
];

function calcBonificacao(garrafas, valor, numPedidos, stepsCustom=null){
  const steps=BON_STEPS_PADRAO.map((s,i)=>{
    const c=stepsCustom?.[i];
    return {min:c?.min??s.min, bonus:c?.bonus??s.bonus, credito:c?.credito??s.credito};
  });
  if(garrafas<steps[0].min) return {step:-1,garrafasBonus:0,credito:0};
  let idx=0;
  for(let i=steps.length-1;i>=0;i--){ if(garrafas>=steps[i].min){idx=i;break;} }
  return {step:idx, garrafasBonus:steps[idx].bonus, credito:steps[idx].credito};
}

