let bonTab='solicitar';
function setBonCanal(canal,btn){
  document.getElementById('bon-b2b-tabs').style.display=canal==='b2b'?'block':'none';
  document.getElementById('bon-b2c-content').style.display=canal==='b2c'?'block':'none';
  ['b2b','b2c'].forEach(c=>{
    const el=document.getElementById('bon-canal-'+c);
    if(!el)return;
    el.style.background=c===canal?'var(--wine)':'none';
    el.style.color=c===canal?'var(--gold)':'var(--txt-mid)';
    el.style.border=c===canal?'1.5px solid var(--wine)':'1.5px solid var(--stripe)';
  });
}
function setBonTab(t){
  bonTab=t;
  ['solicitar','aprov-pen','cnpjs','apurado','historico'].forEach(x=>{
    const c=document.getElementById('btab-content-'+x);
    if(c) c.style.display=x===t?'block':'none';
    const b=document.getElementById('btab-'+x);
    if(b){b.style.borderBottomColor=x===t?'var(--wine)':'transparent';b.style.color=x===t?'var(--wine)':'var(--txt-mid)';}
  });
  if(t==='solicitar') initSolicitarBonif();
  if(t==='aprov-pen') renderAprovPenBonif();
  if(t==='cnpjs')     renderBonCnpjs();
  if(t==='apurado')   renderApuracao();
  if(t==='historico') renderHistoricoBonif();
}
async function initBonificacao(){
  const ano=new Date().getFullYear();
  const selA=document.getElementById('bon-ano');
  if(selA&&!selA.innerHTML) selA.innerHTML=[ano-1,ano,ano+1].map(a=>`<option value="${a}" ${a===ano?'selected':''}>${a}</option>`).join('');
  const selM=document.getElementById('bon-mes');
  if(selM&&!selM.innerHTML) selM.innerHTML=MESES.map((m,i)=>`<option value="${i+1}" ${i+1===new Date().getMonth()+1?'selected':''}>${m}</option>`).join('');
  setBonTab('solicitar');
}
function abrirSolicitarBonif(){showPage('bonificacao');setTimeout(()=>setBonTab('solicitar'),100);}

