// ABA SOLICITAR — formulário completo
// ══════════════════════════════════════════════
function initSolicitarBonif(){
  // Botão de ação conforme papel
  const btn=document.getElementById('btn-submeter-bonif');
  if(btn) btn.textContent=CU?.role==='admin'?'✅ Aprovar':'📤 Enviar para Aprovação';
  // Montar tabela de steps
  montarTabelaSteps();
  // Vigência padrão: início = mês atual
  const hoje=new Date();
  const mesAtual=`${hoje.getFullYear()}-${String(hoje.getMonth()+1).padStart(2,'0')}`;
  const inpInicio=document.getElementById('bon-vig-inicio');
  if(inpInicio&&!inpInicio.value) inpInicio.value=mesAtual;
  calcVigencia();
}
function montarTabelaSteps(){
  const tbody=document.getElementById('bon-steps-tbody');
  if(!tbody)return;
  tbody.innerHTML=BON_STEPS_PADRAO.map((s,i)=>`
    <tr style="border-bottom:0.5px solid var(--stripe);${i<2?'':'background:'+(i%2?'var(--cream)':'white')+';'}">
      <td style="padding:5px 8px;text-align:center;font-weight:bold;color:var(--wine);">${i}</td>
      <td style="padding:4px 6px;">
        <input class="fi bon-step-min" data-step="${i}" type="number" min="0" value="${s.min}"
          style="width:80px;font-size:11px;text-align:center;padding:3px 5px;" oninput="validarStep(${i})">
      </td>
      <td style="padding:4px 6px;" class="col-garrafas">
        <input class="fi bon-step-bonus" data-step="${i}" type="number" min="0" value="${s.bonus}"
          style="width:80px;font-size:11px;text-align:center;padding:3px 5px;">
      </td>
      <td style="padding:4px 6px;" class="col-credito">
        <input class="fi bon-step-credito" data-step="${i}" type="number" min="0" value="${s.credito}"
          style="width:80px;font-size:11px;text-align:center;padding:3px 5px;">
      </td>
    </tr>`).join('');
}
function validarStep(idx){
  if(idx===0)return;
  const mins=[...document.querySelectorAll('.bon-step-min')];
  const valAtual=parseInt(mins[idx]?.value)||0;
  const valAnterior=parseInt(mins[idx-1]?.value)||0;
  if(valAtual<=valAnterior){
    mins[idx].style.border='1.5px solid var(--red)';
    showToast(`Step ${idx} deve ter volume maior que o step ${idx-1} (${valAnterior})`);
  } else {
    mins[idx].style.border='';
  }
}
function updateBonTipo(){
  const tipo=document.querySelector('input[name="bon-tipo"]:checked')?.value||'ambos';
  // Atualizar visual dos botões de tipo
  ['garrafas','monetario','ambos'].forEach(t=>{
    const btn=document.getElementById('bon-tipo-btn-'+t);
    if(!btn)return;
    if(t===tipo){btn.style.background='var(--wine)';btn.style.color='var(--gold)';btn.style.border='1.5px solid var(--wine)';}
    else{btn.style.background='white';btn.style.color='var(--txt-mid)';btn.style.border='1.5px solid var(--stripe)';}
  });
  // Mostrar/ocultar colunas
  const showG=tipo==='garrafas'||tipo==='ambos';
  const showM=tipo==='monetario'||tipo==='ambos';
  document.querySelectorAll('.col-garrafas').forEach(el=>el.style.display=showG?'':'none');
  document.querySelectorAll('.col-credito').forEach(el=>el.style.display=showM?'':'none');
  const thG=document.getElementById('bon-col-garrafas');
  const thM=document.getElementById('bon-col-credito');
  if(thG) thG.style.display=showG?'':'none';
  if(thM) thM.style.display=showM?'':'none';
}
function calcVigencia(){
  const inicio=document.getElementById('bon-vig-inicio')?.value;
  const meses=parseInt(document.getElementById('bon-vig-meses')?.value||12);
  if(!inicio)return;
  const [ano,mes]=inicio.split('-').map(Number);
  const fim=new Date(ano,mes-1+meses,1);
  const fimStr=`${fim.getFullYear()}-${String(fim.getMonth()+1).padStart(2,'0')}`;
  const elFim=document.getElementById('bon-vig-fim');
  if(elFim) elFim.value=fimStr;
}

// Busca de cliente B2B para bonificação
function buscarClienteBon(){
  const q=(document.getElementById('bon-cli-busca')?.value||'').trim();
  const drop=document.getElementById('bon-cli-drop');
  if(!drop)return;
  if(q.length<2){drop.style.display='none';return;}
  const todos=[...S.clientes()];
  clientesCache.forEach(c=>{if(!todos.find(x=>x.id===c.id))todos.push(c);});
  const matches=todos.filter(c=>c.cnpj&&((c.razao||'').toLowerCase().includes(q.toLowerCase())||(c.cnpj||'').includes(q))).slice(0,8);
  if(!matches.length){
    drop.innerHTML='<div style="padding:10px;font-size:11px;color:var(--txt-mid);">Nenhum cliente B2B encontrado. <strong onclick="showPage(\'clientes\')" style="color:var(--wine);cursor:pointer;">Cadastrar agora →</strong></div>';
    drop.style.display='block';return;
  }
  drop.innerHTML=matches.map(c=>`<div onclick="selecionarClienteBon('${c.id}')" style="padding:9px 12px;cursor:pointer;font-size:12px;border-bottom:0.5px solid var(--stripe);" onmouseover="this.style.background='var(--cream)'" onmouseout="this.style.background=''">
    <strong>${c.razao}</strong> <span style="font-size:10px;color:var(--txt-mid);">${c.cnpj}</span>
  </div>`).join('');
  drop.style.display='block';
}
function selecionarClienteBon(id){
  const c=S.clientes().find(x=>x.id===id)||clientesCache.find(x=>x.id===id);
  if(!c)return;
  document.getElementById('bon-cli-busca').value=c.razao;
  document.getElementById('bon-cli-cnpj').value=c.cnpj||'';
  document.getElementById('bon-cli-razao').value=c.razao||'';
  document.getElementById('bon-cli-drop').style.display='none';
}
document.addEventListener('click',e=>{if(!e.target.closest('#bon-cli-busca')&&!e.target.closest('#bon-cli-drop'))document.getElementById('bon-cli-drop')?.style && (document.getElementById('bon-cli-drop').style.display='none');});

async function submeterBonificacao(){
  const cnpj=document.getElementById('bon-cli-cnpj')?.value.trim();
  const razao=document.getElementById('bon-cli-razao')?.value.trim();
  if(!cnpj||!razao){showToast('Selecione um cliente B2B cadastrado');return;}
  const inicio=document.getElementById('bon-vig-inicio')?.value;
  const fim=document.getElementById('bon-vig-fim')?.value;
  if(!inicio){showToast('Informe a data de início da vigência');return;}
  // Coletar steps
  const mins=[...document.querySelectorAll('.bon-step-min')];
  // Validar steps
  for(let i=1;i<mins.length;i++){
    if(parseInt(mins[i].value)<parseInt(mins[i-1].value)){
      showToast(`Step ${i} tem volume menor que o step anterior. Corrija antes de enviar.`);return;
    }
  }
  const steps=BON_STEPS_PADRAO.map((s,i)=>({
    step:i,
    min:parseInt(document.querySelectorAll('.bon-step-min')[i]?.value)||s.min,
    bonus:parseInt(document.querySelectorAll('.bon-step-bonus')[i]?.value)||s.bonus,
    credito:parseFloat(document.querySelectorAll('.bon-step-credito')[i]?.value)||s.credito
  }));
  const tipo=document.querySelector('input[name="bon-tipo"]:checked')?.value||'ambos';
  const isAdmin=CU.role==='admin';
  const isGerente=CU.role==='gerente'||CU.role==='coordenador';
  const status=isAdmin?'aprovado':isGerente?'aguarda_admin':'aguarda_gerente';
  const meses=parseInt(document.getElementById('bon-vig-meses')?.value||12);
  const data={cnpj,razao_social:razao,ativo:true,
    data_inicio:inicio+'-01', data_fim:fim+'-01',
    validade_meses:meses, tipo_bonificacao:tipo,
    steps_config:JSON.stringify(steps),
    solicitante:CU.user, status,
    aprovado_por:isAdmin?CU.user:null,
    aprovado_em:isAdmin?new Date().toISOString():null,
    created_at:new Date().toISOString(), updated_at:new Date().toISOString()
  };
  try{
    await dbCall('upsert','bonificacao_config',{data,onConflict:'cnpj'});
    audit('criar',`Bonificação ${isAdmin?'aprovada':'solicitada'}: ${razao}`);
    showToast(isAdmin?'Bonificação aprovada!':'Solicitação enviada para aprovação!',true);
    // Limpar formulário
    ['bon-cli-busca','bon-cli-cnpj','bon-cli-razao','bon-vig-inicio','bon-vig-fim'].forEach(id=>{const el=document.getElementById(id);if(el)el.value='';});
    montarTabelaSteps();
    setBonTab(isAdmin?'cnpjs':'aprov-pen');
    await atualizarBadgeAprovacoes();
  }catch(e){showToast('Erro: '+e.message);}
}

// ══════════════════════════════════════════════
// ABA PENDENTES
// ══════════════════════════════════════════════
async function renderAprovPenBonif(){
  const div=document.getElementById('bon-aprov-pen-list');
  if(!div)return;
  div.innerHTML='<div style="padding:8px;color:var(--txt-mid);">Carregando...</div>';
  const isAdmin=CU.role==='admin';
  const isGerente=CU.role==='gerente'||CU.role==='coordenador';
  let rows=[];
  try{ rows=await dbCall('select','bonificacao_config',{select:'*',order:'created_at.desc'}); }catch(e){}
  const pendentes=rows.filter(r=>isAdmin?(r.status==='aguarda_admin'||r.status==='aguarda_gerente'):isGerente?(r.status==='aguarda_gerente'):false);
  if(!pendentes.length){div.innerHTML='<div class="empty"><p>Nenhuma solicitação pendente.</p></div>';return;}
  div.innerHTML=pendentes.map(r=>`<div style="background:var(--cream);border-radius:10px;padding:14px;margin-bottom:10px;cursor:pointer;" onclick="abrirDetalhesBonif(${r.id},'pendente')">
    <div style="display:flex;justify-content:space-between;align-items:flex-start;margin-bottom:6px;">
      <div><strong style="font-size:13px;">${r.razao_social}</strong><br>
        <span style="font-size:10px;color:var(--txt-mid);">${r.cnpj} · Solicitante: ${r.solicitante||'—'}</span>
      </div>
      <span style="background:var(--gold-light);color:var(--wine);padding:3px 8px;border-radius:6px;font-size:10px;">${r.status==='aguarda_gerente'?'⏳ Aguarda Gerente':'⏳ Aguarda Admin'}</span>
    </div>
    <div style="font-size:11px;color:var(--txt-mid);">Vigência: ${r.data_inicio?new Date(r.data_inicio+'T12:00').toLocaleDateString('pt-BR','month only',{month:'short',year:'numeric'}):'—'} → ${r.data_fim?new Date(r.data_fim+'T12:00').toLocaleDateString('pt-BR'):''} · ${r.tipo_bonificacao||'ambos'}</div>
    <div style="margin-top:8px;display:flex;gap:6px;">
      <button class="btn-grn" style="padding:5px 12px;font-size:11px;" onclick="event.stopPropagation();aprovarBonifPendente(${r.id})">✅ Aprovar</button>
      <button class="bsm bsm-d" onclick="event.stopPropagation();recusarBonifPendente(${r.id})">❌ Recusar</button>
      <button class="bsm bsm-w" onclick="event.stopPropagation();abrirDetalhesBonif(${r.id},'pendente')">👁 Ver detalhes</button>
    </div>
  </div>`).join('');
}
async function aprovarBonifPendente(id){
  const isAdmin=CU.role==='admin';
  const isGerente=CU.role==='gerente'||CU.role==='coordenador';
  let novoStatus='aprovado';
  if(!isAdmin&&isGerente) novoStatus='aguarda_admin';
  try{
    await dbCall('update','bonificacao_config',{data:{status:novoStatus,aprovado_por:CU.user,aprovado_em:new Date().toISOString(),updated_at:new Date().toISOString()},filters:{id}});
    audit('editar',`Bonificação ${novoStatus==='aprovado'?'aprovada':'encaminhada ao admin'}: ID ${id}`);
    showToast(novoStatus==='aprovado'?'Aprovado!':'Encaminhado ao admin',true);
    await renderAprovPenBonif();
    await atualizarBadgeAprovacoes();
  }catch(e){showToast('Erro: '+e.message);}
}
async function recusarBonifPendente(id){
  if(!confirm('Recusar esta solicitação de bonificação?'))return;
  try{
    await dbCall('update','bonificacao_config',{data:{status:'recusado',aprovado_por:CU.user,aprovado_em:new Date().toISOString(),updated_at:new Date().toISOString()},filters:{id}});
    showToast('Solicitação recusada');
    await renderAprovPenBonif();
    await atualizarBadgeAprovacoes();
  }catch(e){showToast('Erro: '+e.message);}
}

