async function renderBonCnpjs(){
  const div=document.getElementById('bon-cnpjs-list');
  if(!div)return;
  div.innerHTML='<div style="padding:8px;color:var(--txt-mid);">Carregando...</div>';
  let rows=[]; try{ rows=await dbCall('select','bonificacao_config',{select:'*',order:'razao_social.asc'}); }catch(e){}
  const aprovados=rows.filter(r=>r.status==='aprovado');
  if(!aprovados.length){div.innerHTML='<div class="empty"><p>Nenhum estabelecimento aprovado ainda.</p></div>';return;}
  const hoje=new Date();
  const isAdmin=CU.role==='admin';
  div.innerHTML=aprovados.map(r=>{
    const fim=r.data_fim?new Date(r.data_fim+'T12:00'):null;
    const expirado=fim&&fim<hoje;
    const tipo=r.tipo_bonificacao||'ambos';
    const tipoLabel={garrafas:'🍷 Garrafas',monetario:'💰 Monetário',ambos:'🍷💰 Ambos'}[tipo]||tipo;
    return `<div style="background:var(--cream);border-radius:10px;padding:14px;margin-bottom:10px;cursor:pointer;opacity:${expirado?0.6:1};" onclick="abrirDetalhesBonif(${r.id},'aprovado')">
      <div style="display:flex;justify-content:space-between;align-items:flex-start;flex-wrap:wrap;gap:6px;">
        <div><strong style="font-size:13px;">${r.razao_social}</strong><br>
          <span style="font-size:10px;color:var(--txt-mid);">${r.cnpj}</span>
        </div>
        <div style="display:flex;gap:6px;align-items:center;flex-wrap:wrap;">
          <span style="font-size:10px;padding:2px 8px;border-radius:6px;background:${expirado?'var(--red)':'var(--green)'};color:white;">${expirado?'⛔ Expirado':'✅ Ativo'}</span>
          <span style="font-size:10px;color:var(--txt-mid);">${tipoLabel}</span>
          ${isAdmin?`<button class="bsm bsm-w" onclick="event.stopPropagation();editarPlano(${r.id})">✏️</button>`:''}
        </div>
      </div>
      <div style="font-size:11px;color:var(--txt-mid);margin-top:6px;">
        Vigência: ${r.data_inicio?new Date(r.data_inicio+'T12:00').toLocaleDateString('pt-BR'):''} → ${fim?fim.toLocaleDateString('pt-BR'):'—'} · ${r.validade_meses||12} meses
      </div>
    </div>`;
  }).join('');
}

async function abrirDetalhesBonif(id, contexto){
  let rows=[]; try{ rows=await dbCall('select','bonificacao_config',{select:'*',filters:{id}}); }catch(e){}
  const r=rows[0];if(!r)return;
  const steps=r.steps_config?JSON.parse(r.steps_config):BON_STEPS_PADRAO;
  const tipo=r.tipo_bonificacao||'ambos';
  const showG=tipo==='garrafas'||tipo==='ambos';
  const showM=tipo==='monetario'||tipo==='ambos';
  const titulo=document.getElementById('mbd-title');
  const body=document.getElementById('mbd-body');
  const btns=document.getElementById('mbd-btns');
  if(titulo) titulo.textContent=`${r.razao_social} — Plano de Bonificação`;
  if(body) body.innerHTML=`
    <div style="margin-bottom:12px;">
      <div style="display:grid;grid-template-columns:1fr 1fr;gap:8px;font-size:11px;margin-bottom:10px;">
        <div><strong>CNPJ:</strong> ${r.cnpj}</div>
        <div><strong>Tipo:</strong> ${{garrafas:'🍷 Somente Garrafas',monetario:'💰 Somente Monetário',ambos:'🍷💰 Garrafas + Monetário'}[tipo]||tipo}</div>
        <div><strong>Início:</strong> ${r.data_inicio?new Date(r.data_inicio+'T12:00').toLocaleDateString('pt-BR'):''}</div>
        <div><strong>Término:</strong> ${r.data_fim?new Date(r.data_fim+'T12:00').toLocaleDateString('pt-BR'):''}</div>
        <div><strong>Vigência:</strong> ${r.validade_meses||12} meses</div>
        <div><strong>Solicitante:</strong> ${r.solicitante||'—'}</div>
      </div>
      <div style="font-size:11px;font-weight:bold;color:var(--wine);margin-bottom:6px;">Steps de bonificação</div>
      <div class="tbl-scroll">
        <table style="width:100%;border-collapse:collapse;font-size:11px;min-width:300px;">
          <thead><tr style="background:var(--wine);color:var(--gold);">
            <th style="padding:5px 8px;">Step</th>
            <th style="padding:5px 8px;">Mín. garrafas</th>
            ${showG?'<th style="padding:5px 8px;">Garrafas bônus</th>':''}
            ${showM?'<th style="padding:5px 8px;">Crédito R$</th>':''}
          </tr></thead>
          <tbody>${steps.map((s,i)=>`<tr style="border-bottom:0.5px solid var(--stripe);background:${i%2?'var(--cream)':'white'}">
            <td style="padding:5px 8px;text-align:center;font-weight:bold;">${s.step??i}</td>
            <td style="padding:5px 8px;text-align:center;">${s.min||BON_STEPS_PADRAO[i]?.min}</td>
            ${showG?`<td style="padding:5px 8px;text-align:center;color:var(--green);font-weight:bold;">${s.bonus??BON_STEPS_PADRAO[i]?.bonus} 🍷</td>`:''}
            ${showM?`<td style="padding:5px 8px;text-align:center;color:var(--green);font-weight:bold;">R$ ${s.credito??BON_STEPS_PADRAO[i]?.credito}</td>`:''}
          </tr>`).join('')}</tbody>
        </table>
      </div>
    </div>`;
  if(btns){
    const isAdmin=CU.role==='admin';
    btns.innerHTML=`<button class="btn-clr" onclick="closeModal('modal-bon-detalhe')">Fechar</button>
      ${isAdmin&&contexto==='aprovado'?`<button class="bsm bsm-w" onclick="closeModal('modal-bon-detalhe');editarPlano(${r.id})">✏️ Editar</button>`:''}
      ${isAdmin&&(contexto==='pendente')?`<button class="btn-grn" onclick="closeModal('modal-bon-detalhe');aprovarBonifPendente(${r.id})">✅ Aprovar</button>`:''}`;
  }
  document.getElementById('modal-bon-detalhe').classList.add('open');
}

async function editarPlano(id){
  if(CU.role!=='admin'){showToast('Apenas o administrador pode editar planos aprovados');return;}
  let rows=[]; try{ rows=await dbCall('select','bonificacao_config',{select:'*',filters:{id}}); }catch(e){}
  const r=rows[0];if(!r)return;
  setBonTab('solicitar');
  setTimeout(()=>{
    document.getElementById('bon-cli-busca').value=r.razao_social;
    document.getElementById('bon-cli-cnpj').value=r.cnpj;
    document.getElementById('bon-cli-razao').value=r.razao_social;
    if(r.data_inicio){const d=r.data_inicio.slice(0,7);document.getElementById('bon-vig-inicio').value=d;}
    document.getElementById('bon-vig-meses').value=r.validade_meses||12;
    calcVigencia();
    // Preencher tipo
    const tipo=r.tipo_bonificacao||'ambos';
    const radioEl=document.getElementById('bon-tipo-'+tipo);
    if(radioEl){radioEl.checked=true;updateBonTipo();}
    // Preencher steps
    if(r.steps_config){
      const steps=JSON.parse(r.steps_config);
      steps.forEach(s=>{
        const mins=document.querySelectorAll('.bon-step-min');
        const bonus=document.querySelectorAll('.bon-step-bonus');
        const credito=document.querySelectorAll('.bon-step-credito');
        const i=s.step??0;
        if(mins[i]) mins[i].value=s.min;
        if(bonus[i]) bonus[i].value=s.bonus;
        if(credito[i]) credito[i].value=s.credito;
      });
    }
    document.getElementById('bon-cli-busca').scrollIntoView({behavior:'smooth'});
    showToast('Plano carregado para edição',false,true);
  },200);
}

async function aprovarCnpj(){return submeterBonificacao();}
async function removerBonCnpj(id){
  if(!confirm('Remover este plano de bonificação?'))return;
  try{ await dbCall('delete','bonificacao_config',{filters:{id}}); await renderBonCnpjs(); showToast('Removido',true); }
  catch(e){showToast('Erro: '+e.message);}
}

// ══════════════════════════════════════════════
// ABA APURAÇÃO DO MÊS
// ══════════════════════════════════════════════
async function renderApuracao(){
  const ano=parseInt(document.getElementById('bon-ano')?.value||new Date().getFullYear());
  const mes=parseInt(document.getElementById('bon-mes')?.value||new Date().getMonth()+1);
  const div=document.getElementById('bon-apurado-list');
  if(!div)return;
  div.innerHTML='<div style="padding:8px;color:var(--txt-mid);">Calculando...</div>';
  try{
    let aprovados=[];
    try{ aprovados=await dbCall('select','bonificacao_config',{select:'*',filters:{status:'aprovado'}}); }catch(e){}
    const aprovMap={};aprovados.forEach(a=>aprovMap[a.cnpj]=a);
    // Pedidos do mês enviados ou fechados
    const pedidos=S.pedidos().filter(p=>{
      if(p.deletedAt)return false;
      if(!p.blingId&&p.status!=='fechado')return false;
      const d=new Date((p.faturamento?.data||p.data||'')+'T12:00:00');
      if(isNaN(d))return false;
      return d.getFullYear()===ano&&d.getMonth()+1===mes;
    });
    // Agrupar por CNPJ
    const mapa={};
    pedidos.forEach(p=>{
      const cnpj=(p.cliente?.cnpj||'').replace(/\D/g,'');
      if(!cnpj||!aprovMap[p.cliente?.cnpj])return;
      const key=p.cliente.cnpj;
      if(!mapa[key]) mapa[key]={cnpj:key,razao:aprovMap[key].razao_social,garrafas:0,valor:0,pedidosList:[],plano:aprovMap[key]};
      const g=p.items?.reduce((s,it)=>s+(it.qty||0),0)||0;
      mapa[key].garrafas+=g;
      mapa[key].valor+=(p.total||0);
      mapa[key].pedidosList.push(p);
    });
    const entries=Object.entries(mapa);
    if(!entries.length){
      div.innerHTML=`<div class="empty"><p>Nenhum estabelecimento aprovado com pedidos em ${MESES[mes-1]} ${ano}.</p></div>`;
      return;
    }
    div.innerHTML=`<div class="tbl-scroll"><table style="width:100%;border-collapse:collapse;font-size:11px;min-width:550px;">
      <thead><tr style="background:var(--wine);color:var(--gold);">
        <th style="padding:7px 8px;text-align:left;">Estabelecimento</th>
        <th style="padding:7px 8px;text-align:center;">Pedidos</th>
        <th style="padding:7px 8px;text-align:center;">Garrafas</th>
        <th style="padding:7px 8px;">Faturamento</th>
        <th style="padding:7px 8px;text-align:center;">Step</th>
        <th style="padding:7px 8px;">Bonificação</th>
        <th style="padding:7px 8px;"></th>
      </tr></thead>
      <tbody>${entries.map(([cnpj,d])=>{
        const stepsCustom=d.plano.steps_config?JSON.parse(d.plano.steps_config):null;
        const {step,garrafasBonus,credito}=calcBonificacao(d.garrafas,d.valor,d.pedidosList.length,stepsCustom);
        const tipo=d.plano.tipo_bonificacao||'ambos';
        const showG=tipo==='garrafas'||tipo==='ambos';
        const showM=tipo==='monetario'||tipo==='ambos';
        const bonStr=step<0?'<span style="color:var(--txt-mid);font-size:10px;">Abaixo do mínimo</span>':`
          ${showG?`<span style="color:var(--green);">${garrafasBonus}🍷</span>`:''}
          ${showM?`<span style="color:var(--green);margin-left:6px;">R$ ${credito}</span>`:''}`;
        return `<tr style="border-bottom:0.5px solid var(--stripe);cursor:pointer;" onclick="verDetalheApuracao('${cnpj}','${encodeURIComponent(JSON.stringify(d))}')">
          <td style="padding:7px 8px;"><strong>${d.razao}</strong><br><span style="font-size:9px;color:var(--txt-mid);">${cnpj}</span></td>
          <td style="padding:7px 8px;text-align:center;">${d.pedidosList.length}</td>
          <td style="padding:7px 8px;text-align:center;font-weight:bold;">${d.garrafas}</td>
          <td style="padding:7px 8px;">${fmtBRL(d.valor)}</td>
          <td style="padding:7px 8px;text-align:center;">${step>=0?`<span style="background:var(--wine);color:var(--gold);padding:2px 8px;border-radius:4px;font-size:10px;">Step ${step}</span>`:'—'}</td>
          <td style="padding:7px 8px;">${bonStr}</td>
          <td style="padding:7px 8px;"><button class="bsm bsm-w" onclick="event.stopPropagation();verDetalheApuracao('${cnpj}','${encodeURIComponent(JSON.stringify(d))}')">👁</button></td>
        </tr>`;
      }).join('')}</tbody>
    </table></div>`;
  }catch(e){div.innerHTML=`<div style="color:var(--red);padding:10px;">Erro: ${e.message}</div>`;}
}

function verDetalheApuracao(cnpj, dataEnc){
  const d=JSON.parse(decodeURIComponent(dataEnc));
  const stepsCustom=d.plano?.steps_config?JSON.parse(d.plano.steps_config):null;
  const {step,garrafasBonus,credito}=calcBonificacao(d.garrafas,d.valor,d.pedidosList?.length||0,stepsCustom);
  const titulo=document.getElementById('mbd-title');
  const body=document.getElementById('mbd-body');
  const btns=document.getElementById('mbd-btns');
  if(titulo) titulo.textContent=`Apuração — ${d.razao}`;
  if(body) body.innerHTML=`
    <div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:8px;margin-bottom:12px;">
      <div style="background:var(--cream);border-radius:8px;padding:10px;text-align:center;">
        <div style="font-size:18px;font-weight:bold;color:var(--wine);">${d.garrafas}</div>
        <div style="font-size:10px;color:var(--txt-mid);">garrafas</div>
      </div>
      <div style="background:var(--cream);border-radius:8px;padding:10px;text-align:center;">
        <div style="font-size:18px;font-weight:bold;color:var(--wine);">${fmtBRL(d.valor)}</div>
        <div style="font-size:10px;color:var(--txt-mid);">faturamento</div>
      </div>
      <div style="background:var(--cream);border-radius:8px;padding:10px;text-align:center;">
        <div style="font-size:18px;font-weight:bold;color:var(--wine);">${step>=0?'Step '+step:'—'}</div>
        <div style="font-size:10px;color:var(--txt-mid);">step atingido</div>
      </div>
    </div>
    <div style="font-size:11px;font-weight:bold;color:var(--wine);margin-bottom:6px;">Bonificação gerada</div>
    <div style="background:var(--cream);border-radius:8px;padding:10px;margin-bottom:12px;font-size:12px;">
      ${step<0?'⚠️ Volume abaixo do mínimo (Step 0 = '+BON_STEPS_PADRAO[0].min+' garrafas).':`✅ Step ${step} · ${garrafasBonus} garrafas bônus · R$ ${credito} em crédito monetário`}
    </div>
    <div style="font-size:11px;font-weight:bold;color:var(--wine);margin-bottom:6px;">Pedidos do período</div>
    <div class="tbl-scroll"><table style="width:100%;border-collapse:collapse;font-size:11px;min-width:300px;">
      <thead><tr style="background:var(--wine);color:var(--gold);">
        <th style="padding:5px 8px;text-align:left;">Pedido</th>
        <th style="padding:5px 8px;">Data</th>
        <th style="padding:5px 8px;text-align:center;">Garrafas</th>
        <th style="padding:5px 8px;">Total</th>
      </tr></thead>
      <tbody>${(d.pedidosList||[]).map(p=>`<tr style="border-bottom:0.5px solid var(--stripe);">
        <td style="padding:5px 8px;">${p.id}</td>
        <td style="padding:5px 8px;">${p.faturamento?.data?new Date(p.faturamento.data+'T12:00').toLocaleDateString('pt-BR'):''}</td>
        <td style="padding:5px 8px;text-align:center;">${p.items?.reduce((s,it)=>s+(it.qty||0),0)||0}</td>
        <td style="padding:5px 8px;">${fmtBRL(p.total)}</td>
      </tr>`).join('')}</tbody>
    </table></div>`;
  if(btns) btns.innerHTML=`<button class="btn-clr" onclick="closeModal('modal-bon-detalhe')">Fechar</button>`;
  document.getElementById('modal-bon-detalhe').classList.add('open');
}

