let catalogoFiltro='ativos';
function setCatFiltro(f,btn){
  catalogoFiltro=f;
  ['ativos','inativos','todos'].forEach(x=>{
    const b=document.getElementById('cat-tog-'+x);
    if(b)b.className='ctog'+(x===f?' active-all':'');
  });
  renderCatalogo();
}
async function renderCatalogo(){
  const tbody=document.getElementById('catalogo-body');
  if(!tbody)return;
  tbody.innerHTML='<tr><td colspan="8" style="padding:12px;color:var(--txt-mid);text-align:center;">Carregando...</td></tr>';
  let dbRows={};
  try{const rows=await dbCall('select','precos',{select:'*'});rows.forEach(r=>{dbRows[r.nome]=r;});}catch(e){}
  try{const rows=await dbCall('select','rotulos_depara',{select:'*'});rows.forEach(r=>{if(!dbRows[r.rotulo_html])dbRows[r.rotulo_html]={};dbRows[r.rotulo_html].codigo_bling=r.codigo_bling;});}catch(e){}
  // Mesclar CAT com banco
  const map={};
  CAT.forEach(w=>{ map[w.nome]={nome:w.nome,marca:w.marca,safra:w.safra,orig:w.orig,embalagem:'CX 6 un.',b2b:w.b2b,b2c:w.b2c,codigo_bling:'',ativo:true}; });
  Object.values(dbRows).forEach(r=>{if(!r.nome)return;
    if(map[r.nome]){if(r.preco_b2b)map[r.nome].b2b=r.preco_b2b;if(r.preco_b2c)map[r.nome].b2c=r.preco_b2c;if(r.codigo_bling)map[r.nome].codigo_bling=r.codigo_bling;if(r.nome_bling)map[r.nome].nome_bling=r.nome_bling;if(r.ativo===false)map[r.nome].ativo=false;if(r.tipo_produto)map[r.nome].tipo_produto=r.tipo_produto;}
    else{map[r.nome]={nome:r.nome,marca:r.marca||'',safra:r.safra||'',orig:r.orig||'',embalagem:r.embalagem||'CX 6 un.',b2b:r.preco_b2b||0,b2c:r.preco_b2c||0,codigo_bling:r.codigo_bling||'',nome_bling:r.nome_bling||'',tipo_produto:r.tipo_produto||'venda',ativo:r.ativo!==false};}
  });
  // Atualizar CAT em memória
  // Atualizar CAT com dados do banco e filtrar somente produtos de venda
  Object.values(map).forEach(p=>{const idx=CAT.findIndex(w=>w.nome===p.nome);if(idx>=0){CAT[idx].b2b=p.b2b;CAT[idx].b2c=p.b2c;CAT[idx].tipo_produto=p.tipo_produto||'venda';}});
  // CAT_VENDA: só produtos disponíveis para pedidos e amostras
  window.CAT_VENDA=CAT.filter(w=>(w.tipo_produto||'venda')==='venda');
  let produtos=Object.values(map);
  if(catalogoFiltro==='ativos')produtos=produtos.filter(p=>p.ativo!==false);
  else if(catalogoFiltro==='inativos')produtos=produtos.filter(p=>p.ativo===false);
  produtos.sort((a,b)=>a.marca.localeCompare(b.marca)||a.nome.localeCompare(b.nome));
  if(!produtos.length){tbody.innerHTML='<tr><td colspan="8" style="padding:12px;color:var(--txt-mid);">Nenhum produto.</td></tr>';return;}
  tbody.innerHTML=produtos.map((p)=>`<tr style="border-bottom:0.5px solid var(--stripe);opacity:${p.ativo!==false?1:0.5};">
    <td style="padding:7px 6px;"><strong>${p.nome}</strong><br><span style="font-size:10px;color:var(--txt-mid);">${p.marca} · ${p.orig}</span></td>
    <td style="padding:7px 6px;font-size:11px;color:var(--txt-mid);">${p.safra}</td>
    <td style="padding:7px 6px;font-size:11px;color:var(--txt-mid);">${p.embalagem||'CX 6 un.'}</td>
    <td style="padding:7px 6px;">${p.codigo_bling?'<span style="background:var(--green);color:white;padding:2px 5px;border-radius:3px;font-size:10px;">'+p.codigo_bling+'</span>':'<span style="color:var(--txt-mid);font-size:10px;">—</span>'}</td>
    <td style="padding:7px 6px;text-align:right;font-weight:bold;">${p.b2b?'R$ '+p.b2b:'—'}</td>
    <td style="padding:7px 6px;text-align:right;font-weight:bold;">${p.b2c?'R$ '+p.b2c:'—'}</td>
    <td style="padding:7px 6px;text-align:center;">${p.ativo!==false?'<span style="color:var(--green);font-size:11px;">✅</span>':'<span style="color:var(--txt-mid);font-size:11px;">⛔</span>'}</td>
    <td style="padding:7px 6px;display:flex;gap:4px;">
      <button class="bsm bsm-w" onclick="openEditarProduto(${JSON.stringify(p).replace(/"/g,'&quot;')})">✏️</button>
      <button class="bsm ${p.ativo!==false?'bsm-d':'bsm-w'}" onclick="toggleAtivoProduto('${p.nome.replace(/'/g,"\'")}',${p.ativo!==false})">${p.ativo!==false?'🚫':'✅'}</button>
    </td>
  </tr>`).join('');
}
function openNovoProduto(){
  document.getElementById('mp-title').textContent='Novo Produto';
  ['mp-nome','mp-marca','mp-orig','mp-safra','mp-cod','mp-b2b','mp-b2c'].forEach(id=>document.getElementById(id).value='');
  document.getElementById('mp-embal').value='CX 6 un.';
  document.getElementById('mp-tipo-produto').value='venda';
  document.getElementById('modal-produto').classList.add('open');
}
function openEditarProduto(p){
  document.getElementById('mp-title').textContent='Editar Produto';
  document.getElementById('mp-nome').value=p.nome||'';
  document.getElementById('mp-marca').value=p.marca||'';
  document.getElementById('mp-orig').value=p.orig||'';
  document.getElementById('mp-safra').value=p.safra||'';
  document.getElementById('mp-embal').value=p.embalagem||'CX 6 un.';
  document.getElementById('mp-cod').value=p.codigo_bling||'';
  document.getElementById('mp-b2b').value=p.b2b||'';
  document.getElementById('mp-b2c').value=p.b2c||'';
  document.getElementById('mp-tipo-produto').value=p.tipo_produto||'venda';
  document.getElementById('modal-produto').classList.add('open');
}
async function salvarProduto(){
  const nome=document.getElementById('mp-nome').value.trim();
  if(!nome){showToast('Preencha o nome do rótulo');return;}
  const b2b=parseFloat(document.getElementById('mp-b2b').value)||0;
  const b2c=parseFloat(document.getElementById('mp-b2c').value)||0;
  const cod=document.getElementById('mp-cod').value.trim();
  try{
    const tipoProd=document.getElementById('mp-tipo-produto')?.value||'venda';
    await dbCall('upsert','precos',{data:{nome,marca:document.getElementById('mp-marca').value.trim(),orig:document.getElementById('mp-orig').value.trim().toUpperCase(),safra:document.getElementById('mp-safra').value.trim(),embalagem:document.getElementById('mp-embal').value.trim()||'CX 6 un.',preco_b2b:b2b,preco_b2c:b2c,ativo:true,tipo_produto:tipoProd,updated_at:new Date().toISOString()},onConflict:'nome'});
    if(cod)await dbCall('upsert','rotulos_depara',{data:{rotulo_html:nome,codigo_bling:cod,nome_bling:nome,updated_at:new Date().toISOString()},onConflict:'rotulo_html'});
    const idx=CAT.findIndex(w=>w.nome===nome);
    if(idx>=0){CAT[idx].b2b=b2b;CAT[idx].b2c=b2c;}else{CAT.push({nome,marca:document.getElementById('mp-marca').value.trim(),orig:document.getElementById('mp-orig').value.trim(),safra:document.getElementById('mp-safra').value.trim(),tipo:'',b2b,b2c});}
    closeModal('modal-produto');await renderCatalogo();showToast('Produto salvo!',true);
  }catch(e){showToast('Erro: '+e.message);}
}
async function toggleAtivoProduto(nome,estaAtivo){
  if(!confirm((estaAtivo?'Inativar':'Ativar')+' "'+nome+'"?'))return;
  try{
    await dbCall('upsert','precos',{data:{nome,ativo:!estaAtivo,updated_at:new Date().toISOString()},onConflict:'nome'});
    if(estaAtivo){const idx=CAT.findIndex(w=>w.nome===nome);if(idx>=0)CAT.splice(idx,1);}
    await renderCatalogo();showToast(estaAtivo?'Produto inativado':'Produto ativado',true);
  }catch(e){showToast('Erro: '+e.message);}
}


