// USUÁRIOS — via Supabase (tabela "users": ID, Usuario, Nome, Email, senha_hash, role_id, ativo, reporta_para)
// ══════════════════════════════════════════════
async function dbUsers(includeInactive){
  const opts = {select:'*',order:'nome.asc'};
  if (!includeInactive) opts.filters = {ativo:true};
  const rows = await dbCall('select','users',opts);
  return rows.map(r=>({
    id:r.id, user:(r.usuario||'').toLowerCase(), pass:r.senha_hash, name:r.nome||r.usuario,
    role:ROLE_NAME[r.role_id]||'vendedor', ativo:r.ativo!==false, reportaPara:(r.reporta_para||'').toLowerCase()||null
  }));
}
async function dbSaveUser(u, isNew){
  const row = { usuario:u.user, nome:u.name, senha_hash:u.pass, role_id:ROLE_ID[u.role]||6, reporta_para:u.reportaPara||null, ativo:true };
  if (isNew) {
    await dbCall('insert','users',{data:row});
  } else {
    await dbCall('update','users',{data:row, filters:{usuario:u.user}});
  }
}
async function dbDeleteUser(user){
  await dbCall('update','users',{data:{ativo:false}, filters:{usuario:user}});
}

