// ══════════════════════════════════════════════
function audit(action,desc,pedidoId=''){
  const entry={id:'A-'+Date.now(),ts:new Date().toISOString(),user:CU?.user||'?',userName:CU?.name||'?',role:CU?.role||'?',action,desc,pedidoId};
  const log=S.audit();
  log.unshift(entry);
  S.saveA(log.slice(0,5000));
  dbSaveAudit(entry); // grava no Supabase em background
}

