// ══════════════════════════════════════════════
// PERMISSÕES DE MENU
// ══════════════════════════════════════════════
const MENUS_ADM=[
  {key:'aprovacoes', label:'Aprovações',          defaultGerente:true},
  {key:'bonificacao',label:'Bonificações',         defaultGerente:false},
  {key:'comissoes',  label:'Comissões',            defaultGerente:false},
  {key:'audit',      label:'Log de Auditoria',     defaultGerente:false},
  {key:'estoque',    label:'Controle de Estoque',  defaultGerente:false},
  {key:'catalogo',   label:'Catálogo de Produtos', defaultGerente:false},
  {key:'users',      label:'Usuários',             defaultGerente:false},
];
let permissoesCache={};
function menuPermitido(k){
  if(CU?.role==='admin')return true;
  const g=CU?.role==='gerente'||CU?.role==='coordenador';
  if(g&&k==='aprovacoes')return true;
  return permissoesCache[CU?.user]?.[k]===true;
}
function aplicarMenusAdm(){
  const isAdmin=CU?.role==='admin';
  MENUS_ADM.forEach(m=>{
    const el=document.getElementById('nav-'+m.key);
    if(el) el.style.display=(isAdmin||menuPermitido(m.key))?'flex':'none';
  });
  const ep=document.getElementById('nav-permissoes');
  if(ep) ep.style.display=isAdmin?'flex':'none';
  const sb=document.getElementById('sb-adm');
  if(sb) sb.style.display=(isAdmin||MENUS_ADM.some(m=>menuPermitido(m.key)))?'block':'none';
}
async function carregarPermissoes(){
  try{
    const rows=await dbCall('select','user_permissions',{select:'*'});
    permissoesCache={};
    (rows||[]).forEach(r=>{
      if(!permissoesCache[r.usuario_login])permissoesCache[r.usuario_login]={};
      permissoesCache[r.usuario_login][r.menu_key]=r.permitido;
    });
  }catch(e){}
}
async function renderPermissoes(){
  const div=document.getElementById('permissoes-content');
  if(!div)return;
  div.innerHTML='<div style="padding:10px;color:var(--txt-mid);">Carregando...</div>';
  await carregarPermissoes();
  const users=usersCache.filter(u=>u.ativo&&u.role!=='admin');
  if(!users.length){div.innerHTML='<div class="empty"><p>Nenhum usuário para configurar.</p></div>';return;}
  div.innerHTML=users.map(u=>`
    <div style="margin-bottom:20px;background:var(--cream);border-radius:10px;padding:14px;">
      <div style="font-size:13px;font-weight:bold;color:var(--wine);margin-bottom:10px;">${u.name} <span class="rpill rp-${u.role==='gerente'||u.role==='coordenador'?'g':'v'}">${u.role}</span></div>
      <div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(200px,1fr));gap:8px;">
        ${MENUS_ADM.map(m=>{const checked=permissoesCache[u.user]?.[m.key]===true||((u.role==='gerente'||u.role==='coordenador')&&m.defaultGerente);
          return `<label style="display:flex;align-items:center;gap:8px;cursor:pointer;font-size:12px;padding:6px 8px;background:white;border-radius:6px;border:0.5px solid var(--stripe);"><input type="checkbox" ${checked?'checked':''} onchange="salvarPermissao('${u.user}','${m.key}',this.checked)"> ${m.label}</label>`;
        }).join('')}
      </div>
    </div>`).join('');
}
async function salvarPermissao(usuario,menuKey,permitido){
  try{
    await dbCall('upsert','user_permissions',{data:{usuario_login:usuario,menu_key:menuKey,permitido,updated_at:new Date().toISOString()},onConflict:'usuario_login,menu_key'});
    if(!permissoesCache[usuario])permissoesCache[usuario]={};
    permissoesCache[usuario][menuKey]=permitido;
    showToast('Permissão salva',true);
  }catch(e){showToast('Erro: '+e.message);}
}

async function doLogin(){
  const u=document.getElementById('lu').value.trim().toLowerCase();
  const p=document.getElementById('lp').value.trim();
  const btnLogin=document.querySelector('#login-screen button[onclick="doLogin()"]');
  if(btnLogin){btnLogin.disabled=true;btnLogin.textContent='Entrando...';}
  let found=null, viaDb=false;
  try{
    const users=await dbUsers();
    found=users.find(x=>x.user===u&&x.pass===p);
    viaDb=true;
    usersCache=users;
  }catch(e){
    found=defaultUsers().find(x=>x.user.toLowerCase()===u&&x.pass===p);
    usersCache=defaultUsers().map(x=>({...x,user:x.user.toLowerCase(),reportaPara:null,ativo:true}));
  }
  if(btnLogin){btnLogin.disabled=false;btnLogin.textContent='Entrar';}
  if(!found){document.getElementById('lerr').style.display='block';return;}
  CU=found;
  document.getElementById('login-screen').style.display='none';
  document.getElementById('app').style.display='block';
  document.getElementById('sb-logo').src=LOGO;
  const rp={admin:'rp-a',gerente:'rp-g',vendedor:'rp-v',coordenador:'rp-g'};
  const rn={admin:'Administrador',gerente:'Gerente',vendedor:'Vendedor',coordenador:'Coordenador'};
  // Resetar TODOS os menus antes de mostrar os do papel atual
  ['nav-audit','nav-aprovacoes','nav-bonificacao','nav-comissoes','nav-users','nav-catalogo','nav-estoque','nav-permissoes'].forEach(id=>{
    const el=document.getElementById(id); if(el) el.style.display='none';
  });
  const sbAdm=document.getElementById('sb-adm'); if(sbAdm) sbAdm.style.display='none';
  const listTabs=document.getElementById('list-tabs'); if(listTabs) listTabs.style.display='none';
  const vfWrap=document.getElementById('vf-wrap'); if(vfWrap) vfWrap.style.display='none';
  const dashVf=document.getElementById('dash-vf'); if(dashVf) dashVf.style.display='none';
  document.getElementById('sb-user').innerHTML=`👤 <strong>${found.name}</strong><br><span class="rpill ${rp[found.role]}">${rn[found.role]}</span>`;
  document.getElementById('tb-user').textContent=`${found.user} · ${rn[found.role]}`;
  const isAdmin=found.role==='admin';
  const isGerente=found.role==='gerente'||found.role==='coordenador';
  const isAG=isAdmin||isGerente;
  if(isAG) document.getElementById('nl-lbl').textContent='Meus Pedidos';
  // Abas de lista: gerente, coordenador e admin
  if(isAG) document.getElementById('list-tabs').style.display='block';
  // Filtro de vendedor no dashboard: só admin
  if(isAdmin){ document.getElementById('vf-wrap').style.display='block'; document.getElementById('dash-vf').style.display='block'; }
  document.getElementById('sdot').className='sdot ok';
  document.getElementById('slbl').textContent=viaDb?'Conectado · Supabase':'Modo local';
  audit('login','Login realizado');
  // Mostrar menus de CRM (pipeline, interações, tarefas) — visíveis para todos
  ['nav-pipeline','nav-interacoes','nav-tarefas'].forEach(id=>{
    const el=document.getElementById(id);
    if(el) el.style.display='flex';
  });
  // Mostrar menus administrativos conforme papel (sem esperar sync)
  aplicarMenusAdm();
  showPage('dash');
  // Em background: subir pedidos locais para Supabase e depois sincronizar
  if(viaDb){
    setTimeout(async ()=>{
      // 1. Subir pedidos que estão só no localStorage para o Supabase
      const locais=S.pedidos();
      if(locais.length){
        for(const p of locais){
          try{ await dbSavePedido(p); }catch(e){}
        }
      }
      // 2. Sincronizar do Supabase (puxa tudo incluindo pedidos de outros vendedores)
      await syncFromSupabase();
      try{ await carregarPermissoes(); aplicarMenusAdm(); }catch(e){/* mantém menus já exibidos */}
      carregarAlcadas();
      aplicarMenusAdm();
      atualizarBadgeAprovacoes();
      renderDash();
      setTimeout(atualizarBadgeAmostras, 500);
      // 3. Polling a cada 60 segundos — sem precisar de login/logout
      if(window._pollingInterval) clearInterval(window._pollingInterval);
      window._pollingInterval=setInterval(async()=>{
        if(!CU) return clearInterval(window._pollingInterval);
        try{
          await syncFromSupabase();
          const paginaAtiva=document.querySelector('.page.active');
          const pgId=paginaAtiva?.id?.replace('page-','');
          if(pgId==='dash') renderDash();
          else if(pgId==='list') renderList();
          atualizarBadgeAmostras();
        }catch(e){}
      }, 60000);
    }, 1000);
  }
}

function doLogout(){
  audit('login','Logout realizado');
  CU=null;editId=null;
  document.getElementById('login-screen').style.display='flex';
  document.getElementById('app').style.display='none';
  document.getElementById('lu').value='';
  document.getElementById('lp').value='';
  document.getElementById('lerr').style.display='none';
}

