function showPage(name){
  document.querySelectorAll('.page').forEach(p=>p.classList.remove('active'));
  document.querySelectorAll('.ni').forEach(n=>n.classList.remove('active'));
  document.getElementById('page-'+name).classList.add('active');
  const n=document.getElementById('nav-'+name);if(n)n.classList.add('active');
  if(name==='dash')     renderDash();
  if(name==='dash-vol') renderDashVol();
  if(name==='dash-com') renderDashCom();
  if(name==='precos')   renderPrecos();
  if(name==='list')     renderList();
  if(name==='clientes') renderClientes();
  if(name==='audit')    renderAudit();
  if(name==='aprovacoes'){ setAprovTab('amostras'); }
  if(name==='permissoes') renderPermissoes();
  if(name==='users'){renderUsers();loadCfgFields();carregarAlcadasUI();}
  if(name==='rotulos') renderRotulos();
  if(name==='comissoes') initComissoes();
  if(name==='bonificacao') initBonificacao();
  if(name==='amostras') initAmostras();
  if(name==='estoque')  initEstoque();
  if(name==='catalogo') renderCatalogo();
  if(name==='pipeline')   renderPipeline();
  if(name==='interacoes') renderInteracoes();
  if(name==='tarefas')    renderTarefas();
}
