// PEDIDOS DE AMOSTRAS
// ══════════════════════════════════════════════
// Alçadas de aprovação de amostras — carregadas do Supabase (editáveis pelo admin)
let LIMITE_GARRAFAS=3;  // acima disso requer aprovação do admin além do gerente
let LIMITE_VALOR=300;   // acima deste valor B2B requer aprovação do admin

async function carregarAlcadas(){
  try{
    const rows=await dbCall('select','config_sistema',{select:'*',filters:{chave:'alcada_amostras'}});
    if(rows?.[0]?.valor){
      const v=JSON.parse(rows[0].valor);
      if(v.garrafas) LIMITE_GARRAFAS=parseInt(v.garrafas);
      if(v.valor)    LIMITE_VALOR=parseFloat(v.valor);
    }
  }catch(e){/* usa defaults */}
}

async function carregarAlcadasUI(){
  await carregarAlcadas();
  const ga=document.getElementById('alcada-garrafas');
  const va=document.getElementById('alcada-valor');
  if(ga) ga.value=LIMITE_GARRAFAS;
  if(va) va.value=LIMITE_VALOR;
}

async function salvarAlcadas(){
  const g=parseInt(document.getElementById('alcada-garrafas')?.value)||3;
  const v=parseFloat(document.getElementById('alcada-valor')?.value)||300;
  try{
    await dbCall('upsert','config_sistema',{
      data:{chave:'alcada_amostras',valor:JSON.stringify({garrafas:g,valor:v}),updated_at:new Date().toISOString()},
      onConflict:'chave'
    });
    LIMITE_GARRAFAS=g; LIMITE_VALOR=v;
    showToast('Alçadas salvas!',true);
    audit('editar',`Alçadas de amostras atualizadas: >${g} garrafas ou >R$${v} → admin`);
  }catch(e){showToast('Erro: '+e.message);}
}
let amostraTabAtual='todas';
let amostraRecusandoId=null;

function setAmostraTab(tab,btn){
  amostraTabAtual=tab;
  ['todas','pendentes','aprovadas','recusadas'].forEach(t=>{
    const b=document.getElementById('atab-'+t);
    if(b)b.className='ctog'+(t===tab?' active-all':'');
  });
  renderAmostras();
}

async function initAmostras(){
  await renderAmostras();
  atualizarBadgeAmostras();
}

async function atualizarBadgeAmostras(){
  try{
    const rows=await dbCall('select','pedidos_amostras',{select:'id,status'});
    const isAdmin=CU.role==='admin';
    const isGerente=CU.role==='gerente'||CU.role==='coordenador';
    let pendentes=0;
    if(isAdmin) pendentes=rows.filter(r=>r.status==='aguarda_admin').length;
    else if(isGerente) pendentes=rows.filter(r=>r.status==='aguarda_gerente').length;
    const badge=document.getElementById('badge-amostras');
    if(badge){
      if(pendentes>0){badge.style.display='inline';badge.textContent=pendentes;}
      else badge.style.display='none';
    }
  }catch(e){}
}

async function renderAmostras(){
  const div=document.getElementById('amostras-list');
  if(!div)return;
  div.innerHTML='<div style="padding:10px;color:var(--txt-mid);font-size:12px;">Carregando...</div>';
  let rows=[];
  try{ rows=await dbCall('select','pedidos_amostras',{select:'*',order:'created_at.desc'}); }catch(e){ div.innerHTML='<div class="empty"><p>Erro ao carregar amostras.</p></div>'; return; }
  const isAdmin=CU.role==='admin';
  const isGerente=CU.role==='gerente'||CU.role==='coordenador';
  const equipe=isGerente?new Set([CU.user,...usersCache.filter(u=>u.reportaPara===CU.user).map(u=>u.user)]):null;
  // Filtrar por papel
  if(!isAdmin) rows=rows.filter(r=>isGerente?equipe.has(r.vendedor_login):r.vendedor_login===CU.user);
  // Filtrar por aba
  if(amostraTabAtual==='pendentes') rows=rows.filter(r=>r.status==='aguarda_gerente'||r.status==='aguarda_admin');
  else if(amostraTabAtual==='aprovadas') rows=rows.filter(r=>r.status==='aprovado');
  else if(amostraTabAtual==='recusadas') rows=rows.filter(r=>r.status==='recusado');
  if(!rows.length){ div.innerHTML='<div class="empty"><p>Nenhuma solicitação encontrada.</p></div>'; return; }
  const statusLabel={aguarda_gerente:'⏳ Aguarda Gerente',aguarda_admin:'⏳ Aguarda Admin',aprovado:'✅ Aprovado',recusado:'❌ Recusado'};
  const statusColor={aguarda_gerente:'var(--gold)',aguarda_admin:'var(--gold)',aprovado:'var(--green)',recusado:'var(--red)'};
  div.innerHTML=rows.map(r=>{
    const itens=JSON.parse(r.itens_snapshot||'[]');
    const vend=usersCache.find(u=>u.user===r.vendedor_login)?.name||r.vendedor_login;
    const podeAprovarGer=isGerente&&r.status==='aguarda_gerente';
    const podeAprovarAdm=isAdmin&&r.status==='aguarda_admin';
    const podeAprovar=podeAprovarGer||podeAprovarAdm;
    const podeRecusar=podeAprovar;
    return `<div class="pc" style="flex-direction:column;align-items:stretch;margin-bottom:10px;">
      <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:6px;">
        <div><span class="pi-name">${r.cliente_nome||'—'}</span> <span style="font-size:10px;color:var(--txt-mid);">${r.cliente_cnpj||''}</span></div>
        <span style="font-size:11px;font-weight:bold;color:${statusColor[r.status]||'var(--txt-mid)'};">${statusLabel[r.status]||r.status}</span>
      </div>
      <div style="font-size:11px;color:var(--txt-mid);margin-bottom:6px;">
        ${r.data_degustacao?'📅 '+new Date(r.data_degustacao+'T12:00:00').toLocaleDateString('pt-BR'):''} 
        ${r.cliente_endereco?'📍 '+r.cliente_endereco:''} · Solicitante: ${vend}
      </div>
      <div style="font-size:11px;margin-bottom:6px;">
        ${itens.map(it=>`<span style="background:var(--cream);padding:2px 7px;border-radius:4px;margin-right:4px;">${it.nome} (${it.qty} un.)</span>`).join('')}
      </div>
      <div style="display:flex;gap:6px;justify-content:space-between;align-items:center;">
        <div style="font-size:10px;color:var(--txt-mid);">${r.total_garrafas} garrafa(s) · R$ ${r.valor_b2b_total} B2B${r.observacoes?' · '+r.observacoes:''}</div>
        <div style="display:flex;gap:6px;">
          ${podeAprovar?`<button class="bsm bsm-w" style="background:var(--green);color:white;" onclick="aprovarAmostra('${r.id}')">✅ Aprovar</button>
          <button class="bsm bsm-d" onclick="abrirRecusar('${r.id}')">❌ Recusar</button>`:''}
          ${r.status==='recusado'&&r.motivo_recusa?`<span style="font-size:10px;color:var(--red);">Motivo: ${r.motivo_recusa}</span>`:''}
        </div>
      </div>
    </div>`;
  }).join('');
}

function openNovaAmostra(){
  // Popular selects de produtos
  const wrap=document.getElementById('am-itens-wrap');
  wrap.querySelectorAll('.am-select').forEach(sel=>{
    sel.innerHTML=CAT.filter(w=>w.ativo!==false).map(w=>`<option value="${w.nome}" data-b2b="${w.b2b}">${w.nome}</option>`).join('');
  });
  atualizarInfoRegra();
  document.getElementById('modal-amostra').classList.add('open');
}
function addLinhaAmostra(){
  const wrap=document.getElementById('am-itens-wrap');
  const div=document.createElement('div');
  div.style.cssText='display:grid;grid-template-columns:1fr auto auto auto;gap:6px;align-items:center;margin-bottom:6px;';
  div.innerHTML=`<select class="fi am-select" style="font-size:11px;padding:5px 6px;" onchange="atualizarInfoRegra()">${CAT.filter(w=>w.ativo!==false).map(w=>`<option value="${w.nome}" data-b2b="${w.b2b}">${w.nome}</option>`).join('')}</select>
    <input type="number" class="fi am-qty" min="1" value="1" style="width:55px;font-size:11px;padding:5px 6px;" oninput="atualizarInfoRegra()">
    <span class="am-valor" style="font-size:11px;color:var(--txt-mid);min-width:60px;text-align:right;">R$ —</span>
    <button class="bsm bsm-d" onclick="removerLinhaAmostra(this)">✕</button>`;
  wrap.appendChild(div);
  atualizarInfoRegra();
}
function removerLinhaAmostra(btn){ btn.closest('div').remove(); atualizarInfoRegra(); }
function atualizarInfoRegra(){
  let totalGarrafas=0, totalValor=0;
  document.querySelectorAll('#am-itens-wrap > div').forEach(row=>{
    const sel=row.querySelector('.am-select');
    const qty=parseInt(row.querySelector('.am-qty')?.value)||0;
    const b2b=parseFloat(sel?.selectedOptions[0]?.dataset?.b2b)||0;
    const valor=qty*b2b;
    const span=row.querySelector('.am-valor');
    if(span) span.textContent='R$ '+valor.toFixed(2);
    totalGarrafas+=qty; totalValor+=valor;
  });
  const info=document.getElementById('am-regra-info');
  if(!info)return;
  const precisaAdmin=totalGarrafas>LIMITE_GARRAFAS||totalValor>LIMITE_VALOR;
  const isGerente=CU.role==='gerente'||CU.role==='coordenador';
  if(isGerente){
    info.textContent=`Total: ${totalGarrafas} garrafa(s) · R$ ${totalValor.toFixed(2)} B2B → Requer aprovação do administrador`;
  } else if(precisaAdmin){
    info.innerHTML=`⚠️ Total: ${totalGarrafas} garrafa(s) · R$ ${totalValor.toFixed(2)} B2B → <strong>Requer aprovação do gerente e do administrador</strong> (acima do limite)`;
    info.style.color='var(--wine)';
  } else {
    info.innerHTML=`✅ Total: ${totalGarrafas} garrafa(s) · R$ ${totalValor.toFixed(2)} B2B → Requer aprovação do gerente`;
    info.style.color='var(--green)';
  }
}
async function salvarAmostra(){
  const nome=document.getElementById('am-nome').value.trim();
  const cnpj=document.getElementById('am-cnpj').value.trim();
  const data=document.getElementById('am-data').value;
  const end=document.getElementById('am-end').value.trim();
  const obs=document.getElementById('am-obs').value.trim();
  if(!nome){showToast('Informe o nome do estabelecimento');return;}
  const itens=[];
  let totalGarrafas=0,totalValor=0;
  document.querySelectorAll('#am-itens-wrap > div').forEach(row=>{
    const sel=row.querySelector('.am-select');
    const qty=parseInt(row.querySelector('.am-qty')?.value)||0;
    const b2b=parseFloat(sel?.selectedOptions[0]?.dataset?.b2b)||0;
    if(sel&&qty>0){itens.push({nome:sel.value,qty,b2b,valor:qty*b2b});totalGarrafas+=qty;totalValor+=qty*b2b;}
  });
  if(!itens.length){showToast('Adicione pelo menos um produto');return;}
  const isGerente=CU.role==='gerente'||CU.role==='coordenador';
  const precisaAdmin=totalGarrafas>LIMITE_GARRAFAS||totalValor>LIMITE_VALOR;
  let status;
  if(isGerente) status='aguarda_admin';
  else if(precisaAdmin) status='aguarda_gerente'; // gerente aprova primeiro, depois vai para admin
  else status='aguarda_gerente';
  const id='AM-'+Date.now();
  try{
    await dbCall('insert','pedidos_amostras',{data:{id,vendedor_login:CU.user,status,cliente_nome:nome,cliente_cnpj:cnpj,cliente_endereco:end,data_degustacao:data||null,itens_snapshot:JSON.stringify(itens),total_garrafas:totalGarrafas,valor_b2b_total:totalValor,observacoes:obs,created_at:new Date().toISOString(),updated_at:new Date().toISOString()}});
    audit('criar',`Amostra solicitada: ${nome} (${totalGarrafas} gar.)`,id);
    closeModal('modal-amostra');
    await renderAmostras();
    atualizarBadgeAmostras();
    showToast('Solicitação enviada para aprovação!',true);
  }catch(e){showToast('Erro ao salvar: '+e.message);}
}
async function aprovarAmostra(id){
  try{
    const rows=await dbCall('select','pedidos_amostras',{select:'*',filters:{id}});
    const am=rows[0]; if(!am)return;
    const isAdmin=CU.role==='admin';
    const precisaAdmin=am.total_garrafas>LIMITE_GARRAFAS||am.valor_b2b_total>LIMITE_VALOR;
    let novoStatus='aprovado';
    // Se gerente aprovou e ainda precisa de admin
    if(!isAdmin&&precisaAdmin) novoStatus='aguarda_admin';
    await dbCall('update','pedidos_amostras',{data:{status:novoStatus,aprovado_por:CU.user,aprovado_em:new Date().toISOString(),updated_at:new Date().toISOString()},filters:{id}});
    // Se aprovado definitivamente, consumir estoque
    if(novoStatus==='aprovado'){
      await consumirEstoqueAmostras(am);
    }
    audit('editar',`Amostra ${novoStatus==='aprovado'?'aprovada':'encaminhada ao admin'}: ${am.cliente_nome}`,id);
    await renderAmostras(); atualizarBadgeAmostras();
    showToast(novoStatus==='aprovado'?'Aprovado!':'Encaminhado para administrador',true);
  }catch(e){showToast('Erro: '+e.message);}
}
function abrirRecusar(id){ amostraRecusandoId=id; document.getElementById('recusa-motivo').value=''; document.getElementById('modal-recusar-amostra').classList.add('open'); }
async function confirmarRecusa(){
  const motivo=document.getElementById('recusa-motivo').value.trim();
  if(!motivo){showToast('Informe o motivo');return;}
  try{
    await dbCall('update','pedidos_amostras',{data:{status:'recusado',recusado_por:CU.user,recusado_em:new Date().toISOString(),motivo_recusa:motivo,updated_at:new Date().toISOString()},filters:{id:amostraRecusandoId}});
    audit('excluir',`Amostra recusada: ${motivo}`,amostraRecusandoId);
    closeModal('modal-recusar-amostra'); await renderAmostras(); atualizarBadgeAmostras();
    showToast('Solicitação recusada',false);
  }catch(e){showToast('Erro: '+e.message);}
}
async function consumirEstoqueAmostras(am){
  const itens=JSON.parse(am.itens_snapshot||'[]');
  for(const it of itens){
    try{
      // Buscar estoque de amostras
      const rows=await dbCall('select','estoque_amostras',{select:'*',filters:{produto_nome:it.nome}});
      const est=rows[0];
      if(est){
        const novaQtd=Math.max(0,(est.quantidade_atual||0)-it.qty);
        await dbCall('update','estoque_amostras',{data:{quantidade_atual:novaQtd,updated_at:new Date().toISOString()},filters:{produto_nome:it.nome}});
        await dbCall('insert','estoque_movimentos',{data:{tabela:'amostras',produto_nome:it.nome,tipo:'saida',quantidade:it.qty,referencia:am.id,observacao:`Amostra aprovada: ${am.cliente_nome}`,usuario_login:CU.user}});
      }
    }catch(e){ console.warn('Falha ao consumir estoque amostra:', it.nome); }
  }
}

