// CONTROLE DE ESTOQUE
// ══════════════════════════════════════════════
let estoqueTabAtual='produtos';
function setEstoqueTab(tab,btn){
  estoqueTabAtual=tab;
  ['prod','amostras','mov'].forEach((t,i)=>{
    const b=document.getElementById('etab-'+t);
    const tabs=['produtos','amostras','movimentos'];
    if(b)b.className='ctog'+(tabs[i]===tab?' active-all':'');
  });
  renderEstoque();
}
async function initEstoque(){ setEstoqueTab('produtos',document.getElementById('etab-prod')); }
async function renderEstoque(){
  const div=document.getElementById('estoque-content');
  if(!div)return;
  div.innerHTML='<div style="padding:10px;color:var(--txt-mid);font-size:12px;">Carregando...</div>';
  try{
    if(estoqueTabAtual==='movimentos'){
      const rows=await dbCall('select','estoque_movimentos',{select:'*',order:'created_at.desc'});
      if(!rows.length){div.innerHTML='<div class="empty"><p>Nenhuma movimentação.</p></div>';return;}
      div.innerHTML=`<table style="width:100%;border-collapse:collapse;font-size:11px;">
        <thead><tr style="border-bottom:2px solid var(--stripe);">
          <th style="padding:7px 6px;text-align:left;">Data</th><th style="padding:7px 6px;">Estoque</th>
          <th style="padding:7px 6px;">Produto</th><th style="padding:7px 6px;">Tipo</th>
          <th style="padding:7px 6px;text-align:right;">Qtd</th><th style="padding:7px 6px;">Referência</th>
        </tr></thead>
        <tbody>${rows.map(r=>`<tr style="border-bottom:0.5px solid var(--stripe);">
          <td style="padding:6px;">${new Date(r.created_at).toLocaleDateString('pt-BR')}</td>
          <td style="padding:6px;"><span style="background:${r.tabela==='amostras'?'var(--gold-light)':'var(--cream)'};padding:2px 6px;border-radius:4px;font-size:10px;">${r.tabela}</span></td>
          <td style="padding:6px;">${r.produto_nome}</td>
          <td style="padding:6px;color:${r.tipo==='saida'?'var(--red)':'var(--green)'};">${r.tipo}</td>
          <td style="padding:6px;text-align:right;font-weight:bold;color:${r.tipo==='saida'?'var(--red)':'var(--green)'};">${r.tipo==='saida'?'-':'+'} ${r.quantidade}</td>
          <td style="padding:6px;font-size:10px;color:var(--txt-mid);">${r.referencia||''} ${r.observacao?'· '+r.observacao:''}</td>
        </tr>`).join('')}</tbody></table>`;
      return;
    }
    const tabela=estoqueTabAtual==='produtos'?'estoque_produtos':'estoque_amostras';
    // Usar CAT para listar todos os produtos
    const estMap={};
    try{
      const dbRows=await dbCall('select',tabela,{select:'*',order:'produto_nome.asc'});
      dbRows.forEach(r=>estMap[r.produto_nome]=r);
    }catch(e){}
    div.innerHTML=`<div style="display:flex;justify-content:flex-end;margin-bottom:10px;">
      <button class="bsm bsm-w" onclick="salvarEstoqueTodo('${tabela}')">💾 Salvar todos</button>
    </div>
    <table style="width:100%;border-collapse:collapse;font-size:11px;">
      <thead><tr style="border-bottom:2px solid var(--stripe);">
        <th style="padding:7px 6px;text-align:left;">Produto</th>
        <th style="padding:7px 6px;text-align:right;">Estoque Atual</th>
        <th style="padding:7px 6px;text-align:right;">Inicial</th>
        <th style="padding:7px 6px;">Última Revisão</th>
        <th style="padding:7px 6px;">Obs</th>
        <th style="padding:7px 6px;text-align:center;">Revisão</th>
      </tr></thead>
      <tbody>${CAT.filter(w=>w.ativo!==false).map(w=>{
        const est=estMap[w.nome]||{quantidade_atual:0,quantidade_inicial:0,ultima_revisao:'',obs:''};
        const id='est-'+w.nome.replace(/[^a-zA-Z0-9]/g,'');
        const baixo=est.quantidade_atual<=5;
        return `<tr style="border-bottom:0.5px solid var(--stripe);${baixo?'background:#fff5f5;':''}">
          <td style="padding:7px 6px;"><strong>${w.nome}</strong><br><span style="font-size:10px;color:var(--txt-mid);">${w.marca}</span></td>
          <td style="padding:7px 6px;text-align:right;"><span style="font-size:16px;font-weight:bold;color:${baixo?'var(--red)':'var(--wine)'};">${est.quantidade_atual}</span>${baixo?' ⚠️':''}</td>
          <td style="padding:7px 6px;text-align:right;color:var(--txt-mid);">${est.quantidade_inicial}</td>
          <td style="padding:7px 6px;font-size:10px;color:var(--txt-mid);">${est.ultima_revisao?new Date(est.ultima_revisao+'T12:00:00').toLocaleDateString('pt-BR'):'—'}</td>
          <td style="padding:7px 6px;"><input class="fi" id="${id}-obs" value="${est.obs||''}" style="font-size:10px;padding:3px 5px;width:120px;" placeholder="Obs..."></td>
          <td style="padding:7px 6px;text-align:center;">
            <input type="number" id="${id}-rev" min="0" value="${est.quantidade_atual}" style="width:65px;font-size:11px;padding:4px 5px;border:1.5px solid var(--stripe);border-radius:5px;text-align:center;">
            <button class="bsm bsm-w" style="margin-top:3px;" onclick="revisarEstoque('${tabela}','${w.nome}','${id}')">✓</button>
          </td>
        </tr>`;
      }).join('')}</tbody>
    </table>`;
  }catch(e){div.innerHTML=`<div style="color:var(--red);padding:10px;">Erro: ${e.message}</div>`;}
}

async function revisarEstoque(tabela,produtoNome,elId){
  const novaQtd=parseInt(document.getElementById(elId+'-rev').value)||0;
  const obs=document.getElementById(elId+'-obs').value.trim();
  try{
    await dbCall('upsert',tabela,{data:{produto_nome:produtoNome,quantidade_atual:novaQtd,quantidade_inicial:novaQtd,ultima_revisao:new Date().toISOString().slice(0,10),obs,updated_at:new Date().toISOString()},onConflict:'produto_nome'});
    await dbCall('insert','estoque_movimentos',{data:{tabela:tabela==='estoque_amostras'?'amostras':'produtos',produto_nome:produtoNome,tipo:'revisao',quantidade:novaQtd,observacao:'Revisão manual',usuario_login:CU.user}});
    showToast('Revisão salva!',true);
    await renderEstoque();
  }catch(e){showToast('Erro: '+e.message);}
}

// Consumir estoque de PRODUTOS quando pedido vai ao Bling
async function consumirEstoqueProdutos(pedido){
  if(!pedido?.items?.length)return;
  for(const it of pedido.items){
    try{
      const rows=await dbCall('select','estoque_produtos',{select:'*',filters:{produto_nome:it.nome}});
      const est=rows[0];
      if(est){
        const novaQtd=Math.max(0,(est.quantidade_atual||0)-it.qty);
        await dbCall('update','estoque_produtos',{data:{quantidade_atual:novaQtd,updated_at:new Date().toISOString()},filters:{produto_nome:it.nome}});
        await dbCall('insert','estoque_movimentos',{data:{tabela:'produtos',produto_nome:it.nome,tipo:'saida',quantidade:it.qty,referencia:pedido.id,observacao:`Pedido Bling: ${pedido.cliente?.razao||''}`,usuario_login:pedido.vendedor}});
      }
    }catch(e){ console.warn('Falha ao consumir estoque produto:', it.nome); }
  }
}

