// Canal selecionado no dashboard
let dashCanal = '';
let volCanal  = '';
let comCanal  = '';

function setVolCanal(c,btn){
  volCanal=c;
  document.querySelectorAll('#dash-vol .ctog').forEach(b=>b.className='ctog');
  if(btn)btn.className='ctog '+(c===''?'active-all':c==='b2b'?'active-b2b':'active-b2c');
  renderDashVol();
}
function setComCanal(c,btn){
  comCanal=c;
  document.querySelectorAll('#dash-com .ctog').forEach(b=>b.className='ctog');
  if(btn)btn.className='ctog '+(c===''?'active-all':c==='b2b'?'active-b2b':'active-b2c');
  renderDashCom();
}

function initVolSelects(){
  const ano=new Date().getFullYear(); const mes=new Date().getMonth()+1;
  const selA=document.getElementById('vol-ano');
  if(selA&&!selA.innerHTML) selA.innerHTML=[ano-1,ano,ano+1].map(a=>`<option value="${a}" ${a===ano?'selected':''}>${a}</option>`).join('');
  const selM=document.getElementById('vol-mes');
  if(selM&&!selM.innerHTML) selM.innerHTML='<option value="0">Todo o ano</option>'+MESES.map((m,i)=>`<option value="${i+1}" ${i+1===mes?'selected':''}>${m}</option>`).join('');
  const selV=document.getElementById('vol-fv');
  if(selV){
    const equipeGer=CU.role==='gerente'||CU.role==='coordenador'
      ? new Set([CU.user,...usersCache.filter(u=>u.reportaPara===CU.user).map(u=>u.user)]) : null;
    selV.innerHTML='<option value="">'+( equipeGer?'Toda a equipe':'Todos os vendedores')+'</option>';
    usersCache.filter(u=>u.ativo&&u.role!=='admin'&&(!equipeGer||equipeGer.has(u.user)))
      .forEach(u=>{selV.innerHTML+=`<option value="${u.user}">${u.name}</option>`;});
  }
}
function initComSelects(){
  const ano=new Date().getFullYear(); const mes=new Date().getMonth()+1;
  const selA=document.getElementById('com-ano');
  if(selA&&!selA.innerHTML) selA.innerHTML=[ano-1,ano,ano+1].map(a=>`<option value="${a}" ${a===ano?'selected':''}>${a}</option>`).join('');
  const selM=document.getElementById('com-mes');
  if(selM&&!selM.innerHTML) selM.innerHTML=MESES.map((m,i)=>`<option value="${i+1}" ${i+1===mes?'selected':''}>${m}</option>`).join('');
  const selV=document.getElementById('com-fv');
  if(selV){
    const equipeGer=CU.role==='gerente'||CU.role==='coordenador'
      ? new Set([CU.user,...usersCache.filter(u=>u.reportaPara===CU.user).map(u=>u.user)]) : null;
    selV.innerHTML='<option value="">Todos</option>';
    usersCache.filter(u=>u.ativo&&u.role!=='admin'&&(!equipeGer||equipeGer.has(u.user)))
      .forEach(u=>{selV.innerHTML+=`<option value="${u.user}">${u.name}</option>`;});
  }
  // Mostrar filtro de pessoa para admin/gerente
  const comVF=document.getElementById('com-vf');
  if(comVF&&(CU.role==='admin'||CU.role==='gerente'||CU.role==='coordenador')) comVF.style.display='block';
}
function initVolVF(){
  const volVF=document.getElementById('vol-vf');
  if(volVF&&(CU.role==='admin'||CU.role==='gerente'||CU.role==='coordenador')) volVF.style.display='block';
}

// ══════════════════════════════════════════════
// DASHBOARD 2 — VOLUMES E BONIFICAÇÕES
// ══════════════════════════════════════════════
async function renderDashVol(){
  initVolSelects(); initVolVF();
  const ano=parseInt(document.getElementById('vol-ano')?.value||new Date().getFullYear());
  const mes=parseInt(document.getElementById('vol-mes')?.value||0);
  const bonifFilt=document.getElementById('vol-bonif')?.value||'';
  const vdF=document.getElementById('vol-fv')?.value||'';
  // Equipe visível
  const isAdmin=CU.role==='admin';
  const isGerente=CU.role==='gerente'||CU.role==='coordenador';
  const equipe=isGerente?new Set([CU.user,...usersCache.filter(u=>u.reportaPara===CU.user).map(u=>u.user)]):null;

  let pedidos=S.pedidos().filter(p=>{
    // Incluir pedidos enviados ao Bling OU fechados
    if(p.deletedAt)return false;
    if(!p.blingId && p.status!=='fechado')return false;
    const d=new Date((p.faturamento?.data||p.data||'')+'T12:00:00');
    if(isNaN(d))return false;
    if(d.getFullYear()!==ano)return false;
    if(mes>0&&d.getMonth()+1!==mes)return false;
    if(volCanal&&p.cType!==volCanal)return false;
    if(vdF&&p.vendedor!==vdF)return false;
    if(isGerente&&equipe&&!equipe.has(p.vendedor))return false;
    if(!isAdmin&&!isGerente&&p.vendedor!==CU.user)return false;
    return true;
  });

  // Buscar aprovados
  let aprovados=[]; try{ aprovados=await dbCall('select','bonificacao_config',{select:'*'}); }catch(e){}
  const aprovMap={};aprovados.forEach(a=>aprovMap[a.cnpj]=a);

  // Agrupar por CNPJ/CPF
  const map={};
  pedidos.forEach(p=>{
    const doc=p.cliente?.cnpj||p.cliente?.cpf||'SEM DOC';
    if(!map[doc]) map[doc]={razao:p.cliente?.razao||'?',cnpj:p.cliente?.cnpj||'',cpf:p.cliente?.cpf||'',garrafas:0,valor:0,pedidos:0,menorPreco:Infinity};
    const g=p.items?.reduce((s,it)=>s+(it.qty||0),0)||0;
    map[doc].garrafas+=g;
    map[doc].valor+=(p.total||0);
    map[doc].pedidos++;
    p.items?.forEach(it=>{
      const cat=CAT.find(c=>c.nome===it.nome);
      const pb2b=cat?cat.b2b:it.price;
      if(pb2b<map[doc].menorPreco) map[doc].menorPreco=pb2b;
    });
  });

  // Filtrar por bonif
  let entries=Object.entries(map);
  if(bonifFilt==='aprovados') entries=entries.filter(([doc,d])=>aprovMap[d.cnpj]);
  else if(bonifFilt==='nao') entries=entries.filter(([doc,d])=>!aprovMap[d.cnpj]);
  entries.sort(([,a],[,b])=>b.garrafas-a.garrafas);

  // Cards
  const totalGarrafas=entries.reduce((s,[,d])=>s+d.garrafas,0);
  const totalCredito=entries.filter(([,d])=>aprovMap[d.cnpj]).reduce((s,[,d])=>s+calcBonificacao(d.garrafas,d.valor,d.pedidos).credito,0);
  document.getElementById('vol-grid').innerHTML=`
    <div class="dc"><span class="dc-n">${totalGarrafas}</span><div class="dc-l">GARRAFAS NO PERÍODO</div></div>
    <div class="dc"><span class="dc-n">${Object.values(aprovMap).length}</span><div class="dc-l">CNPJs APROVADOS</div></div>
    <div class="dc wine"><span class="dc-n">${fmtBRL(totalCredito)}</span><div class="dc-l">CRÉDITO TOTAL GERADO</div></div>
  `;

  // Tabela de estabelecimentos
  if(!entries.length){
    document.getElementById('vol-estab-list').innerHTML='<div class="empty"><p>Nenhum pedido enviado ao Bling no período.</p></div>';
    return;
  }
  document.getElementById('vol-estab-list').innerHTML=`
    <table style="width:100%;border-collapse:collapse;font-size:11px;">
      <thead><tr style="border-bottom:2px solid var(--stripe);">
        <th style="padding:7px 6px;text-align:left;">Estabelecimento</th>
        <th style="padding:7px 6px;text-align:center;">Pedidos</th>
        <th style="padding:7px 6px;text-align:center;">Garrafas</th>
        <th style="padding:7px 6px;">Valor</th>
        <th style="padding:7px 6px;text-align:center;">Step</th>
        <th style="padding:7px 6px;">Garr. Bônus</th>
        <th style="padding:7px 6px;">Crédito</th>
        <th style="padding:7px 6px;">Entrega</th>
      </tr></thead>
      <tbody>${entries.map(([doc,d])=>{
        const aprov=aprovMap[d.cnpj];
        const {step,garrafasBonus,credito}=calcBonificacao(d.garrafas,d.valor,d.pedidos);
        const mesEntrega=mes>0?MESES[(mes%12)]+' '+(mes===12?ano+1:ano):'mês seguinte';
        return `<tr style="border-bottom:0.5px solid var(--stripe);">
          <td style="padding:7px 6px;"><strong>${d.razao}</strong><br><span style="font-size:10px;color:var(--txt-mid);">${d.cnpj||d.cpf}</span>${aprov?'<span style="margin-left:5px;background:var(--green);color:white;font-size:9px;padding:1px 5px;border-radius:3px;">✓ Bonif.</span>':''}</td>
          <td style="padding:7px 6px;text-align:center;">${d.pedidos}</td>
          <td style="padding:7px 6px;text-align:center;font-weight:bold;">${d.garrafas}</td>
          <td style="padding:7px 6px;">${fmtBRL(d.valor)}</td>
          <td style="padding:7px 6px;text-align:center;">${aprov&&step>=0?'<span style="background:var(--wine);color:var(--gold);padding:2px 7px;border-radius:4px;font-size:10px;">Step '+step+'</span>':'<span style="color:var(--txt-mid);">'+(d.garrafas<60?'&lt;60 gar.':'—')+'</span>'}</td>
          <td style="padding:7px 6px;color:var(--green);font-weight:bold;">${aprov&&step>=0?garrafasBonus+' 🍷':'—'}</td>
          <td style="padding:7px 6px;font-weight:bold;color:var(--green);">${aprov&&step>=0?fmtBRL(credito):'—'}</td>
          <td style="padding:7px 6px;font-size:10px;color:var(--txt-mid);">${aprov&&step>=0?'1º ped. '+mesEntrega:'—'}</td>
        </tr>`;
      }).join('')}</tbody>
    </table>`;
}

// ══════════════════════════════════════════════
// DASHBOARD 3 — COMISSÕES
// ══════════════════════════════════════════════
async function renderDashCom(){
  initComSelects();
  const ano=parseInt(document.getElementById('com-ano')?.value||new Date().getFullYear());
  const mes=parseInt(document.getElementById('com-mes')?.value||new Date().getMonth()+1);
  const tipoMes=document.getElementById('com-tipo-mes')?.value||'faturamento';
  const statusFilt=document.getElementById('com-status')?.value||'';
  const pessoaFilt=document.getElementById('com-fv')?.value||'';

  const isAdmin=CU.role==='admin';
  const isGerente=CU.role==='gerente'||CU.role==='coordenador';
  const equipe=isGerente?new Set([CU.user,...usersCache.filter(u=>u.reportaPara===CU.user).map(u=>u.user)]):null;

  let rows=[]; let regras=[]; let cascatas=[];
  try{
    [rows,regras,cascatas]=await Promise.all([
      dbCall('select','comissoes',{select:'*',order:'data_venda.desc'}),
      dbCall('select','regras_comissao',{select:'*'}),
      dbCall('select','regras_comissao_cascata',{select:'*'})
    ]);
  }catch(e){}

  // Filtrar por mês/ano — faturamento (data_venda) ou pagamento (data_vencimento)
  let filtradas=rows.filter(r=>{
    const campo=tipoMes==='pagamento'?(r.data_vencimento||''):(r.data_venda||'');
    const yr=parseInt(campo.slice(0,4));const mo=parseInt(campo.slice(5,7));
    if(yr!==ano||mo!==mes)return false;
    if(comCanal&&r.cliente_tipo!==comCanal)return false;
    if(statusFilt&&r.status!==statusFilt)return false;
    if(!isAdmin&&!isGerente&&r.beneficiario!==CU.user)return false;
    if(isGerente&&equipe&&!equipe.has(r.beneficiario))return false;
    if(pessoaFilt&&r.beneficiario!==pessoaFilt)return false;
    return true;
  });

  // Totais
  const totalGeral=filtradas.reduce((s,r)=>s+(parseFloat(r.valor_comissao)||0),0);
  const b2cRows=filtradas.filter(r=>r.cliente_tipo==='b2c');
  const b2bRows=filtradas.filter(r=>r.cliente_tipo==='b2b');
  const totalB2C=b2cRows.reduce((s,r)=>s+(parseFloat(r.valor_comissao)||0),0);
  const totalB2B=b2bRows.reduce((s,r)=>s+(parseFloat(r.valor_comissao)||0),0);
  const dataVencB2C=new Date(ano,mes,5).toLocaleDateString('pt-BR');
  const dataVencB2B=new Date(ano,mes+1,5).toLocaleDateString('pt-BR');

  document.getElementById('com-grid-totais').innerHTML=`
    <div class="dc wine"><span class="dc-n">${fmtBRL(totalGeral)}</span><div class="dc-l">TOTAL A PAGAR — ${MESES[mes-1].toUpperCase()}</div></div>
    <div class="dc"><span class="dc-n" style="color:var(--green);">${fmtBRL(totalB2C)}</span><div class="dc-l">B2C · Vence ${dataVencB2C}</div></div>
    <div class="dc"><span class="dc-n" style="color:var(--bling);">${fmtBRL(totalB2B)}</span><div class="dc-l">B2B · Vence ${dataVencB2B}</div></div>
  `;

  if(!filtradas.length){
    document.getElementById('com-corpo').innerHTML='<div class="empty"><p>Nenhuma comissão registrada no período. Pedidos precisam ser enviados ao Bling para gerar comissões.</p></div>';
    return;
  }

  // Agrupar por beneficiário
  const byUser={};
  filtradas.forEach(r=>{
    const u=r.beneficiario;
    if(!byUser[u]) byUser[u]={nome:usersCache.find(x=>x.user===u)?.name||u,propria:0,cascata:0,b2b:0,b2c:0,linhas:[]};
    const vlr=parseFloat(r.valor_comissao)||0;
    if(r.tipo_comissao==='propria') byUser[u].propria+=vlr;
    else byUser[u].cascata+=vlr;
    if(r.cliente_tipo==='b2b') byUser[u].b2b+=vlr;
    else byUser[u].b2c+=vlr;
    byUser[u].linhas.push(r);
  });

  document.getElementById('com-corpo').innerHTML=`
    <div class="dash-sec-title">Por beneficiário</div>
    <table style="width:100%;border-collapse:collapse;font-size:11px;">
      <thead><tr style="border-bottom:2px solid var(--stripe);">
        <th style="padding:7px 6px;text-align:left;">Pessoa</th>
        <th style="padding:7px 6px;">Comissão própria</th>
        <th style="padding:7px 6px;">Cascata</th>
        <th style="padding:7px 6px;">B2B</th>
        <th style="padding:7px 6px;">B2C</th>
        <th style="padding:7px 6px;font-weight:bold;">Total</th>
        <th style="padding:7px 6px;">Status</th>
      </tr></thead>
      <tbody>${Object.values(byUser).sort((a,b)=>(b.propria+b.cascata)-(a.propria+a.cascata)).map(u=>`
        <tr style="border-bottom:0.5px solid var(--stripe);">
          <td style="padding:7px 6px;font-weight:bold;">${u.nome}</td>
          <td style="padding:7px 6px;">${u.propria>0?fmtBRL(u.propria):'—'}</td>
          <td style="padding:7px 6px;">${u.cascata>0?fmtBRL(u.cascata):'—'}</td>
          <td style="padding:7px 6px;">${u.b2b>0?fmtBRL(u.b2b):'—'}</td>
          <td style="padding:7px 6px;">${u.b2c>0?fmtBRL(u.b2c):'—'}</td>
          <td style="padding:7px 6px;font-weight:bold;color:var(--wine);">${fmtBRL(u.propria+u.cascata)}</td>
          <td style="padding:7px 6px;">${u.linhas.every(r=>r.status==='pago')?'<span style="color:var(--green);font-size:10px;">✅ Pago</span>':'<span style="color:var(--gold);font-size:10px;">⏳ Pendente</span>'}</td>
        </tr>`).join('')}
      </tbody>
    </table>
    <div class="dash-sec-title" style="margin-top:18px;">Calendário de pagamentos</div>
    <div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(220px,1fr));gap:12px;">
      <div style="background:var(--cream);border-radius:10px;padding:14px;border-left:4px solid var(--green);">
        <div style="font-size:12px;font-weight:bold;color:var(--txt-sec);margin-bottom:4px;">B2C — ${dataVencB2C}</div>
        <div style="font-size:20px;font-weight:bold;color:var(--wine);">${fmtBRL(totalB2C)}</div>
        <div style="font-size:10px;color:var(--txt-mid);margin-top:4px;">Vendas de ${MESES[mes-1]} · B2C</div>
      </div>
      <div style="background:var(--cream);border-radius:10px;padding:14px;border-left:4px solid var(--bling);">
        <div style="font-size:12px;font-weight:bold;color:var(--txt-sec);margin-bottom:4px;">B2B — ${dataVencB2B}</div>
        <div style="font-size:20px;font-weight:bold;color:var(--wine);">${fmtBRL(totalB2B)}</div>
        <div style="font-size:10px;color:var(--txt-mid);margin-top:4px;">Vendas de ${MESES[mes-1]} · B2B</div>
      </div>
    </div>`;
}

