// LISTA DE PREÇOS
// ══════════════════════════════════════════════
// LISTA DE PREÇOS — via Supabase (tabela precos)
// ══════════════════════════════════════════════
const precosDB={};

async function renderPrecos(){
  const tbody=document.getElementById('precos-body');
  tbody.innerHTML='<tr><td colspan="7" style="padding:12px;color:var(--txt-mid);text-align:center;font-size:12px;">Carregando preços...</td></tr>';
  // Carregar preços do Supabase
  try{
    const rows=await dbCall('select','precos',{select:'*'});
    rows.forEach(r=>{ precosDB[r.nome]=r; });
  }catch(e){}
  // Carregar códigos Bling do rotulos_depara
  try{
    const rows=await dbCall('select','rotulos_depara',{select:'*'});
    rows.forEach(r=>{
      if(!precosDB[r.rotulo_html]) precosDB[r.rotulo_html]={};
      precosDB[r.rotulo_html].codigo_bling=r.codigo_bling;
    });
  }catch(e){}
  tbody.innerHTML=CAT.map((w,i)=>{
    const rid='pr'+i;
    const db=precosDB[w.nome]||{};
    const b2b=db.preco_b2b??w.b2b;
    const b2c=db.preco_b2c??w.b2c;
    const cod=db.codigo_bling||'';
    // Atualizar CAT em memória com valores do banco
    CAT[i].b2b=b2b; CAT[i].b2c=b2c;
    return `<tr style="border-bottom:0.5px solid var(--stripe);" id="pr-row-${i}">
      <td style="padding:7px 6px;"><strong>${w.nome}</strong><br><span style="font-size:10px;color:var(--txt-mid);">${w.marca} · ${w.orig}</span></td>
      <td style="padding:7px 6px;font-size:11px;color:var(--txt-mid);">${w.safra}</td>
      <td style="padding:7px 6px;font-size:11px;color:var(--txt-mid);">CX 6 un.</td>
      <td style="padding:7px 6px;"><input class="fi" id="${rid}-cod" value="${cod}" placeholder="Cód. Bling" style="width:90px;font-size:11px;padding:4px 6px;"></td>
      <td style="padding:7px 6px;text-align:right;"><input class="fi" id="${rid}-b2b" type="number" value="${b2b}" min="0" step="0.01" style="width:80px;font-size:11px;padding:4px 6px;text-align:right;"></td>
      <td style="padding:7px 6px;text-align:right;"><input class="fi" id="${rid}-b2c" type="number" value="${b2c}" min="0" step="0.01" style="width:80px;font-size:11px;padding:4px 6px;text-align:right;"></td>
      <td style="padding:7px 6px;text-align:center;"><button class="bsm bsm-w" onclick="savePrecoLinha(${i},'${rid}')">💾</button></td>
    </tr>`;
  }).join('');
  document.getElementById('precos-sync-status').textContent='';
}

async function savePrecoLinha(idx,rid){
  const w=CAT[idx];
  const b2b=parseFloat(document.getElementById(rid+'-b2b').value)||w.b2b;
  const b2c=parseFloat(document.getElementById(rid+'-b2c').value)||w.b2c;
  const cod=document.getElementById(rid+'-cod').value.trim();
  CAT[idx].b2b=b2b; CAT[idx].b2c=b2c;
  precosDB[w.nome]={...(precosDB[w.nome]||{}),preco_b2b:b2b,preco_b2c:b2c,codigo_bling:cod};
  try{
    await dbCall('upsert','precos',{
      data:{nome:w.nome,marca:w.marca,safra:w.safra,orig:w.orig,preco_b2b:b2b,preco_b2c:b2c,embalagem:'CX 6 un.',updated_at:new Date().toISOString()},
      onConflict:'nome'
    });
    await dbCall('upsert','rotulos_depara',{
      data:{rotulo_html:w.nome,codigo_bling:cod||null,nome_bling:w.nome,updated_at:new Date().toISOString()},
      onConflict:'rotulo_html'
    });
    showToast('Preço salvo!',true);
    const row=document.getElementById('pr-row-'+idx);
    if(row){row.style.background='var(--bg-success)';setTimeout(()=>{row.style.background='';},1500);}
  }catch(e){showToast('Erro ao salvar: '+e.message);}
}

async function syncBlingPrecos(canal){
  if(!VERCEL_URL){showToast('VERCEL_URL não configurado');return;}
  const btn=event?.target;if(btn){btn.disabled=true;btn.textContent='Sincronizando...';}
  const status=document.getElementById('precos-sync-status');
  status.textContent='Sincronizando '+canal.toUpperCase()+'...';
  let ok=0,fail=0,skip=0;
  const erros=[];
  for(let i=0;i<CAT.length;i++){
    const w=CAT[i];
    const cod=(precosDB[w.nome]?.codigo_bling||'').trim()||document.getElementById('pr'+i+'-cod')?.value?.trim();
    if(!cod){skip++;continue;}
    const preco=canal==='b2b'?w.b2b:w.b2c;
    try{
      const resp=await fetch(VERCEL_URL+'/api/bling-precos',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({codigoProduto:cod,canal,preco})});
      const data=await resp.json();
      if(resp.ok) ok++;
      else{ fail++; erros.push(`${w.nome}: ${data?.error?.message||data?.error||resp.status}`); }
    }catch(e){fail++;erros.push(`${w.nome}: ${e.message}`);}
    await new Promise(r=>setTimeout(r,300));
  }
  let msg=`Sync ${canal.toUpperCase()}: ${ok} atualizados`;
  if(skip>0) msg+=`, ${skip} sem código`;
  if(fail>0) msg+=`, ${fail} falha(s)`;
  msg+=` · ${new Date().toLocaleTimeString('pt-BR')}`;
  if(erros.length) msg+='\n⚠️ Erros:\n'+erros.join('\n');
  status.style.whiteSpace='pre-wrap';
  status.textContent=msg;
  if(btn){btn.disabled=false;btn.textContent=`🔗 Sync ${canal.toUpperCase()}`;}
  showToast(`Sync ${canal.toUpperCase()}: ${ok} ok${fail>0?', '+fail+' falhas':''}`,ok>0);
}
function gerarPdfPrecos(canal){
  const {jsPDF}=window.jspdf||{};
  if(!jsPDF){showToast('Biblioteca de PDF não carregada. Aguarde e tente novamente.');return;}
  // Perguntar nome do arquivo
  const mesAtualStr=MESES[new Date().getMonth()]+new Date().getFullYear();
  const sugestao=`WG_Tabela_${canal.toUpperCase()}_${mesAtualStr}.pdf`;
  const nomeArq=prompt('Nome do arquivo PDF:',sugestao);
  if(!nomeArq)return; // cancelado
  const doc=new jsPDF({orientation:'portrait',unit:'mm',format:'a4'});
  const W=210;const WINE=[107,26,44];const GOLD=[181,146,76];const CREAM=[253,248,242];
  const mesAtual=MESES[new Date().getMonth()].toUpperCase()+' '+new Date().getFullYear();
  const tituloTabela=canal==='b2b'?'TABELA B2B':'TABELA B2C';
  const tituloPrincipal=canal==='b2b'?'Lista de Preços para Revenda':'Lista de Preços ao Consumidor';

  // Paginação inteligente — respeitando altura disponível
  // Cabeçalho: 50mm, Rodapé barra: 12mm, Rodapé conteúdo última pág: 28mm, margem: 5mm
  const Y_START=60; // onde começam os produtos
  const Y_LIMIT_NORMAL=252; // limite para páginas normais
  const Y_LIMIT_LAST=222;   // limite última página (espaço para condições)
  // Pre-calcular paginação
  const paginas=[];let pag=[];let y=Y_START;let marcaAtual='';
  for(let i=0;i<CAT.length;i++){
    const w=CAT[i];
    const isUltimaPag=false; // recalculado depois
    const altMarca=w.marca!==marcaAtual?7:0;
    const altProd=7;
    const limite=Y_LIMIT_NORMAL; // usaremos depois para a última
    if(y+altMarca+altProd>limite&&pag.length>0){
      paginas.push(pag);pag=[];y=Y_START;marcaAtual='';
    }
    pag.push(w);
    if(w.marca!==marcaAtual){marcaAtual=w.marca;y+=altMarca;}
    y+=altProd;
  }
  if(pag.length)paginas.push(pag);
  const totalPgs=paginas.length;

  function renderPagina(doc,produtosPagina,pgNum){
    const W=210;
    const WINE=[107,26,44]; const GOLD=[181,146,76]; const CREAM=[248,242,236];

    // ── BADGE — topo direito, completamente isolado (y=0 a y=11)
    doc.setFillColor(...WINE);
    doc.rect(152, 0, 58, 11, 'F');
    doc.setTextColor(...GOLD);
    doc.setFontSize(8); doc.setFont('helvetica','bold');
    doc.text(tituloTabela, 181, 7.5, {align:'center'});

    // ── LOGO — topo esquerdo (y=4 a y=30)
    try{
      doc.addImage(LOGO, 'JPEG', 5, 4, 38, 24);
    }catch(e){
      doc.setTextColor(...WINE);
      doc.setFontSize(12); doc.setFont('helvetica','bold');
      doc.text("Wine's Gallery", 7, 18);
    }

    // ── TÍTULO — centralizado, bem abaixo do badge (y=24)
    // Com fonte 18pt o texto tem ~5mm de altura; y=24 → topo ≈ y=19 → sem overlap com badge (y=0-11)
    doc.setTextColor(50, 18, 25);
    doc.setFontSize(18); doc.setFont('helvetica','bold');
    doc.text(tituloPrincipal, W/2, 22, {align:'center'});

    // ── LINHA SEPARADORA (y=25)
    doc.setDrawColor(...WINE); doc.setLineWidth(0.35);
    doc.line(48, 25, W-48, 25);

    // ── SUBTÍTULO (y=30)
    doc.setFontSize(8.5); doc.setFont('helvetica','normal');
    doc.setTextColor(...GOLD);
    doc.text('Importadora de Vinhos Boutique e de Rótulos Exclusivos', W/2, 30, {align:'center'});

    // ── BARRA DE PÁGINA (y=34 a y=42)
    doc.setFillColor(...WINE);
    doc.rect(0, 34, W, 8, 'F');
    doc.setTextColor(...GOLD); doc.setFontSize(8); doc.setFont('helvetica','normal');
    doc.text(`Página ${pgNum} de ${totalPgs}`, 7, 39.5);
    doc.text(mesAtual, W/2, 39.5, {align:'center'});

    // ── CABEÇALHO DA TABELA (y=45 a y=52)
    let y = 50;
    doc.setFillColor(...CREAM); doc.rect(5, y-6, W-10, 7, 'F');
    doc.setTextColor(...WINE); doc.setFontSize(7.5); doc.setFont('helvetica','bold');
    doc.text('RÓTULO', 8, y);
    doc.text('SAFRA', 120, y);
    doc.text('EMBALAGEM', 148, y);
    doc.text('PREÇO / UN', W-8, y, {align:'right'});
    doc.setDrawColor(...WINE); doc.setLineWidth(0.5);
    doc.line(5, y+2, W-5, y+2);
    y += 8;

    // ── PRODUTOS
    let mAtual = '';
    for(const w of produtosPagina){
      if(w.marca !== mAtual){
        mAtual = w.marca;
        doc.setFontSize(10); doc.setFont('helvetica','bold'); doc.setTextColor(30,10,10);
        doc.text(w.marca.toUpperCase(), 10, y);
        doc.setFontSize(7.5); doc.setFont('helvetica','normal'); doc.setTextColor(160,130,110);
        doc.text(w.orig, W-8, y, {align:'right'});
        y += 7;
      }
      const preco = canal==='b2b' ? w.b2b : w.b2c;
      doc.setFontSize(9); doc.setFont('helvetica','normal'); doc.setTextColor(40,20,20);
      doc.text(w.nome, 10, y);
      doc.setTextColor(160,140,120);
      doc.text(String(w.safra), 120, y);
      doc.text('CX 6 un.', 148, y);
      doc.setTextColor(40,20,20); doc.setFont('helvetica','bold');
      doc.text(`R$ ${preco}`, W-8, y, {align:'right'});
      doc.setDrawColor(225,215,205); doc.setLineWidth(0.1);
      doc.line(5, y+2.5, W-5, y+2.5);
      y += 7;
    }

    // ── NOTA DE PREÇOS — posicionada acima das condições
    const notaY = pgNum===totalPgs ? 218 : 253;
    doc.setDrawColor(200,185,170); doc.setLineWidth(0.2);
    doc.line(6, notaY-2, W-6, notaY-2);
    doc.setFontSize(7); doc.setFont('helvetica','italic'); doc.setTextColor(150,130,110);
    doc.text('* Preços unitários com impostos inclusos  ·  Embalagem mínima: caixa com 6 unidades', 8, notaY+3);

    // ── CONDIÇÕES COMERCIAIS — só na última página
    if(pgNum===totalPgs){
      const cY = 228;
      doc.setFontSize(7.5); doc.setFont('helvetica','bold'); doc.setTextColor(...WINE);
      doc.text('CONDIÇÕES COMERCIAIS', 8, cY);
      doc.setFont('helvetica','normal'); doc.setTextColor(40,20,20);
      // Coluna esquerda
      doc.setFont('helvetica','bold'); doc.text('Pedido mínimo', 8, cY+8);
      doc.setFont('helvetica','normal'); doc.text('R$ 1.500  ·  mínimo 3 SKUs diferentes', 42, cY+8);
      doc.setFont('helvetica','bold'); doc.text('Frete', 8, cY+14);
      doc.setFont('helvetica','normal'); doc.text('Incluso para São Paulo Capital nas condições acima', 42, cY+14);
      // Coluna direita
      doc.setFont('helvetica','bold'); doc.text('Pagamento', 112, cY+8);
      doc.setFont('helvetica','normal'); doc.text('PIX, transferência bancária ou boleto', 135, cY+8);
      doc.setFont('helvetica','bold'); doc.text('Boleto', 112, cY+14);
      doc.setFont('helvetica','normal'); doc.text('14 ou 28 dias', 135, cY+14);
    }

    // ── BARRA RODAPÉ (y=272 até fim da página)
    doc.setFillColor(...WINE); doc.rect(0, 272, W, 25, 'F');
    doc.setTextColor(210,190,165); doc.setFontSize(8.5); doc.setFont('helvetica','normal');
    doc.text('(11) 95540-0902', 52, 285, {align:'center'});
    doc.text('@wine_gallery',    W/2, 285, {align:'center'});
    doc.text('winesgallery.com.br', 158, 285, {align:'center'});
  }
  for(let pg=0;pg<paginas.length;pg++){
    if(pg>0)doc.addPage();
    renderPagina(doc,paginas[pg],pg+1);
  }
  doc.save(nomeArq.endsWith('.pdf')?nomeArq:nomeArq+'.pdf');
  showToast(`PDF gerado: ${nomeArq}`,true);
}
function setDashCanal(c){
  dashCanal=c;
  ['all','b2b','b2c'].forEach(x=>document.getElementById('ctog-'+x).className='ctog');
  if(c==='')document.getElementById('ctog-all').className='ctog active-all';
  else if(c==='b2b')document.getElementById('ctog-b2b').className='ctog active-b2b';
  else document.getElementById('ctog-b2c').className='ctog active-b2c';
  renderDash();
}
async function renderDash(){
  const isAdmin=CU.role==='admin';
  const isGerente=CU.role==='gerente'||CU.role==='coordenador';
  const isAG=isAdmin||isGerente;
  const canal=dashCanal;
  const canalLabel=canal==='b2b'?' · B2B':canal==='b2c'?' · B2C':'';
  // Filtro de status
  const statusFilt=document.getElementById('dash-fstatus')?.value||'';
  // Filtro de vendedor (só admin usa)
  const vdF=isAdmin?(document.getElementById('dash-fv')?.value||''):'';
  // Popular select de vendedor (só admin)
  if(isAdmin){
    const sel=document.getElementById('dash-fv');const cur=sel?.value;
    if(sel){
      sel.innerHTML='<option value="">Todos os vendedores</option>';
      usersCache.forEach(u=>{sel.innerHTML+=`<option value="${u.user}">${u.name}</option>`;});
      sel.value=cur;
    }
  }
  // Definir título
  document.getElementById('dash-title').textContent=isAdmin?'Painel Geral':isGerente?'Painel da Equipe':'Meu Painel';
  document.getElementById('dash-sub').textContent=(isAdmin?'Visão consolidada de todos os vendedores':isGerente?'Você e sua equipe':'Resumo dos seus pedidos')+canalLabel;
  // Determinar equipe visível
  let equipe=null;
  if(isGerente){
    equipe=new Set([CU.user,...usersCache.filter(u=>u.reportaPara===CU.user).map(u=>u.user)]);
  }
  let mp=S.pedidos().filter(p=>!p.deletedAt);
  if(isAdmin){
    if(vdF) mp=mp.filter(p=>p.vendedor===vdF);
  } else if(isGerente){
    mp=mp.filter(p=>equipe.has(p.vendedor));
  } else {
    mp=mp.filter(p=>p.vendedor===CU.user);
  }
  if(canal) mp=mp.filter(p=>p.cType===canal);
  if(statusFilt==='espelho') mp=mp.filter(p=>!p.blingId&&p.status==='espelho');
  else if(statusFilt==='fechado') mp=mp.filter(p=>!p.blingId&&p.status==='fechado');
  else if(statusFilt==='bling') mp=mp.filter(p=>!!p.blingId);
  const tot=mp.length;
  const esp=mp.filter(p=>p.status==='espelho'&&!p.blingId).length;
  const fec=mp.filter(p=>p.status==='fechado'&&!p.blingId).length;
  const bl =mp.filter(p=>p.blingId).length;
  const totalR=mp.reduce((a,p)=>a+p.total,0);
  document.getElementById('dash-nums-label').textContent=(isAG&&!vdF?'Números Consolidados':'Meus Números')+canalLabel;
  // Cards: vendedor vê só Totais, Espelhos, Fechados
  if(isAG){
    document.getElementById('dash-grid').innerHTML=`
      <div class="dc wine"><span class="dc-n">${tot}</span><div class="dc-l">PEDIDOS TOTAIS</div></div>
      <div class="dc"><span class="dc-n" style="color:#7D2A44;">${esp}</span><div class="dc-l">ESPELHOS</div></div>
      <div class="dc"><span class="dc-n" style="color:var(--green);">${fec}</span><div class="dc-l">FECHADOS</div></div>
      <div class="dc wine" style="grid-column:span 2;"><span class="dc-n">${fmtBRL(totalR)}</span><div class="dc-l">TOTAL EM CARTEIRA${canalLabel}</div></div>
    `;
  }else{
    document.getElementById('dash-grid').innerHTML=`
      <div class="dc wine"><span class="dc-n">${tot}</span><div class="dc-l">PEDIDOS TOTAIS</div></div>
      <div class="dc"><span class="dc-n" style="color:#7D2A44;">${esp}</span><div class="dc-l">ESPELHOS</div></div>
      <div class="dc"><span class="dc-n" style="color:var(--green);">${fec}</span><div class="dc-l">FECHADOS</div></div>
    `;
  }
  // Barra Bling comparativa
  const pct=fec>0?Math.round((bl/fec)*100):0;
  const barW=Math.min(pct,100);
  const msg=fec===0?'Nenhum pedido fechado ainda.':bl===fec?'✅ Todos os pedidos fechados foram enviados ao Bling.':bl<fec?`⚠️ ${fec-bl} pedido(s) fechado(s) ainda não enviado(s) ao Bling.`:'';
  document.getElementById('bc-rows').innerHTML=`
    <div class="bc-row">
      <span class="bc-label">Pedidos Fechados</span>
      <div class="bc-bar-wrap"><div class="bc-bar" style="width:100%;background:var(--green);"></div></div>
      <span class="bc-val" style="color:var(--green);">${fec}</span>
      <span class="bc-pct"></span>
    </div>
    <div class="bc-row">
      <span class="bc-label">Enviados ao Bling</span>
      <div class="bc-bar-wrap"><div class="bc-bar" style="width:${barW}%;background:var(--bling);"></div></div>
      <span class="bc-val" style="color:var(--bling);">${bl}</span>
      <span class="bc-pct">${pct}%</span>
    </div>
    <div style="font-size:10px;color:var(--txt-mid);margin-top:6px;">${msg}</div>
  `;
  // Por vendedor — admin vê todos, gerente/coord vê equipe, vendedor não vê
  const vsWrap=document.getElementById('dash-vs-wrap');
  if(isAG&&!vdF){
    vsWrap.style.display='block';
    const vsLabel=document.getElementById('dash-vs-canal-label');
    if(vsLabel)vsLabel.textContent=canalLabel;
    let todos=S.pedidos().filter(p=>!p.deletedAt);
    if(canal)todos=todos.filter(p=>p.cType===canal);
    // Filtrar pela equipe (gerente) ou todos (admin)
    if(isGerente&&equipe) todos=todos.filter(p=>equipe.has(p.vendedor));
    const byV={};
    todos.forEach(p=>{
      if(!byV[p.vendedor])byV[p.vendedor]={user:p.vendedor,name:p.vendedorName||p.vendedor,tot:0,qtd:0,esp:0,fec:0,bl:0};
      const v=byV[p.vendedor];v.qtd++;v.tot+=p.total;
      if(p.status==='espelho'&&!p.blingId)v.esp++;
      if(p.status==='fechado'&&!p.blingId)v.fec++;
      if(p.blingId)v.bl++;
    });
    document.getElementById('dash-vs').innerHTML=Object.values(byV).sort((a,b)=>b.tot-a.tot).map(v=>{
      const bPct=v.fec>0?Math.round((v.bl/v.fec)*100):0;
      return `<div class="vs-card">
        <div class="vs-name">${v.name}</div>
        <div class="vs-row"><span>Pedidos</span><strong>${v.qtd}</strong></div>
        <div class="vs-row"><span>Espelhos</span><strong style="color:#7D2A44;">${v.esp}</strong></div>
        <div class="vs-row"><span>Fechados</span><strong style="color:var(--green);">${v.fec}</strong></div>
        <div class="vs-row"><span>No Bling</span><strong style="color:var(--bling);">${v.bl} <span style="font-size:9px;font-weight:normal;">(${bPct}%)</span></strong></div>
        <div class="vs-row"><span style="color:var(--wine);font-weight:bold;">Total</span><strong style="color:var(--wine);">${fmtBRL(v.tot)}</strong></div>
      </div>`;
    }).join('')||'<div class="empty"><p>Nenhum pedido ainda.</p></div>';
  }else vsWrap.style.display='none';
  // Últimos pedidos
  const recent=mp.slice(0,5);
  document.getElementById('dash-recent').innerHTML=recent.length?recent.map(p=>{
    const st=p.blingId?'<span class="ps-b">🔗 Bling</span>':p.status==='fechado'?'<span class="ps-f">✅ Fechado</span>':'<span class="ps-e">📋 Espelho</span>';
    const ctb=p.cType==='b2b'?'<span class="bb2b" style="font-size:8px;">B2B</span>':p.cType==='b2c'?'<span class="bb2c" style="font-size:8px;">B2C</span>':'';
    return `<div class="pc" style="margin-bottom:6px;"><div style="flex:1;"><span class="pi-name">${p.cliente?.razao||'—'} ${ctb}</span><span class="pi-sub">${p.id} · ${new Date(p.data).toLocaleDateString('pt-BR')}</span></div><div style="display:flex;align-items:center;gap:8px;">${st}<span class="p-total">${fmtBRL(p.total)}</span><button class="bsm bsm-w" onclick="openEdit('${p.id}')">Abrir</button></div></div>`;
  }).join(''):'<div class="empty"><p>Nenhum pedido ainda. Crie o primeiro!</p></div>';
  // Seções novas
  renderDashComissoes();
  // Estabelecimentos (admin/gerente)
  const isAdmG=CU.role==='admin'||CU.role==='gerente';
  if(isAdmG){
    const selEA=document.getElementById('est-ano');
    const selEM=document.getElementById('est-mes');
    const ano=new Date().getFullYear();
    if(selEA&&!selEA.innerHTML) selEA.innerHTML=[ano-1,ano,ano+1].map(a=>`<option value="${a}" ${a===ano?'selected':''}>${a}</option>`).join('');
    if(selEM&&!selEM.innerHTML) selEM.innerHTML='<option value="0">Todos os meses</option>'+MESES.map((m,i)=>`<option value="${i+1}" ${i+1===new Date().getMonth()+1?'selected':''}>${m}</option>`).join('');
    renderEstabelecimentos();
  }
}
function filterDashByVendor(user){
  const sel=document.getElementById('dash-fv');if(sel)sel.value=user;
  renderDash();
}

// ══════════════════════════════════════════════
// TIPO DE CLIENTE
// ══════════════════════════════════════════════
function onDoc(field){
  const cnpj=document.getElementById('c-cnpj').value.trim();
  const cpf=document.getElementById('c-cpf').value.trim();
  if(field==='cnpj'&&cnpj){cType='b2b';document.getElementById('c-cpf').value='';}
  else if(field==='cpf'&&cpf){cType='b2c';document.getElementById('c-cnpj').value='';}
  else cType=null;
  document.getElementById('ct-badge').innerHTML=cType==='b2b'?'<span class="bb2b">B2B</span>':cType==='b2c'?'<span class="bb2c">B2C</span>':'';
  document.getElementById('pt-ind').textContent=cType==='b2b'?'📋 Tabela B2B':cType==='b2c'?'📋 Tabela B2C':'';
  document.querySelectorAll('.ws').forEach(s=>updateRow(s.closest('tr')));
}

// ══════════════════════════════════════════════
// AUTOCOMPLETE / LUPA CLIENTES
// ══════════════════════════════════════════════
let acTimer=null;
function onRazaoInput(){
  clearTimeout(acTimer);
  const v=document.getElementById('c-razao').value.trim();
  if(v.length<3){document.getElementById('ac-drop').style.display='none';return;}
  acTimer=setTimeout(()=>_showAC(v),300);
}
function buscarCliente(){_showAC(document.getElementById('c-razao').value.trim());}
function _showAC(q){
  if(!q){showToast('Digite pelo menos 3 letras para buscar');return;}
  // Busca combinada: localStorage + clientesCache (Supabase)
  const todos=[...S.clientes()];
  clientesCache.forEach(c=>{if(!todos.find(x=>x.id===c.id))todos.push(c);});
  const matches=todos.filter(c=>(c.razao||'').toLowerCase().includes(q.toLowerCase())||(c.cnpj||'').includes(q)||(c.cpf||'').includes(q)).slice(0,8);
  const drop=document.getElementById('ac-drop');
  if(!matches.length){drop.innerHTML='<div class="ac-item"><div class="ac-nm">Nenhum cliente encontrado</div></div>';drop.style.display='block';return;}
  drop.innerHTML=matches.map(c=>`<div class="ac-item" onclick="fillFromCliente('${c.id}')"><div><div class="ac-nm">${c.razao}</div><div class="ac-sb">${c.cnpj||c.cpf||''} · ${c.cidade||''}</div></div><span class="${c.tipo==='B2B'?'bb2b':'bb2c'}">${c.tipo||''}</span></div>`).join('');
  drop.style.display='block';
}
function fillFromCliente(id){
  const c=S.clientes().find(x=>x.id===id);if(!c)return;
  document.getElementById('c-razao').value=c.razao||'';
  document.getElementById('c-fantasia').value=c.fantasia||'';
  document.getElementById('c-cnpj').value=c.cnpj||'';
  document.getElementById('c-cpf').value=c.cpf||'';
  document.getElementById('c-end').value=c.end||'';
  document.getElementById('c-cidade').value=c.cidade||'';
  document.getElementById('c-cep').value=c.cep||'';
  document.getElementById('c-tel').value=c.tel||'';
  document.getElementById('c-email').value=c.email||'';
  document.getElementById('ac-drop').style.display='none';
  if(c.cnpj)onDoc('cnpj');else if(c.cpf)onDoc('cpf');
  showToast('Dados preenchidos: '+c.razao,true);
}
document.addEventListener('click',e=>{if(!e.target.closest('.ac-wrap'))document.getElementById('ac-drop').style.display='none';});

// ══════════════════════════════════════════════
// STATUS / FRETE
// ══════════════════════════════════════════════
function setSts(s){oStatus=s;document.getElementById('sts-e').className='so'+(s==='espelho'?' sel-e':'');document.getElementById('sts-f').className='so'+(s==='fechado'?' sel-f':'');}
function setFrete(m){freteMode=m;['d','i','v'].forEach(x=>document.getElementById('fb-'+x).classList.remove('active'));document.getElementById('fb-'+(m==='definir'?'d':m==='incluso'?'i':'v')).classList.add('active');document.getElementById('frete-valor').style.display=m==='valor'?'inline-block':'none';calcTots();}

// ══════════════════════════════════════════════
// CAMPOS EXTRAS
// ══════════════════════════════════════════════
function addField(lbl='',val=''){
  const name=lbl||document.getElementById('ef-n').value.trim();
  const value=val||document.getElementById('ef-v').value.trim();
  if(!name&&!lbl){showToast('Informe o nome do campo');return;}
  const id='ef_'+Date.now();
  const div=document.createElement('div');div.className='fr';div.id=id;
  div.innerHTML=`<div class="fl">${name.toUpperCase()}</div><div class="fw" style="display:flex;gap:7px;align-items:center;"><input class="fi" type="text" value="${value}" placeholder="Valor" style="flex:1;"><button class="btn-rm" onclick="document.getElementById('${id}').remove()">✕</button></div>`;
  document.getElementById('extra-fields').appendChild(div);
  if(!lbl){document.getElementById('ef-n').value='';document.getElementById('ef-v').value='';}
}

// ══════════════════════════════════════════════
// ITENS DO PEDIDO
// ══════════════════════════════════════════════
function buildOpts(sel=''){
  let h='<option value="">— Selecione o vinho —</option>';
  [...new Set(CAT.map(c=>c.marca))].forEach(m=>{
    const its=CAT.filter(c=>c.marca===m);
    h+=`<optgroup label="${m} (${its[0].orig})">`;
    its.forEach(w=>{h+=`<option value="${w.nome}"${w.nome===sel?' selected':''}>${w.nome} ${w.safra}</option>`;});
    h+='</optgroup>';
  });
  return h;
}
function addItem(sn='',qty=0,neg=0){
  const tr=document.createElement('tr');
  tr.innerHTML=`<td><select class="ws" onchange="updateRow(this.closest('tr'))">${buildOpts(sn)}</select></td><td><input class="ci" readonly style="width:52px;"></td><td><input class="ci" readonly style="width:47px;"></td><td><input class="qi" type="number" min="0" placeholder="0" style="width:57px;" oninput="updateRow(this.closest('tr'))"></td><td><input class="ci" readonly style="width:57px;"></td><td><input class="pi" readonly style="width:70px;"></td><td><input class="ni2" type="number" min="0" step="0.01" placeholder="—" style="width:70px;" oninput="updateRow(this.closest('tr'))"></td><td class="tc">—</td><td><button class="btn-rm" onclick="this.closest('tr').remove();calcTots()">✕</button></td>`;
  document.getElementById('ot-body').appendChild(tr);
  if(sn){tr.querySelector('.qi').value=qty||'';tr.querySelector('.ni2').value=neg||'';updateRow(tr);}
}
function updateRow(tr){
  if(!tr)return;
  const nome=tr.querySelector('.ws').value;
  const wine=CAT.find(c=>c.nome===nome);
  const [safraI,tipoI,qtyI,cxI,priceI,negI]=tr.querySelectorAll('input');
  const totTd=tr.querySelector('.tc');
  if(!wine){safraI.value=tipoI.value=cxI.value=priceI.value='';totTd.textContent='—';calcTots();return;}
  safraI.value=wine.safra;tipoI.value=wine.tipo;
  const price=wine[cType==='b2c'?'b2c':'b2b'];
  priceI.value=fmtBRL(price);
  const qty=parseInt(qtyI.value)||0;
  cxI.value=qty>0?(qty%6===0?(qty/6)+' cx':qty+' un'):'—';
  const neg=parseFloat(negI.value)||price;
  totTd.textContent=qty>0?fmtBRL(qty*neg):'—';
  totTd.style.color=(parseFloat(negI.value)>0&&parseFloat(negI.value)<price)?'var(--red)':'var(--wine)';
  calcTots();
}

// ══════════════════════════════════════════════
// TOTAIS / PARCELAS
// ══════════════════════════════════════════════
function calcTots(){
  let sub=0;
  document.querySelectorAll('#ot-body tr').forEach(tr=>{
    const wine=CAT.find(c=>c.nome===tr.querySelector('.ws').value);if(!wine)return;
    const qty=parseInt(tr.querySelectorAll('input')[2].value)||0;
    const negI=tr.querySelectorAll('input')[5];
    const price=parseFloat(negI.value)||wine[cType==='b2c'?'b2c':'b2b'];
    sub+=qty*price;
  });
  document.getElementById('t-sub').textContent=fmtBRL(sub);
  let fv=0,fd='—';
  if(freteMode==='incluso')fd='Incluso';
  else if(freteMode==='valor'){fv=parseFloat(document.getElementById('frete-valor').value)||0;fd=fmtBRL(fv);}
  document.getElementById('t-frete').textContent=fd;
  document.getElementById('t-geral').textContent=fmtBRL(sub+fv);
  calcParc();
}
function calcParc(){
  const data=document.getElementById('f-data').value,forma=document.getElementById('f-forma').value;
  const np=parseInt(document.getElementById('f-parc').value)||1,pr=document.getElementById('f-prazos').value;
  const tot=parseBRL(document.getElementById('t-geral').textContent);
  const cont=document.getElementById('parc-list');
  if(!data||!forma){cont.innerHTML='<div style="font-size:10px;color:var(--txt-mid);padding:7px 0;">Preencha data e forma de pagamento.</div>';return;}
  const base=new Date(data+'T12:00:00');const pv=tot/np;
  let prazos=pr.trim()?pr.split(/[,;\s]+/).map(p=>parseInt(p)).filter(p=>!isNaN(p)):[];
  while(prazos.length<np)prazos.push((prazos[prazos.length-1]||0)+30);
  const fL={pix:'PIX',transferencia:'Transferência Bancária',boleto:'Boleto'};
  let h=`<div class="parc-item"><span class="pn">Total</span><strong style="color:var(--wine);">${fmtBRL(tot)}</strong><span style="color:var(--txt-mid);margin-left:14px;">${fL[forma]||forma} · ${np}× de ${fmtBRL(pv)}</span></div>`;
  for(let i=0;i<np;i++){const d=new Date(base);d.setDate(d.getDate()+prazos[i]);h+=`<div class="parc-item"><span class="pn">${i+1}ª Parcela</span><strong>${fmtBRL(pv)}</strong><span style="color:var(--txt-mid);margin-left:14px;">Vencimento: ${formatDate(d)}</span></div>`;}
  cont.innerHTML=h;
}

// ══════════════════════════════════════════════
// COMENTÁRIOS
// ══════════════════════════════════════════════
function renderComments(pedido){
  const comments=pedido?.comments||[];
  const rp={admin:'rp-a',gerente:'rp-g',vendedor:'rp-v'};
  const rn={admin:'ADM',gerente:'Gerente',vendedor:'Vendedor'};
  const list=document.getElementById('comments-list');
  if(!comments.length){list.innerHTML='<div style="font-size:10px;color:var(--txt-mid);padding:9px 13px;">Nenhum comentário ainda.</div>';return;}
  list.innerHTML=comments.map(c=>`<div class="ci"><div class="ci-hd"><span class="ci-auth">${c.authorName}</span><span class="rpill ${rp[c.authorRole]||'rp-v'}">${rn[c.authorRole]||c.authorRole}</span><span class="ci-date">${new Date(c.ts).toLocaleString('pt-BR')}</span></div><div>${c.text}</div></div>`).join('');
}
function addComment(){
  const text=document.getElementById('c-ta').value.trim();
  if(!text){showToast('Digite um comentário');return;}
  if(!editId){showToast('Salve o pedido antes de comentar');return;}
  const lista=S.pedidos();const idx=lista.findIndex(p=>p.id===editId);if(idx<0)return;
  const comment={id:'C-'+Date.now(),ts:new Date().toISOString(),author:CU.user,authorName:CU.name,authorRole:CU.role,text};
  if(!lista[idx].comments)lista[idx].comments=[];
  lista[idx].comments.push(comment);S.saveP(lista);
  audit('comentario',`Comentário no pedido ${editId}: "${text.slice(0,50)}"`,editId);
  document.getElementById('c-ta').value='';renderComments(lista[idx]);
  showToast('Comentário adicionado!',true);
}

// ══════════════════════════════════════════════
// NOME DO PDF
// ══════════════════════════════════════════════
function pdfFileName(razao){
  const words=(razao||'cliente').trim().replace(/[^\w\sÀ-ÿ]/g,'').split(/\s+/).filter(Boolean);
  const nm=words.length>=2?`${words[0]}_${words[1]}`:words[0]||'cliente';
  return `${nm}_espelho_pedido_${new Date().toISOString().slice(0,10)}.pdf`;
}

// ══════════════════════════════════════════════
// COLLECT / FILL FORM
// ══════════════════════════════════════════════
function collectItems(){
  const items=[];
  document.querySelectorAll('#ot-body tr').forEach(tr=>{
    const nome=tr.querySelector('.ws').value;const wine=CAT.find(c=>c.nome===nome);if(!wine)return;
    const inps=tr.querySelectorAll('input');const qty=parseInt(inps[2].value)||0;if(!qty)return;
    const price=parseFloat(inps[5].value)||wine[cType==='b2c'?'b2c':'b2b'];
    items.push({nome,safra:wine.safra,tipo:wine.tipo,marca:wine.marca,orig:wine.orig,qty,price,total:qty*price});
  });
  return items;
}
function fillForm(p){
  const c=p.cliente||{};
  ['razao','fantasia','cnpj','ie','cpf','end','cidade','cep','tel','email','vendedor'].forEach(k=>document.getElementById('c-'+k).value=c[k]||'');
  document.getElementById('extra-fields').innerHTML='';
  (c.extras||[]).forEach(e=>addField(e.l,e.v));
  cType=p.cType||null;onDoc(c.cnpj?'cnpj':c.cpf?'cpf':null);
  setSts(p.status||'espelho');
  document.getElementById('ot-body').innerHTML='';
  (p.items||[]).forEach(it=>addItem(it.nome,it.qty,it.price));
  freteMode=p.frete?.mode||'definir';setFrete(freteMode);
  if(freteMode==='valor')document.getElementById('frete-valor').value=p.frete?.valor||0;
  calcTots();
  const fat=p.faturamento||{};
  ['data','forma','prazos'].forEach(k=>document.getElementById('f-'+k).value=fat[k]||'');
  document.getElementById('f-parc').value=fat.parcelas||'1';calcParc();
  renderComments(p);
  document.getElementById('form-title').textContent='Editando Pedido';
  document.getElementById('form-sub').textContent=p.id+' · '+(p.cliente?.razao||'');
  document.getElementById('btn-bling').disabled=false;
  const emailBtn=document.getElementById('btn-email');if(emailBtn)emailBtn.disabled=false;
  document.getElementById('bling-msg').textContent=p.blingId?`✅ Enviado ao Bling · ID: ${p.blingId}`:'';
}

// ══════════════════════════════════════════════
// SALVAR PEDIDO
// ══════════════════════════════════════════════
function salvar(){
  const razao=document.getElementById('c-razao').value.trim();
  if(!razao){showToast('Informe a Razão Social');return;}
  const items=collectItems();
  if(!items.length){showToast('Adicione pelo menos um item');return;}
  const extras=[];
  document.querySelectorAll('#extra-fields .fr').forEach(row=>{extras.push({l:row.querySelector('.fl').textContent.trim(),v:row.querySelector('input').value});});
  const isNew=!editId;const lista=S.pedidos();const existing=editId?lista.find(p=>p.id===editId):null;
  const cliData={razao,fantasia:document.getElementById('c-fantasia').value,cnpj:document.getElementById('c-cnpj').value,ie:document.getElementById('c-ie').value,cpf:document.getElementById('c-cpf').value,end:document.getElementById('c-end').value,cidade:document.getElementById('c-cidade').value,cep:document.getElementById('c-cep').value,tel:document.getElementById('c-tel').value,email:document.getElementById('c-email').value,vendedor:document.getElementById('c-vendedor').value,extras};
  upsertCliente(cliData); // auto-salvar cliente
  const vendedorSel=document.getElementById('c-vendedor')?.value||CU.user;
  const vendedorObj=usersCache.find(u=>u.user===vendedorSel)||{user:CU.user,name:CU.name};
  const pedido={
    id:editId||('PED-'+Date.now()),status:oStatus,
    vendedor:vendedorObj.user,vendedorName:vendedorObj.name,
    data:isNew?new Date().toISOString():(existing?.data||new Date().toISOString()),
    updatedAt:new Date().toISOString(),updatedBy:CU.user,
    cType,cliente:cliData,items,
    frete:{mode:freteMode,valor:parseFloat(document.getElementById('frete-valor').value)||0},
    total:parseBRL(document.getElementById('t-geral').textContent),
    faturamento:{data:document.getElementById('f-data').value,forma:document.getElementById('f-forma').value,parcelas:document.getElementById('f-parc').value,prazos:document.getElementById('f-prazos').value},
    comments:existing?.comments||[],blingId:existing?.blingId||null,blingSentAt:existing?.blingSentAt||null,
    history:[...(existing?.history||[]),{ts:new Date().toISOString(),by:CU.user,byName:CU.name,action:isNew?'criar':'editar',snapshot:{status:oStatus,items:[...items],total:parseBRL(document.getElementById('t-geral').textContent)}}],
  };
  if(editId){const idx=lista.findIndex(p=>p.id===editId);if(idx>=0)lista[idx]=pedido;else lista.unshift(pedido);}
  else lista.unshift(pedido);
  S.saveP(lista);editId=pedido.id;
  audit(isNew?'criar':'editar',`Pedido ${isNew?'criado':'editado'}: ${razao} · ${fmtBRL(pedido.total)}`,pedido.id);
  document.getElementById('form-title').textContent='Editando Pedido';
  document.getElementById('form-sub').textContent=pedido.id+' · '+razao;
  document.getElementById('btn-bling').disabled=false;
  const emailBtn=document.getElementById('btn-email');if(emailBtn)emailBtn.disabled=false;
  // Salvar no Supabase em background
  dbSavePedido(pedido);
  // Gerar comissão se pedido fechado
  if(pedido.status==='fechado'&&!pedido.blingId){
    try{ gerarComissaoPedido(pedido, null); }catch(e){}
  }
  showToast('Pedido salvo!',true);
}

// ══════════════════════════════════════════════
// CLIENTES — CRUD
// ══════════════════════════════════════════════
function upsertCliente(cliData){
  if(!cliData.razao)return;
  let clientes=S.clientes();
  let idx=clientes.findIndex(c=>c.razao.toLowerCase()===cliData.razao.toLowerCase());
  if(idx<0&&cliData.cnpj)idx=clientes.findIndex(c=>c.cnpj===cliData.cnpj);
  if(idx<0&&cliData.cpf)idx=clientes.findIndex(c=>c.cpf===cliData.cpf);
  const tipo=cliData.cnpj?'B2B':cliData.cpf?'B2C':null;
  const cli={id:idx>=0?clientes[idx].id:('CLI-'+Date.now()),razao:cliData.razao,fantasia:cliData.fantasia||'',cnpj:cliData.cnpj||'',ie:cliData.ie||'',cpf:cliData.cpf||'',tipo:tipo||clientes[idx]?.tipo||null,ativo:idx>=0?(clientes[idx].ativo!==false):true,end:cliData.end||'',cidade:cliData.cidade||'',cep:cliData.cep||'',tel:cliData.tel||'',email:cliData.email||'',vendedor:CU.user,updatedAt:new Date().toISOString()};
  if(idx>=0)clientes[idx]=cli;else clientes.unshift(cli);
  S.saveCli(clientes);
  dbSaveCliente(cli);
}
function openCliModal(id){
  editCliId=id;
  document.getElementById('mc-title').textContent=id?'Editar Cliente':'Novo Cliente';
  if(id){
    const c=S.clientes().find(x=>x.id===id)||{};
    document.getElementById('mc-razao').value=c.razao||'';document.getElementById('mc-fantasia').value=c.fantasia||'';
    document.getElementById('mc-cnpj').value=c.cnpj||'';document.getElementById('mc-ie').value=c.ie||'';document.getElementById('mc-cpf').value=c.cpf||'';
    document.getElementById('mc-end').value=c.end||'';document.getElementById('mc-cidade').value=c.cidade||'';
    document.getElementById('mc-cep').value=c.cep||'';document.getElementById('mc-tel').value=c.tel||'';
    document.getElementById('mc-email').value=c.email||'';
    document.getElementById(c.ativo!==false?'mc-ativo-s':'mc-ativo-n').checked=true;
    document.getElementById('mc-tipo-badge').textContent=c.tipo||'—';
  }else{
    ['mc-razao','mc-fantasia','mc-cnpj','mc-ie','mc-cpf','mc-end','mc-cidade','mc-cep','mc-tel','mc-email'].forEach(x=>document.getElementById(x).value='');
    document.getElementById('mc-ativo-s').checked=true;
    document.getElementById('mc-tipo-badge').textContent='—';
  }
  document.getElementById('modal-cli').classList.add('open');
}
function onCliDoc(field){
  const cnpj=document.getElementById('mc-cnpj').value.trim();
  const cpf=document.getElementById('mc-cpf').value.trim();
  let tipo=null;
  if(field==='cnpj'&&cnpj){tipo='B2B';document.getElementById('mc-cpf').value='';}
  else if(field==='cpf'&&cpf){tipo='B2C';document.getElementById('mc-cnpj').value='';}
  document.getElementById('mc-tipo-badge').textContent=tipo||'—';
}
function saveCliente(){
  const razao=document.getElementById('mc-razao').value.trim();
  if(!razao){showToast('Informe a Razão Social');return;}
  const cnpj=document.getElementById('mc-cnpj').value.trim();
  const cpf=document.getElementById('mc-cpf').value.trim();
  const tipo=cnpj?'B2B':cpf?'B2C':null;
  const ativo=document.getElementById('mc-ativo-s').checked;
  let clientes=S.clientes();
  const cli={id:editCliId||('CLI-'+Date.now()),razao,fantasia:document.getElementById('mc-fantasia').value,cnpj,ie:document.getElementById('mc-ie').value,cpf,tipo,ativo,end:document.getElementById('mc-end').value,cidade:document.getElementById('mc-cidade').value,cep:document.getElementById('mc-cep').value,tel:document.getElementById('mc-tel').value,email:document.getElementById('mc-email').value,vendedor:CU.user,updatedAt:new Date().toISOString()};
  if(editCliId){const idx=clientes.findIndex(c=>c.id===editCliId);if(idx>=0)clientes[idx]=cli;else clientes.unshift(cli);}
  else clientes.unshift(cli);
  S.saveCli(clientes);
  dbSaveCliente(cli);
  audit('editar',`Cliente ${editCliId?'editado':'criado'}: ${razao}`);
  closeModal('modal-cli');renderClientes();showToast('Cliente salvo!',true);
}
function renderClientes(){
  const tipoF=document.getElementById('clf-tipo').value;
  const ativoF=document.getElementById('clf-ativo').value;
  const srF=document.getElementById('clf-search').value.toLowerCase();
  const isAG=CU.role==='admin'||CU.role==='gerente';
  const lista=S.clientes().filter(c=>{
    if(!isAG&&c.vendedor!==CU.user)return false;
    if(tipoF&&c.tipo!==tipoF)return false;
    if(ativoF==='1'&&c.ativo===false)return false;
    if(ativoF==='0'&&c.ativo!==false)return false;
    if(srF&&!c.razao?.toLowerCase().includes(srF))return false;
    return true;
  });
  const cont=document.getElementById('clientes-container');
  if(!lista.length){cont.innerHTML='<div class="empty"><p>Nenhum cliente encontrado.</p></div>';return;}
  cont.innerHTML=lista.map(c=>`<div class="clc"><div style="flex:1;min-width:0;"><span class="cl-name">${c.razao}</span><span class="cl-sub">${c.cnpj||c.cpf||''} · ${c.cidade||''} · ${c.email||''}</span></div><div style="display:flex;align-items:center;gap:7px;flex-wrap:wrap;">${c.tipo==='B2B'?'<span class="bb2b">B2B</span>':c.tipo==='B2C'?'<span class="bb2c">B2C</span>':''}<span class="${c.ativo!==false?'ba-s':'ba-n'}">${c.ativo!==false?'● Ativo':'● Inativo'}</span><button class="bsm bsm-w" onclick="openCliModal('${c.id}')">✏️ Editar</button></div></div>`).join('');
}

