function setTab(t){listTab=t;['ativos','excluidos'].forEach(x=>document.getElementById('tab-'+x)?.classList.toggle('active',x===t));renderList();}
function renderList(){
  const isAdmin=CU.role==='admin';
  const isGerente=CU.role==='gerente'||CU.role==='coordenador';
  const isAG=isAdmin||isGerente;
  // Equipe do gerente
  const equipeGer=isGerente?new Set([CU.user,...usersCache.filter(u=>u.reportaPara===CU.user).map(u=>u.user)]):null;
  document.getElementById('list-title').textContent=isAdmin?'Todos os Pedidos':isGerente?'Pedidos da Equipe':'Meus Pedidos';
  document.getElementById('list-sub').textContent=isAdmin?'Pedidos de todos os vendedores':isGerente?'Você e sua equipe':'Seus espelhos e pedidos fechados';
  if(isAdmin){
    const sel=document.getElementById('filter-vendor');const cur=sel.value;
    sel.innerHTML='<option value="">Todos os vendedores</option>';
    usersCache.forEach(u=>{sel.innerHTML+=`<option value="${u.user}">${u.name}</option>`;});
    sel.value=cur;
  } else if(isGerente){
    const sel=document.getElementById('filter-vendor');const cur=sel.value;
    sel.innerHTML='<option value="">Toda a equipe</option>';
    usersCache.filter(u=>equipeGer.has(u.user)).forEach(u=>{sel.innerHTML+=`<option value="${u.user}">${u.name}</option>`;});
    sel.value=cur;
  }
  const stF=document.getElementById('filter-status').value;
  const cnF=document.getElementById('filter-canal').value;
  const vdF=isAG?document.getElementById('filter-vendor').value:'';
  const srF=document.getElementById('filter-search').value.toLowerCase();
  const fonte=(isAdmin&&listTab==='excluidos')?S.excluidos():S.pedidos();
  const lista=fonte.filter(p=>{
    // Filtro por papel
    if(isAdmin){ if(vdF&&p.vendedor!==vdF)return false; }
    else if(isGerente){ if(!equipeGer.has(p.vendedor))return false; if(vdF&&p.vendedor!==vdF)return false; }
    else { if(p.vendedor!==CU.user)return false; }
    if(cnF&&p.cType!==cnF)return false;
    if(stF){if(stF==='bling'&&!p.blingId)return false;if(stF!=='bling'&&p.status!==stF)return false;}
    if(srF&&!p.cliente?.razao?.toLowerCase().includes(srF))return false;
    return true;
  });
  const cont=document.getElementById('list-container');
  if(!lista.length){cont.innerHTML='<div class="empty"><p>Nenhum pedido encontrado.</p></div>';return;}
  const isDelTab=(CU.role==='admin'||CU.role==='gerente')&&listTab==='excluidos';
  cont.innerHTML=lista.map(p=>{
    const canEdit=CU.role==='admin'||CU.role==='gerente'||(p.vendedor===CU.user);
    const canDel=(p.vendedor===CU.user||CU.role==='admin')&&!isDelTab;
    const canRestore=(CU.role==='admin'||CU.role==='gerente')&&isDelTab;
    const canViewDel=isDelTab&&!canRestore&&p.vendedor===CU.user; // vendedor vê os seus
    const stHtml=isDelTab?'<span class="ps-x">🗑 Excluído</span>':p.blingId?'<span class="ps-b">🔗 Bling</span>':p.status==='fechado'?'<span class="ps-f">✅ Fechado</span>':'<span class="ps-e">📋 Espelho</span>';
    const ctb=p.cType==='b2b'?'<span class="bb2b" style="font-size:8px;">B2B</span>':p.cType==='b2c'?'<span class="bb2c" style="font-size:8px;">B2C</span>':'';
    const vLine=(isAG&&p.vendedorName)?` · <strong style="color:var(--wine);">${p.vendedorName}</strong>`:'';
    const commB=p.comments?.length?`<span style="background:var(--gold-light);color:var(--wine);padding:1px 5px;border-radius:8px;font-size:9px;font-weight:bold;">💬 ${p.comments.length}</span>`:'';
    const delInfo=isDelTab?`<span style="font-size:10px;color:var(--txt-mid);"> · Excluído por ${p.deletedBy||'?'} em ${p.deletedAt?new Date(p.deletedAt).toLocaleDateString('pt-BR'):''}</span>`:'';
    return `<div class="pc"><div style="flex:1;min-width:0;"><span class="pi-name">${p.cliente?.razao||'—'} ${ctb}</span><span class="pi-sub">${p.id} · ${new Date(p.data).toLocaleDateString('pt-BR')}${vLine} ${commB}${delInfo}</span></div><div style="display:flex;align-items:center;gap:7px;flex-wrap:wrap;">${stHtml}<span class="p-total">${fmtBRL(p.total)}</span>${(canEdit||canViewDel)&&isDelTab?`<button class="bsm bsm-w" onclick="openEditReadonly('${p.id}')">👁 Ver</button>`:''}${canEdit&&!isDelTab?`<button class="bsm bsm-w" onclick="openEdit('${p.id}')">✏️ Abrir</button>`:''}${canRestore?`<button class="bsm" style="background:#FFF8EC;color:var(--wine);border:1px solid var(--gold);" onclick="openRestoreModal('${p.id}')">↩️ Restaurar</button>`:''}${canDel?`<button class="bsm bsm-d" onclick="askDel('${p.id}',event)">🗑</button>`:''}</div></div>`;
  }).join('');
}
function openEdit(id){const fonte=listTab==='excluidos'?S.excluidos():S.pedidos();const p=fonte.find(x=>x.id===id);if(!p)return;editId=id;fillForm(p);showPage('new');}
function askDel(id,e){e.stopPropagation();delId=id;document.getElementById('modal-del').classList.add('open');}
async function confirmDel(){
  const idParaDeletar=delId;
  let lista=S.pedidos();
  const p=lista.find(x=>x.id===idParaDeletar);
  if(p){
    p.deletedAt=new Date().toISOString();
    p.deletedBy=CU.user;
    const ex=S.excluidos();
    ex.unshift(p);
    S.saveX(ex);
    // Marcar como excluído no Supabase (update direto por id, mais robusto)
    if(VERCEL_URL){
      try{
        await dbCall('update','pedidos',{
          data:{excluido:true,excluido_at:p.deletedAt,updated_at:new Date().toISOString()},
          filters:{id:idParaDeletar}
        });
      }catch(e){
        // Se falhar o update (pedido pode não existir no Supabase ainda), tenta insert completo
        try{ await dbSavePedido(p); }catch(e2){}
      }
    }
    audit('excluir',`Pedido excluído: ${p.cliente?.razao||''} · ${fmtBRL(p.total)}`,idParaDeletar);
  }
  S.saveP(lista.filter(x=>x.id!==idParaDeletar));
  delId=null;
  closeModal('modal-del');
  renderList();
  showToast('Pedido excluído',true);
}

