async function renderAudit(){
  document.getElementById('audit-list').innerHTML='<div style="padding:12px;color:var(--txt-mid);font-size:12px;">Carregando...</div>';
  let log=[];
  try{
    const rows=await dbCall('select','auditoria',{select:'*',order:'created_at.desc'});
    log=rows.map(r=>({
      ts:r.created_at, user:r.usuario_login, userName:r.usuario_nome,
      role:r.usuario_role, action:r.acao, desc:r.descricao, pedidoId:r.pedido_id||''
    }));
  }catch(e){
    // Fallback para localStorage se Supabase falhar
    log=S.audit();
  }
  const uF=document.getElementById('afu').value,aF=document.getElementById('afa').value,sF=document.getElementById('afs').value.toLowerCase();
  const sel=document.getElementById('afu');const cur=sel.value;
  sel.innerHTML='<option value="">Todos os usuários</option>';
  [...new Set(log.map(l=>l.user))].forEach(u=>{sel.innerHTML+=`<option value="${u}">${u}</option>`;});sel.value=cur;
  const filtered=log.filter(l=>{if(uF&&l.user!==uF)return false;if(aF&&l.action!==aF)return false;if(sF&&!l.desc?.toLowerCase().includes(sF)&&!l.user?.toLowerCase().includes(sF))return false;return true;});
  const icons={criar:'📝',editar:'✏️',excluir:'🗑',comentario:'💬',bling:'🔗',pdf:'📄',login:'🔑'};
  const rp={admin:'rp-a',gerente:'rp-g',vendedor:'rp-v',coordenador:'rp-g'};
  document.getElementById('audit-list').innerHTML=filtered.length?filtered.map(l=>`<div class="ai"><div style="font-size:13px;flex-shrink:0;margin-top:1px;">${icons[l.action]||'•'}</div><div class="ai-info"><div class="ai-what">${l.desc}</div><div class="ai-who"><span class="rpill ${rp[l.role]||'rp-v'}" style="font-size:8px;">${l.role}</span> <strong>${l.userName||l.user}</strong>${l.pedidoId?` · <span style="color:var(--wine);">${l.pedidoId}</span>`:''}</div></div><div class="ai-time">${new Date(l.ts).toLocaleString('pt-BR')}</div></div>`).join(''):'<div class="empty"><p>Nenhum registro.</p></div>';
}

