function openEditUser(u){editUserId=u;const found=usersCache.find(x=>x.user===u);document.getElementById('mu-title').textContent='Editar Usuário';document.getElementById('mu-name').value=found.name||'';document.getElementById('mu-user').value=found.user;document.getElementById('mu-pass').value=found.pass;document.getElementById('mu-role').value=found.role;document.getElementById('mu-user').disabled=true;fillChefeOptions(u);document.getElementById('mu-chefe').value=found.reportaPara||'';document.getElementById('modal-user').classList.add('open');}
