// ══════════════════════════════════════════════
// BLING — INTEGRAÇÃO
// ══════════════════════════════════════════════
function openBlingModal(){if(!editId){showToast('Salve o pedido antes de enviar ao Bling');return;}document.getElementById('bling-result').style.display='none';document.getElementById('modal-bling').classList.add('open');}
async function enviarBling(){
  if(!VERCEL_URL){showToast('VERCEL_URL não configurado no sistema');return;}
  const action=document.getElementById('bling-action').value;
  const lista=S.pedidos();const p=lista.find(x=>x.id===editId);if(!p){showToast('Pedido não encontrado');return;}
  const btn=document.getElementById('bling-ok-btn');btn.disabled=true;btn.textContent='Enviando...';
  const resultDiv=document.getElementById('bling-result');
  const endpoint=action==='pedido_venda'?'https://www.bling.com.br/Api/v3/pedidos/vendas':'https://www.bling.com.br/Api/v3/orcamentos';
  const fat=p.faturamento||{};
  const totalGeral=p.total||p.items.reduce((s,it)=>s+(it.qty*it.price),0)+(p.frete?.valor||0);
  const np=parseInt(fat.parcelas)||1;
  const pv=Math.round((totalGeral/np)*100)/100;
  let prazos=(fat.prazos||'').trim()?fat.prazos.split(/[,;\s]+/).map(x=>parseInt(x)).filter(x=>!isNaN(x)):[];
  while(prazos.length<np)prazos.push((prazos[prazos.length-1]||0)+30);
  const baseData=fat.data?new Date(fat.data+'T12:00:00'):new Date();
  const parcelas=Array.from({length:np},(_,i)=>{
    const d=new Date(baseData);d.setDate(d.getDate()+prazos[i]);
    return{valor:pv,dataVencimento:d.toISOString().slice(0,10),formaPagamentoTipo:fat.forma||'boleto'};
  });
  const depara=await getRotulosDepara();
  const itensFaltando=p.items.filter(it=>!depara[it.nome]?.codigo_bling);
  if(itensFaltando.length){
    const lista=itensFaltando.map(it=>it.nome).join(', ');
    btn.disabled=false;btn.textContent='Enviar ao Bling';
    resultDiv.style.cssText='display:block;background:#FEE;border:1px solid var(--red);border-radius:5px;padding:9px;color:var(--red);font-size:12px;';
    resultDiv.textContent=`❌ Falta cadastrar o código do Bling para: ${lista}. Vá em "De/Para Rótulos" no menu admin.`;
    return;
  }
  const payload={data:(fat.data||new Date().toISOString().slice(0,10)),contato:{nome:p.cliente?.razao||'',documento:p.cliente?.cnpj||p.cliente?.cpf||'',ie:p.cliente?.ie||''},itens:p.items.map(it=>({codigo:depara[it.nome].codigo_bling,descricao:depara[it.nome].nome_bling||(it.nome+' '+it.safra),quantidade:it.qty,valor:it.price})),parcelas,observacoes:`WG ${p.id} · ${p.vendedorName||p.vendedor}`};
  const url=VERCEL_URL+'/api/bling';
  const body=JSON.stringify({endpoint,payload});
  const headers={'Content-Type':'application/json'};
  try{
    const resp=await fetch(url,{method:'POST',headers,body});
    const data=await resp.json();
    const blingId=String(data?.data?.id||data?.id||'');
    if(resp.ok&&blingId){
      const idx=lista.findIndex(x=>x.id===editId);
      if(idx>=0){lista[idx].blingId=blingId;lista[idx].blingSentAt=new Date().toISOString();}
      S.saveP(lista);
      if(idx>=0) dbSavePedido(lista[idx]);
      audit('bling',`Enviado ao Bling · ID: ${blingId} · ${action}`,editId);
      resultDiv.style.cssText='display:block;background:#EAF4ED;border:1px solid var(--green);border-radius:5px;padding:9px;color:var(--green);font-size:12px;';
      resultDiv.textContent=`✅ Sucesso! ID Bling: ${blingId}`;
      document.getElementById('bling-msg').textContent=`✅ Enviado ao Bling · ID: ${blingId}`;
      showToast('Enviado ao Bling!',true);
      // Gerar comissão automaticamente
      try{ await gerarComissaoPedido(lista[idx]||p, blingId); }catch(e){ console.warn('Comissão não gerada:',e.message); }
      try{ await consumirEstoqueProdutos(lista[idx]||p); }catch(e){ console.warn('Estoque não consumido:',e.message); }
      // Enviar email automaticamente com PDF (se RESEND configurado)
      try{
        const pedidoAtual=lista[idx]||p;
        const cfg=getCfg();
        if(cfg.emailAdmin&&VERCEL_URL){
          const dt=new Date().toLocaleDateString('pt-BR');
          const subj=(cfg.emailSubj||'Pedido WG — {cliente} — {data}')
            .replace('{cliente}',pedidoAtual.cliente?.razao||'—')
            .replace('{data}',dt).replace('{id}',pedidoAtual.id);
          const body=buildEmailBody(pedidoAtual);
          const pdf=gerarPdfBase64();
          const payload={para:cfg.emailAdmin,cc:cfg.emailCc||'',subject:subj,body};
          if(pdf){payload.pdfBase64=pdf.base64;payload.pdfFileName=pdf.filename;}
          fetch(VERCEL_URL+'/api/send-email',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(payload)})
            .then(r=>r.json()).then(d=>{ if(d.ok) showToast('E-mail enviado automaticamente!',true); })
            .catch(e=>console.warn('E-mail automático falhou:',e.message));
        }
      }catch(e){ console.warn('E-mail automático falhou:',e.message); }
    }else if(resp.status===401){
      throw new Error('Bling não conectado. Acesse /api/bling-connect uma vez para autorizar.');
    }else throw new Error(data?.error?.error?.description||data?.error?.error?.message||data?.error?.description||data?.error?.message||data?.message||JSON.stringify(data).slice(0,500));
  }catch(err){
    resultDiv.style.cssText='display:block;background:#FEE;border:1px solid var(--red);border-radius:5px;padding:9px;color:var(--red);font-size:12px;';
    resultDiv.textContent=`❌ Erro: ${err.message}`;
    audit('bling',`Falha Bling: ${err.message}`,editId);
  }
  btn.disabled=false;btn.textContent='Enviar ao Bling';
}

