function gerarPDF(){
  const {jsPDF}=window.jspdf;
  const doc=new jsPDF({orientation:'portrait',unit:'mm',format:'a4'});
  const W=210,ML=14,CW=W-ML*2;
  const WINE=[92,26,46],WINE2=[125,42,68],GOLD=[201,169,110],SAND=[245,237,227],STRIPE=[237,224,212];
  const TXT=[44,26,40],TMID=[138,96,112],WHITE=[255,255,255];
  // Fundo
  doc.setFillColor(250,245,240);doc.rect(0,0,W,297,'F');
  // Header vinho
  doc.setFillColor(...WINE);doc.rect(0,0,W,28,'F');
  // Logo
  try{if(LOGO&&!LOGO.includes(''))doc.addImage(LOGO,'JPEG',ML-2,3,54,22);}catch(e){}
  // Título
  doc.setTextColor(...GOLD);doc.setFontSize(18);doc.setFont('helvetica','bold');
  doc.text('Espelho de Pedido',W/2+20,12,{align:'center'});
  doc.setFontSize(9);doc.setFont('helvetica','italic');
  doc.text('Importadora de Vinhos Boutique e de Rótulos Exclusivos',W/2+20,19,{align:'center'});
  // Badge status
  doc.setFillColor(...GOLD);doc.roundedRect(W-ML-38,4,38,8,1.5,1.5,'F');
  doc.setTextColor(...WINE);doc.setFontSize(6.5);doc.setFont('helvetica','bold');
  doc.text(oStatus==='fechado'?'PEDIDO FECHADO':'ESPELHO',W-ML-19,9.2,{align:'center'});
  // Subheader
  doc.setFillColor(...WINE2);doc.rect(0,28,W,8,'F');
  doc.setTextColor(...GOLD);doc.setFontSize(8);doc.setFont('helvetica','normal');
  doc.text(new Date().toLocaleString('pt-BR',{month:'long',year:'numeric'}).toUpperCase(),W/2,33.5,{align:'center'});
  let y=42;
  const secBar=(t,yy)=>{doc.setFillColor(...WINE);doc.rect(ML,yy,CW,7,'F');doc.setTextColor(...GOLD);doc.setFontSize(8);doc.setFont('helvetica','bold');doc.text(t,ML+3,yy+4.8);return yy+7;};
  const dRow=(l,v,yy,alt)=>{doc.setFillColor(...(alt?STRIPE:SAND));doc.rect(ML,yy,CW,6.5,'F');doc.setTextColor(...TMID);doc.setFontSize(7);doc.setFont('helvetica','bold');doc.text(l.toUpperCase(),ML+3,yy+4.2);doc.setTextColor(...TXT);doc.setFont('helvetica','normal');doc.text(String(v||''),ML+42,yy+4.2);return yy+6.5;};
  // Dados do cliente
  y=secBar('DADOS DO CLIENTE',y);let alt=false;
  const cli={'Razão Social':document.getElementById('c-razao').value,'Nome Fantasia':document.getElementById('c-fantasia').value,[cType==='b2c'?'CPF':'CNPJ']:cType==='b2c'?document.getElementById('c-cpf').value:document.getElementById('c-cnpj').value,'Endereço':document.getElementById('c-end').value,'Cidade / UF':document.getElementById('c-cidade').value,'CEP':document.getElementById('c-cep').value,'Telefone':document.getElementById('c-tel').value,'E-mail':document.getElementById('c-email').value,'Vendedor':document.getElementById('c-vendedor').value};
  Object.entries(cli).forEach(([k,v])=>{if(v){y=dRow(k,v,y,alt);alt=!alt;}});
  document.querySelectorAll('#extra-fields .fr').forEach(row=>{const l=row.querySelector('.fl').textContent.trim();const v=row.querySelector('input').value;if(v){y=dRow(l,v,y,alt);alt=!alt;}});
  // Pedido
  y+=4;y=secBar('PEDIDO',y);
  doc.setFillColor(...WINE);doc.rect(ML,y,CW,6,'F');
  doc.setTextColor(...GOLD);doc.setFontSize(6.5);doc.setFont('helvetica','bold');
  [{l:'RÓTULO',x:ML+2,a:'left'},{l:'SAFRA',x:ML+74,a:'center'},{l:'TIPO',x:ML+92,a:'center'},{l:'QTDE',x:ML+110,a:'center'},{l:'CAIXAS',x:ML+127,a:'center'},{l:'UNIT.',x:ML+145,a:'center'},{l:'TOTAL',x:ML+CW-2,a:'right'}].forEach(c=>doc.text(c.l,c.x,y+4,{align:c.a}));y+=6;
  const items=collectItems();let sub=0;let curM=null;alt=false;
  items.forEach(it=>{
    if(it.marca!==curM){curM=it.marca;doc.setFillColor(...(it.orig==='CHILE'?[26,58,92]:WINE2));doc.rect(ML,y,CW,5,'F');doc.setTextColor(...GOLD);doc.setFontSize(7);doc.setFont('helvetica','bold');doc.text(it.marca.toUpperCase(),ML+3,y+3.5);doc.setTextColor(138,96,112);doc.setFontSize(6);doc.setFont('helvetica','normal');doc.text(it.orig,ML+CW-2,y+3.5,{align:'right'});y+=5;alt=false;}
    doc.setFillColor(...(alt?STRIPE:SAND));doc.rect(ML,y,CW,6,'F');
    const cx=it.qty%6===0?(it.qty/6)+' cx':it.qty+' un';
    doc.setTextColor(...TXT);doc.setFontSize(8);doc.setFont('helvetica','bold');doc.text(it.nome,ML+2,y+4);
    doc.setTextColor(...TMID);doc.setFontSize(7);doc.setFont('helvetica','italic');doc.text(it.safra,ML+74,y+4,{align:'center'});
    doc.setFont('helvetica','normal');doc.text(it.tipo,ML+92,y+4,{align:'center'});
    doc.setTextColor(...TXT);doc.setFont('helvetica','bold');doc.text(it.qty+'un',ML+110,y+4,{align:'center'});
    doc.setTextColor(...TMID);doc.setFont('helvetica','normal');doc.text(cx,ML+127,y+4,{align:'center'});
    doc.setTextColor(...TXT);doc.text(fmtBRL(it.price),ML+145,y+4,{align:'center'});
    doc.setTextColor(...WINE);doc.setFont('helvetica','bold');doc.text(fmtBRL(it.total),ML+CW-2,y+4,{align:'right'});
    sub+=it.total;y+=6;alt=!alt;
  });
  // Totais
  let fv=0,fd='—';if(freteMode==='incluso')fd='Incluso';else if(freteMode==='valor'){fv=parseFloat(document.getElementById('frete-valor').value)||0;fd=fmtBRL(fv);}
  [[STRIPE,'SUBTOTAL PRODUTOS',fmtBRL(sub)],[SAND,'FRETE',fd]].forEach(([bg,l,v])=>{doc.setFillColor(...bg);doc.rect(ML,y,CW,6,'F');doc.setTextColor(...TMID);doc.setFontSize(7);doc.setFont('helvetica','bold');doc.text(l,ML+CW-44,y+4,{align:'right'});doc.setTextColor(...TXT);doc.setFont('helvetica','normal');doc.text(v,ML+CW-2,y+4,{align:'right'});y+=6;});
  doc.setFillColor(...WINE);doc.rect(ML,y,CW,8,'F');doc.setTextColor(255,255,255);doc.setFontSize(8);doc.setFont('helvetica','bold');doc.text('TOTAL GERAL',ML+CW-54,y+5.2,{align:'right'});doc.setTextColor(...GOLD);doc.setFontSize(12);doc.text(fmtBRL(sub+fv),ML+CW-2,y+5.5,{align:'right'});y+=8;y+=5;
  // Faturamento
  y=secBar('FORMA DE PAGAMENTO',y);
  const fd2=document.getElementById('f-data').value,frma=document.getElementById('f-forma').value,np=parseInt(document.getElementById('f-parc').value)||1,pr=document.getElementById('f-prazos').value;
  let prazos=pr.trim()?pr.split(/[,;\s]+/).map(p=>parseInt(p)).filter(p=>!isNaN(p)):[];while(prazos.length<np)prazos.push((prazos[prazos.length-1]||0)+30);
  const fLb={pix:'PIX',transferencia:'Transferência Bancária',boleto:'Boleto'};const totG=sub+fv;
  const pmtRows=[['Subtotal',fmtBRL(sub)],['Frete',fd],['Total Geral',fmtBRL(totG)],[`${np}× via ${fLb[frma]||frma} de`,fmtBRL(totG/np)]];
  if(fd2){const base=new Date(fd2+'T12:00:00');for(let i=0;i<np;i++){const d=new Date(base);d.setDate(d.getDate()+prazos[i]);pmtRows.push([`${i+1}ª Parcela — vencimento`,formatDate(d)]);}}
  alt=false;pmtRows.forEach(([k,v])=>{doc.setFillColor(...(alt?STRIPE:SAND));doc.rect(ML,y,CW,6.5,'F');doc.setTextColor(...TXT);doc.setFontSize(8);doc.setFont('helvetica','bold');doc.text(k,ML+3,y+4.2);doc.setFont('helvetica','normal');doc.text(String(v),ML+CW-2,y+4.2,{align:'right'});y+=6.5;alt=!alt;});
  // Entrega
  y+=4;y=secBar('LOCAL DE ENTREGA / FATURAMENTO',y);alt=false;
  [['Razão Social',document.getElementById('c-razao').value],['Nome Fantasia',document.getElementById('c-fantasia').value],[cType==='b2c'?'CPF':'CNPJ',cType==='b2c'?document.getElementById('c-cpf').value:document.getElementById('c-cnpj').value],['Endereço',document.getElementById('c-end').value],['Cidade / UF',document.getElementById('c-cidade').value],['CEP',document.getElementById('c-cep').value],['Telefone',document.getElementById('c-tel').value],['E-mail',document.getElementById('c-email').value]].forEach(([k,v])=>{if(!v)return;doc.setFillColor(...(alt?STRIPE:SAND));doc.rect(ML,y,CW,6.5,'F');doc.setTextColor(...TMID);doc.setFontSize(7);doc.setFont('helvetica','bold');doc.text(k.toUpperCase(),ML+3,y+4.2);doc.setTextColor(...TXT);doc.setFont('helvetica','normal');doc.setFontSize(8);doc.text(String(v),ML+42,y+4.2);y+=6.5;alt=!alt;});
  // Rodapé
  y+=4;doc.setTextColor(...TMID);doc.setFontSize(7);doc.setFont('helvetica','italic');doc.text('* Preços com impostos inclusos · Embalagem mínima: caixa com 6 unidades · Tabela B2B/B2C Jun/2026',ML,y);
  const fy=285;doc.setFillColor(...WINE);doc.rect(0,fy,W,12,'F');doc.setDrawColor(...GOLD);doc.setLineWidth(.5);doc.line(0,fy,W,fy);doc.setTextColor(255,255,255);doc.setFontSize(8);doc.setFont('helvetica','normal');doc.text('(11) 95540-0902',W/6,fy+7,{align:'center'});doc.text('@wine_gallery',W/2,fy+7,{align:'center'});doc.text('winesgallery.com.br',5*W/6,fy+7,{align:'center'});doc.setDrawColor(...GOLD);doc.setLineWidth(.3);doc.line(W/3,fy+2,W/3,fy+10);doc.line(2*W/3,fy+2,2*W/3,fy+10);
  // Salvar com nome correto
  const razao=document.getElementById('c-razao').value||'cliente';
  if(_pdfOutputMode==='base64'){
    _pdfBase64Result={base64:doc.output('datauristring').split(',')[1], filename:pdfFileName(razao)};
  } else {
    doc.save(pdfFileName(razao));
    audit('pdf',`PDF gerado: ${razao}`,editId||'');
    showToast('PDF gerado!',true);
  }
}

// Retorna {base64, filename} sem salvar — usado pelo envio de email
// Usa uma flag global para que gerarPDF retorne base64 em vez de salvar
let _pdfOutputMode = 'save'; // 'save' | 'base64'
let _pdfBase64Result = null;

function gerarPdfBase64(){
  _pdfOutputMode = 'base64';
  _pdfBase64Result = null;
  try{ gerarPDF(); } catch(e){ console.warn('gerarPdfBase64:', e.message); }
  _pdfOutputMode = 'save';
  return _pdfBase64Result;
}

// ══════════════════════════════════════════════
// PONTO 01 — RESTAURAR PEDIDO EXCLUÍDO
// ══════════════════════════════════════════════
let restoreId = null;

function openEditReadonly(id){
  // Vendedor vê pedido excluído em modo somente leitura
  const fonte = S.excluidos();
  const p = fonte.find(x => x.id === id);
  if(!p) return;
  editId = null; // não edita
  fillForm(p);
  showPage('new');
  // Bloquear edição
  document.querySelectorAll('#page-new input, #page-new select, #page-new textarea').forEach(el => el.disabled = true);
  document.getElementById('form-title').textContent = '👁 Visualizando Pedido Excluído';
  document.getElementById('form-sub').textContent = p.id + ' · ' + (p.cliente?.razao || '') + ' · excluído em ' + (p.deletedAt ? new Date(p.deletedAt).toLocaleDateString('pt-BR') : '');
  document.getElementById('act-bar-new')?.querySelectorAll('button').forEach(b => b.disabled = true);
  // Reabilitar só leitura após ver
  setTimeout(() => {
    const note = document.createElement('div');
    note.style.cssText = 'background:#FFF8EC;border:1.5px dashed var(--gold);border-radius:6px;padding:10px 14px;font-size:12px;color:var(--wine);margin-top:10px;';
    note.innerHTML = '🗑 Este pedido está na lixeira. Somente administradores e gerentes podem restaurá-lo.';
    document.getElementById('bling-msg').after(note);
  }, 100);
}

function openRestoreModal(id){
  if(CU.role !== 'admin' && CU.role !== 'gerente'){showToast('Sem permissão para restaurar pedidos');return;}
  restoreId = id;
  const ex = S.excluidos();
  const p = ex.find(x => x.id === id);
  if(!p) return;
  // Montar opções de destino
  const users = usersCache;
  const opts = users.filter(u => u.role === 'vendedor' || u.role === 'gerente' || u.role === 'admin');
  let html = `<div style="font-size:11px;color:var(--txt-mid);margin-bottom:10px;">Pedido: <strong>${p.cliente?.razao||''}</strong> · ${fmtBRL(p.total)}</div>`;
  html += `<div style="font-size:11px;font-weight:bold;color:var(--txt-mid);margin-bottom:6px;">Restaurar para o vendedor:</div>`;
  // Opção: retornar ao vendedor original
  const orig = users.find(u => u.user === p.vendedor);
  if(orig){
    html += `<button onclick="confirmarRestore('${id}','${orig.user}')" style="width:100%;padding:10px;background:var(--wine);color:var(--gold);border:none;border-radius:5px;font-size:12px;font-weight:bold;cursor:pointer;margin-bottom:6px;text-align:left;">↩️ Vendedor original: ${orig.name} (${orig.user})</button>`;
  }
  // Outros vendedores
  opts.filter(u => u.user !== p.vendedor).forEach(u => {
    const rn = {admin:'ADM',gerente:'Gerente',vendedor:'Vendedor',coordenador:'Coordenador'};
    html += `<button onclick="confirmarRestore('${id}','${u.user}')" style="width:100%;padding:9px;background:var(--white);color:var(--txt);border:1.5px solid var(--stripe);border-radius:5px;font-size:12px;cursor:pointer;margin-bottom:5px;text-align:left;">${u.name} <span style="color:var(--txt-mid);font-size:10px;">(${u.user} · ${rn[u.role]})</span></button>`;
  });
  document.getElementById('restore-options').innerHTML = html;
  document.getElementById('modal-restore').classList.add('open');
}

function confirmarRestore(id, targetUser){
  const ex = S.excluidos();
  const p = ex.find(x => x.id === id);
  if(!p){showToast('Pedido não encontrado');return;}
  const targetUsr = usersCache.find(u => u.user === targetUser);
  // Remover flags de exclusão e reatribuir
  const restored = {...p};
  delete restored.deletedAt;
  delete restored.deletedBy;
  delete restored.deletedByName;
  restored.vendedor = targetUser;
  restored.vendedorName = targetUsr?.name || targetUser;
  restored.updatedAt = new Date().toISOString();
  restored.updatedBy = CU.user;
  restored.history = [...(p.history||[]),{ts:new Date().toISOString(),by:CU.user,byName:CU.name,action:'restaurar',snapshot:{restoredTo:targetUser}}];
  // Salvar na lista ativa
  const lista = S.pedidos();
  lista.unshift(restored);
  S.saveP(lista);
  dbSavePedido(restored);
  // Remover dos excluídos
  S.saveX(ex.filter(x => x.id !== id));
  audit('editar', `Pedido restaurado para ${targetUsr?.name||targetUser}: ${p.cliente?.razao||''} · ${fmtBRL(p.total)}`, id);
  closeModal('modal-restore');
  renderList();
  showToast(`Pedido restaurado para ${targetUsr?.name||targetUser}!`, true);
}

