// PONTO 02 — E-MAIL
// ══════════════════════════════════════════════
function getCfg(){
  return {
    emailAdmin: localStorage.getItem('cfg_email_admin') || 'administrativo@winesgallery.com.br',
    emailCc:    localStorage.getItem('cfg_email_cc') || '',
    emailSubj:  localStorage.getItem('cfg_email_subject') || 'Novo Pedido — {cliente} — {data}',
  };
}
function saveCfg(){
  localStorage.setItem('cfg_email_admin', document.getElementById('cfg-email-admin')?.value || '');
  localStorage.setItem('cfg_email_cc',    document.getElementById('cfg-email-cc')?.value || '');
  localStorage.setItem('cfg_email_subject', document.getElementById('cfg-email-subject')?.value || '');
}
function loadCfgFields(){
  const cfg = getCfg();
  if(document.getElementById('cfg-email-admin')) document.getElementById('cfg-email-admin').value = cfg.emailAdmin;
  if(document.getElementById('cfg-email-cc'))    document.getElementById('cfg-email-cc').value    = cfg.emailCc;
  if(document.getElementById('cfg-email-subject')) document.getElementById('cfg-email-subject').value = cfg.emailSubj;
}

function buildEmailBody(p){
  if(!p) return '';
  const c = p.cliente || {};
  const fat = p.faturamento || {};
  const comments = (p.comments||[]).map(cm=>`  • ${cm.authorName} (${new Date(cm.ts).toLocaleString('pt-BR')}): ${cm.text}`).join('\n');
  const itens = (p.items||[]).map(it=>`  • ${it.nome} ${it.safra} — ${it.qty} un — ${fmtBRL(it.price)}/un — Total: ${fmtBRL(it.total)}`).join('\n');
  const docLabel = c.cnpj ? 'CNPJ' : 'CPF';
  const docVal   = c.cnpj || c.cpf || '—';
  const formaMap = {pix:'PIX',transferencia:'Transferência Bancária',boleto:'Boleto'};
  const forma    = formaMap[fat.forma] || fat.forma || '—';
  return `Novo Pedido — Wine's Gallery
════════════════════════════

DADOS DO CLIENTE
Razão Social: ${c.razao || '—'}
${docLabel}: ${docVal}
Endereço: ${c.end || '—'}
Cidade: ${c.cidade || '—'}
Telefone: ${c.tel || '—'}
E-mail: ${c.email || '—'}

PEDIDO
Número: ${p.id}
Status: ${p.status === 'fechado' ? 'Fechado' : 'Espelho'}
Canal: ${(p.cType||'').toUpperCase() || '—'}
Data: ${new Date(p.data).toLocaleDateString('pt-BR')}

ITENS
${itens || '  (sem itens)'}

TOTAIS
Subtotal: ${fmtBRL((p.items||[]).reduce((a,it)=>a+it.total,0))}
Frete: ${p.frete?.mode === 'incluso' ? 'Incluso' : p.frete?.mode === 'valor' ? fmtBRL(p.frete.valor) : 'A definir'}
Total Geral: ${fmtBRL(p.total)}

FATURAMENTO
Forma: ${forma}
Parcelas: ${fat.parcelas || 1}×
Prazos: ${fat.prazos || '—'}
Data Faturamento: ${fat.data || '—'}

VENDEDOR
${p.vendedorName || p.vendedor}

${comments ? 'COMENTÁRIOS\n' + comments : '(sem comentários)'}

────────────────────────────
Wine's Gallery · MG Importadora
(11) 95540-0902 · @wine_gallery · winesgallery.com.br`;
}

function openEmailModal(){
  if(!editId){showToast('Salve o pedido antes de enviar e-mail');return;}
  const lista = S.pedidos();
  const p = lista.find(x => x.id === editId);
  if(!p){showToast('Pedido não encontrado');return;}
  const cfg = getCfg();
  const dt  = new Date().toLocaleDateString('pt-BR');
  const subj = cfg.emailSubj
    .replace('{cliente}', p.cliente?.razao || '—')
    .replace('{data}', dt)
    .replace('{id}', p.id);
  document.getElementById('em-para').value    = cfg.emailAdmin;
  document.getElementById('em-cc').value      = cfg.emailCc;
  document.getElementById('em-subject').value = subj;
  document.getElementById('em-body-preview').textContent = buildEmailBody(p);
  document.getElementById('modal-email').classList.add('open');
}

async function enviarEmail(){
  const lista = S.pedidos();
  const p = lista.find(x => x.id === editId);
  if(!p) return;
  const para    = document.getElementById('em-para').value.trim();
  const cc      = document.getElementById('em-cc').value.trim();
  const subject = document.getElementById('em-subject').value.trim();
  const body    = buildEmailBody(p);
  if(!para){ showToast('Informe o e-mail de destino'); return; }
  const btn = document.getElementById('btn-enviar-email');
  const statusEl = document.getElementById('em-status');
  btn.disabled = true; btn.textContent = 'Gerando PDF...';
  statusEl.style.display='none';

  // Gerar PDF em base64
  const pdf = gerarPdfBase64();

  btn.textContent = 'Enviando...';
  try{
    if(!VERCEL_URL) throw new Error('VERCEL_URL não configurado');
    const payload = {para, cc, subject, body};
    if(pdf){ payload.pdfBase64=pdf.base64; payload.pdfFileName=pdf.filename; }
    const resp = await fetch(VERCEL_URL+'/api/send-email',{
      method:'POST',
      headers:{'Content-Type':'application/json'},
      body: JSON.stringify(payload)
    });
    const data = await resp.json();
    if(!resp.ok) throw new Error(data?.error || JSON.stringify(data));
    statusEl.style.cssText='display:block;background:var(--bg-success);color:var(--green);padding:8px;border-radius:5px;';
    statusEl.textContent='✅ E-mail enviado com sucesso'+(pdf?' (com PDF anexado)':'')+'!';
    audit('pdf', `E-mail enviado: ${p.cliente?.razao||''} · Para: ${para}`, editId);
    showToast('E-mail enviado!', true);
    setTimeout(()=>closeModal('modal-email'), 2000);
  }catch(e){
    statusEl.style.cssText='display:block;background:var(--bg-danger);color:var(--red);padding:8px;border-radius:5px;';
    statusEl.textContent='❌ Erro ao enviar: '+e.message;
    showToast('Erro ao enviar e-mail', false);
  }finally{
    btn.disabled=false; btn.textContent='📧 Enviar com PDF';
  }
}

// ══════════════════════════════════════════════
// UTILS
// ══════════════════════════════════════════════
function fmtBRL(v){return 'R$ '+Number(v).toLocaleString('pt-BR',{minimumFractionDigits:2,maximumFractionDigits:2});}
function parseBRL(s){return parseFloat(String(s).replace('R$ ','').replace(/\./g,'').replace(',','.'))||0;}
function formatDate(d){return d.toLocaleDateString('pt-BR');}
function showToast(msg,ok=false,info=false){const t=document.getElementById('toast');t.textContent=msg;t.className='toast'+(ok?' ok':info?' info':'');t.classList.add('show');setTimeout(()=>t.classList.remove('show'),3200);}
function closeModal(id){document.getElementById(id).classList.remove('open');}
document.querySelectorAll('.modal-bg').forEach(m=>m.addEventListener('click',function(e){if(e.target===this)this.classList.remove('open');}));
